function scaleImpactCard() {
  const card = document.querySelector(".impact-card");
  const inner = document.querySelector(".impact-bar-outer");
  const rolePill = document.getElementById("impactRolePill");

  if (!card || !inner) return;

  inner.style.transform = "none";

  const cardRect = card.getBoundingClientRect();
  const innerRect = inner.getBoundingClientRect();
  const reservedHeight = (rolePill?.getBoundingClientRect().height || 0) + 8;
  const availableWidth = Math.max(1, cardRect.width - 16);
  const availableHeight = Math.max(1, cardRect.height - reservedHeight - 4);

  const scaleX = availableWidth / innerRect.width;
  const scaleY = availableHeight / innerRect.height;
  const rawScale = Math.min(scaleX, scaleY, 1);
  const scale = rawScale < 0.98 ? Math.max(0.9, rawScale) : 1;

  inner.style.transform = `scale(${scale})`;
  inner.style.transformOrigin = "top center";
}

function applyStaticTrackGradient(fillEl, percent, direction = "horizontal") {
  if (!fillEl) return;
  const pct = Math.max(0, Math.min(100, Number(percent) || 0));

  if (pct <= 0) {
    fillEl.style.backgroundSize = "100% 100%";
    fillEl.style.backgroundPosition = direction === "vertical" ? "left bottom" : "left top";
    if (direction === "vertical") {
      fillEl.style.setProperty("--impact-fill-inset", "100%");
    } else {
      fillEl.style.setProperty("--track-fill-inset", "100%");
    }
    return;
  }

  if (direction === "vertical") {
    fillEl.style.backgroundSize = "100% 100%";
    fillEl.style.backgroundPosition = "left bottom";
    fillEl.style.setProperty("--impact-fill-inset", `${100 - pct}%`);
    return;
  }

  fillEl.style.backgroundSize = "100% 100%";
  fillEl.style.backgroundPosition = "left top";
  fillEl.style.setProperty("--track-fill-inset", `${100 - pct}%`);
}

function updateImpactThresholdState(percent) {
  const pct = Math.max(0, Math.min(100, Number(percent) || 0));
  const poor = document.getElementById("impactTierPoor");
  const solid = document.getElementById("impactTierSolid");
  const carry = document.getElementById("impactTierCarry");
  const activeId = pct >= 85
    ? "impactTierCarry"
    : pct >= 60
      ? "impactTierSolid"
      : "impactTierPoor";

  const tierClassById = {
    impactTierPoor: "impact-tier-poor",
    impactTierSolid: "impact-tier-solid",
    impactTierCarry: "impact-tier-carry"
  };

  [poor, solid, carry].forEach((el) => {
    if (!el) return;
    el.classList.toggle("is-active", el.id === activeId);
    el.classList.remove("impact-tier-poor", "impact-tier-solid", "impact-tier-carry");
    if (el.id === activeId) {
      el.classList.add(tierClassById[activeId]);
    }
  });
}

function getImpactRoleLabel(match = null, matchIndex = null) {
  const core = getMatchCore(match || {});
  const agent = core?.agent || agentName?.textContent || "";
  const role = String(agentRoles?.[agent] || "").trim();
  const roleLabel = role
    ? `${role.charAt(0).toUpperCase()}${role.slice(1)} Report`
    : "Role Report";

  if (Number.isInteger(matchIndex) && matchIndex >= 0) {
    const latestIndex = Math.max(0, matches.length - 1);
    return matchIndex === latestIndex
      ? `Latest ${roleLabel}`
      : `Game ${matchIndex + 1} ${roleLabel}`;
  }

  return `Latest ${roleLabel}`;
}

function updateImpactRolePill(match = null, matchIndex = null) {
  if (!impactRolePill) return;

  const core = getMatchCore(match || {});
  const agent = core?.agent || agentName?.textContent || "";
  const role = String(agentRoles?.[agent] || "").trim().toLowerCase();

  impactRolePill.textContent = getImpactRoleLabel(match, matchIndex);
  impactRolePill.dataset.role = role || "duelist";
  impactRolePill.dataset.matchIndex = Number.isInteger(matchIndex) && matchIndex >= 0
    ? String(matchIndex)
    : "";
}

