const APP_BASE_WIDTH = 1920;
const APP_BASE_HEIGHT = 1080;
const LARGE_VIEWPORT_WIDTH_THRESHOLD = 2300;
const LARGE_VIEWPORT_HEIGHT_THRESHOLD = 1300;
const LARGE_VIEWPORT_DEVICE_PIXEL_BUDGET = 3200000;
const LARGE_VIEWPORT_SCALE_THRESHOLD = 0.9;
const ULTRA_VIEWPORT_WIDTH_THRESHOLD = 3300;
const ULTRA_VIEWPORT_HEIGHT_THRESHOLD = 1800;
const ULTRA_VIEWPORT_DEVICE_PIXEL_BUDGET = 7000000;
let themeBuilderState = {};
let themeBuilderNeedsSave = false;
let themeBuilderSaveTimer = 0;
let themeBuilderFxListenersAttached = false;

function supportsCssDeclaration(property, value) {
  const css = window.CSS;
  if (!css?.supports) return false;
  try {
    return css.supports(property, value) || css.supports(`(${property}:${value})`);
  } catch (_error) {
    return false;
  }
}

function detectBrowserFeatureSupport() {
  return {
    backdropFilter:
      supportsCssDeclaration("backdrop-filter", "blur(1px)") ||
      supportsCssDeclaration("-webkit-backdrop-filter", "blur(1px)"),
    colorMix:
      supportsCssDeclaration("color", "color-mix(in srgb, red 50%, white)") ||
      supportsCssDeclaration("background", "color-mix(in srgb, red 50%, white)"),
    contentVisibility: supportsCssDeclaration("content-visibility", "auto"),
    individualTransform:
      supportsCssDeclaration("translate", "0 0") &&
      supportsCssDeclaration("scale", "1"),
    maskImage:
      supportsCssDeclaration("mask-image", "linear-gradient(#000,#000)") ||
      supportsCssDeclaration("-webkit-mask-image", "linear-gradient(#000,#000)"),
    mixBlendMode: supportsCssDeclaration("mix-blend-mode", "screen")
  };
}

const browserFeatureSupport = detectBrowserFeatureSupport();

function isBrowserCompatibilityBasicMode() {
  return document.body?.classList.contains("compat-basic");
}

function colorMixOrFallback(value, fallback) {
  return browserFeatureSupport.colorMix ? value : fallback;
}

function applyBrowserCompatibilityMode() {
  const body = document.body;
  if (!body) return;
  const compatBasic =
    !browserFeatureSupport.backdropFilter ||
    !browserFeatureSupport.colorMix ||
    !browserFeatureSupport.individualTransform ||
    !browserFeatureSupport.maskImage ||
    !browserFeatureSupport.mixBlendMode;

  body.classList.toggle("compat-basic", compatBasic);
  body.classList.toggle("compat-no-backdrop", !browserFeatureSupport.backdropFilter);
  body.classList.toggle("compat-no-color-mix", !browserFeatureSupport.colorMix);
  body.classList.toggle("compat-no-content-visibility", !browserFeatureSupport.contentVisibility);
  body.classList.toggle("compat-no-individual-transform", !browserFeatureSupport.individualTransform);
  body.classList.toggle("compat-no-mask", !browserFeatureSupport.maskImage);
  body.classList.toggle("compat-no-mix-blend", !browserFeatureSupport.mixBlendMode);
  body.dataset.browserCompatibility = compatBasic ? "basic" : "full";
}

function updateViewportPerformanceMode(viewportWidth, viewportHeight, scale) {
  const body = document.body;
  if (!body) return;

  const dpr = Math.min(window.devicePixelRatio || 1, 1.5);
  const devicePixelBudget = viewportWidth * viewportHeight * dpr * dpr;
  const shouldOptimize =
    viewportWidth >= LARGE_VIEWPORT_WIDTH_THRESHOLD ||
    viewportHeight >= LARGE_VIEWPORT_HEIGHT_THRESHOLD ||
    scale >= LARGE_VIEWPORT_SCALE_THRESHOLD ||
    devicePixelBudget >= LARGE_VIEWPORT_DEVICE_PIXEL_BUDGET;
  const shouldUltraOptimize =
    viewportWidth >= ULTRA_VIEWPORT_WIDTH_THRESHOLD ||
    viewportHeight >= ULTRA_VIEWPORT_HEIGHT_THRESHOLD ||
    devicePixelBudget >= ULTRA_VIEWPORT_DEVICE_PIXEL_BUDGET;
  const wasOptimized = body.classList.contains("viewport-performance-mode");

  body.classList.toggle("viewport-performance-mode", shouldOptimize);
  body.classList.toggle("viewport-ultra-performance-mode", shouldUltraOptimize);
  body.dataset.renderBudget = shouldUltraOptimize ? "ultra" : shouldOptimize ? "large" : "standard";
  document.documentElement.style.setProperty("--viewport-render-scale", `${scale}`);

  if (wasOptimized !== shouldOptimize && typeof syncThemeBuilderFxEngine === "function") {
    syncThemeBuilderFxEngine();
  }
}

function scaleApp() {
  const wrap = document.querySelector(".app-scale-wrap");
  const root = document.querySelector(".app-root");
  if (!wrap || !root) return;

  const viewportWidth = window.innerWidth || document.documentElement.clientWidth || APP_BASE_WIDTH;
  const viewportHeight = window.innerHeight || document.documentElement.clientHeight || APP_BASE_HEIGHT;
  const effectiveBaseWidth = viewportWidth;
  const effectiveBaseHeight = viewportHeight;
  const legacyDesignScale = Math.min(
    viewportWidth / APP_BASE_WIDTH,
    viewportHeight / APP_BASE_HEIGHT
  );

  document.documentElement.style.setProperty("--app-base-width", `${effectiveBaseWidth}`);
  document.documentElement.style.setProperty("--app-base-height", `${effectiveBaseHeight}`);
  document.documentElement.style.setProperty("--app-scale", `${legacyDesignScale}`);

  wrap.style.alignItems = "stretch";
  wrap.style.justifyContent = "flex-start";

  root.style.width = "100%";
  root.style.height = "100%";
  root.style.maxWidth = "100%";
  root.style.maxHeight = "100%";
  root.style.transformOrigin = "top left";
  root.style.transform = "none";

  updateViewportPerformanceMode(viewportWidth, viewportHeight, legacyDesignScale);
}

let viewportRefreshTimer = 0;
let viewportRefreshRaf = 0;
let viewportRefreshNeedsChart = false;
let viewportRefreshNeedsThemeBuilder = false;

function flushViewportRefresh() {
  viewportRefreshTimer = 0;
  viewportRefreshRaf = 0;
  const shouldRenderChart = viewportRefreshNeedsChart;
  const shouldRefreshThemeBuilder = viewportRefreshNeedsThemeBuilder;

  viewportRefreshNeedsChart = false;
  viewportRefreshNeedsThemeBuilder = false;

  scaleApp();
  if (typeof scaleImpactCard === "function") scaleImpactCard();
  if (typeof updateAgentFrameMetrics === "function") updateAgentFrameMetrics();
  if (shouldRenderChart && typeof renderChart === "function") renderChart(currentSize);
  if (shouldRefreshThemeBuilder && typeof applyThemeBuilderRuntimeStyles === "function") {
    applyThemeBuilderRuntimeStyles();
  }
  scheduleLoadoutValueTextFit();
}

function scheduleViewportRefresh({
  renderChart: shouldRenderChart = true,
  applyThemeBuilder: shouldRefreshThemeBuilder = true
} = {}) {
  viewportRefreshNeedsChart = viewportRefreshNeedsChart || shouldRenderChart;
  viewportRefreshNeedsThemeBuilder = viewportRefreshNeedsThemeBuilder || shouldRefreshThemeBuilder;

  if (viewportRefreshTimer) {
    window.clearTimeout(viewportRefreshTimer);
  }
  viewportRefreshTimer = window.setTimeout(() => {
    if (viewportRefreshRaf) return;
    viewportRefreshRaf = window.requestAnimationFrame(flushViewportRefresh);
  }, 80);
}


