function getMapIconUrl(mapName) {
  const normalized = String(mapName || "").trim();
  return `https://raw.githubusercontent.com/michealdoolittle-cyber/images/main/icons/${encodeURIComponent(normalized)}.png`;
}

function average(values = []) {
  const nums = values.filter((value) => Number.isFinite(Number(value))).map(Number);
  if (!nums.length) return 0;
  return nums.reduce((sum, value) => sum + value, 0) / nums.length;
}

function getSortedMatches(matchList = []) {
  return (matchList || []).slice().sort((a, b) =>
    new Date(a?.createdAt || 0).getTime() - new Date(b?.createdAt || 0).getTime()
  );
}

function getMatchCore(match = {}) {
  const stats = match?.segments?.[0]?.stats || {};
  const metadata = match?.metadata || {};
  const agent = metadata.agent || match.agent || "Unknown";
  const map = metadata.mapName || match.map || "Unknown";
  const result = metadata.result || match.result || "draw";
  const kills = safeNumber(stats.kills?.value);
  const deaths = safeNumber(stats.deaths?.value);
  const assists = safeNumber(stats.assists?.value);
  const acs = safeNumber(stats.scorePerRound?.value);
  const adr = safeNumber(stats.damagePerRound?.value, safeNumber(match?.adr));
  const hs = safeNumber(stats.headshotsPercentage?.value);

  return {
    agent,
    role: agentRoles?.[agent] || "Unknown",
    map,
    result,
    kills,
    deaths,
    assists,
    acs,
    adr,
    hs,
    createdAt: match?.createdAt || metadata.playedAt || nowISO()
  };
}

function createPerformanceBucket(label) {
  return {
    label,
    matchesPlayed: 0,
    matchesWon: 0,
    matchesLost: 0,
    kills: 0,
    deaths: 0,
    assists: 0,
    acsTotal: 0,
    hsTotal: 0
  };
}

function finalizePerformanceBucket(bucket = {}) {
  const matchesPlayed = safeNumber(bucket.matchesPlayed);
  const matchesWon = safeNumber(bucket.matchesWon);
  const matchesLost = safeNumber(bucket.matchesLost);
  const deaths = safeNumber(bucket.deaths);

  return {
    ...bucket,
    matchesPlayed,
    matchesWon,
    matchesLost,
    winrate: matchesPlayed ? (matchesWon / matchesPlayed) * 100 : 0,
    kd: deaths ? safeNumber(bucket.kills) / deaths : safeNumber(bucket.kills),
    adr: matchesPlayed ? safeNumber(bucket.acsTotal) / matchesPlayed : 0,
    hs: matchesPlayed ? safeNumber(bucket.hsTotal) / matchesPlayed : 0
  };
}

function rankBuckets(mapObj = {}, labelKey) {
  return Object.values(mapObj)
    .map(finalizePerformanceBucket)
    .sort((a, b) => {
      if (b.matchesPlayed !== a.matchesPlayed) return b.matchesPlayed - a.matchesPlayed;
      if (b.winrate !== a.winrate) return b.winrate - a.winrate;
      return String(a[labelKey] || a.label || "").localeCompare(String(b[labelKey] || b.label || ""));
    });
}

function clampPercent(value) {
  return Math.max(0, Math.min(100, Math.round(safeNumber(value))));
}

function normalizeDistributionTo100(entries = {}) {
  const keys = Object.keys(entries);
  if (!keys.length) return {};

  const safeEntries = {};
  let total = 0;

  keys.forEach((key) => {
    const value = Math.max(0, safeNumber(entries[key]));
    safeEntries[key] = value;
    total += value;
  });

  if (!total) {
    const fallback = {};
    const base = Math.floor(100 / keys.length);
    let remainder = 100 - (base * keys.length);
    keys.forEach((key, index) => {
      fallback[key] = base + (index < remainder ? 1 : 0);
    });
    return fallback;
  }

  const exact = keys.map((key) => ({
    key,
    value: (safeEntries[key] / total) * 100
  }));

  const rounded = {};
  let roundedTotal = 0;

  exact.forEach((entry) => {
    rounded[entry.key] = Math.floor(entry.value);
    roundedTotal += rounded[entry.key];
  });

  let remainder = 100 - roundedTotal;
  exact
    .slice()
    .sort((a, b) => (b.value - Math.floor(b.value)) - (a.value - Math.floor(a.value)))
    .forEach((entry) => {
      if (remainder <= 0) return;
      rounded[entry.key] += 1;
      remainder -= 1;
    });

  return rounded;
}

function getConfidenceLabel(score) {
  if (score >= 80) return "High Confidence";
  if (score >= 55) return "Medium Confidence";
  return "Low Confidence";
}

function getPriorityLabel(score) {
  if (score >= 90) return "Immediate";
  if (score >= 75) return "High";
  if (score >= 55) return "Moderate";
  return "Watch";
}

function buildCoachRecommendation(kind, entity = {}, model = {}) {
  const overview = model?.overview || {};

  if (kind === "map") {
    const mapName = entity?.map || "this map";
    const mapWr = Math.round(safeNumber(entity?.winrate));
    return {
      diagnosis: mapWr < 45 ? `${mapName} is a live weakness right now.` : `${mapName} is a stable environment in your sample.`,
      emphasis: mapWr < 45 ? "Prep your first 3 rounds before queueing this map." : "Keep using this map as a confidence anchor.",
      recommendation: mapWr < 45
        ? `Build one attack default and one defensive fallback plan for ${mapName}, then review whether the next two games feel less reactive.`
        : `Reuse the habits that already work on ${mapName} and carry one of them into a weaker map next session.`
    };
  }

  if (kind === "agent") {
    const agentName = entity?.agent || "this agent";
    const winrate = Math.round(safeNumber(entity?.winrate));
    const kd = Number(entity?.kd || 0);
    return {
      diagnosis: winrate >= 50 && kd >= 1 ? `${agentName} is giving you stable value.` : `${agentName} is not converting cleanly enough yet.`,
      emphasis: winrate >= 50 && kd >= 1 ? "Use this pick when you want consistency." : "Narrow the job you expect from this pick.",
      recommendation: winrate >= 50 && kd >= 1
        ? `Treat ${agentName} as an anchor pick while you experiment less on lower-confidence roles.`
        : `Play ${agentName} with one clearer responsibility next block instead of trying to solve every round.`
    };
  }

  if (kind === "role") {
    const roleName = entity?.role || "this role";
    const winrate = Math.round(safeNumber(entity?.winrate));
    return {
      diagnosis: winrate >= 50 ? `${roleName} currently fits your decision profile.` : `${roleName} is where your decision load is slipping.`,
      emphasis: winrate >= 50 ? "Lean into the role strengths already showing up." : "Reduce overload and simplify the role plan.",
      recommendation: winrate >= 50
        ? `Bias queues toward ${roleName} when you want stable impact and review what transfers from it to weaker roles.`
        : `Give ${roleName} one smaller role objective next session so success is easier to measure.`
    };
  }

  return {
    diagnosis: overview.kd >= 1 ? "Your profile has a workable baseline." : "Your profile still needs a stronger floor.",
    emphasis: "Use the next match block to validate one change, not five.",
    recommendation: "Keep the next improvement target narrow enough that you can tell whether it actually worked."
  };
}

function clampScore(value, min = 0, max = 100) {
  return Math.max(min, Math.min(max, Number(value) || 0));
}

function normalizeMetricAgainstBaseline(value, baseline, spread = null, options = {}) {
  const { inverse = false, center = 50, scale = 18 } = options;
  const safeValue = safeNumber(value);
  const safeBaseline = safeNumber(baseline, safeValue || 1);
  const safeSpread = Math.max(0.08, safeNumber(spread, Math.max(Math.abs(safeBaseline) * 0.18, 0.12)));
  const delta = (safeValue - safeBaseline) / safeSpread;
  return clampScore(center + ((inverse ? -delta : delta) * scale));
}

