function getRecentLogs(limit = 10) {
  if (!logEntries || !logEntries.length) return [];
  return logEntries.slice(-limit);
}

function avg(arr) {
  if (!arr.length) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

// ========================
// CALCULATE FOCUS PROGRESS
// ========================

function calculateFocusProgress() {
  if (!activeInsightFocus || !logEntries) return 0;

  const recent = logEntries.slice(-10);
  let matchesFocus = 0;

  const target = activeInsightFocus.toLowerCase();

  const map = {
    mental: ["tilt", "mental"],
    aim: ["aim", "crosshair"],
    consistency: ["consistency", "discipline"],
    "game sense": ["sense", "awareness"],
    "agent mastery": ["agent"],
    "role discipline": ["role"],
    "map awareness": ["map"]
  };

  const keys = map[target] || [target];

  recent.forEach((l) => {
    const f = (l.focus || "").toLowerCase();

    if (keys.some((k) => f.includes(k)) || f === target) {
      matchesFocus++;
    }
  });

  focusProgress = Math.min(100, (matchesFocus / focusProgressMax) * 100);
  return focusProgress;
}

// ========================
// MAP INSIGHT → FOCUS
// ========================

function mapInsightToFocus(ins) {
  if (!ins) return null;

  const title = ins.title.toLowerCase();

  if (title.includes("tilt")) return "mental";
  if (title.includes("loss")) return "Consistency";
  if (title.includes("streak")) return "Momentum Control";
  if (title.includes("kd") || title.includes("duel")) return "Aim";
  if (title.includes("agent")) return "Agent Mastery";
  if (title.includes("role")) return "Role Discipline";
  if (title.includes("map")) return "Map Awareness";

  return "Game Sense";
}

