function getNextFocusFromInsight(ins) {
  if (!ins || !ins.title) return null;

  const t = ins.title.toLowerCase();

  if (t.includes("tilt") || t.includes("loss")) {
    return "Mental Reset";
  }

  if (t.includes("duel") || t.includes("kd")) {
    return "Aim";
  }

  if (t.includes("role")) {
    return "Role Discipline";
  }

  if (t.includes("map")) {
    return "Map Awareness";
  }

  if (t.includes("agent")) {
    return "Agent Mastery";
  }

  if (t.includes("performance")) {
    return "Consistency";
  }

  return "Game Sense";
}

// ========================
// WEEKLY FOCUS LOCK HELPERS
// ========================

const WEEKLY_FOCUS_KEY = "valtracker_weekly_focus_v1";
const WEEKLY_FOCUS_WEEK_KEY = "valtracker_weekly_focus_week_v1";
const APP_ENTRY_CHOICE_KEY = "valtracker_entry_choice_v1";

function getCurrentWeekKey() {
  return `week-${formatLocalDateKey(getWeekStart())}`;
}

function getLockedWeeklyFocus() {
  const savedFocus = localStorage.getItem(WEEKLY_FOCUS_KEY);
  const savedWeek = localStorage.getItem(WEEKLY_FOCUS_WEEK_KEY);
  const currentWeek = getCurrentWeekKey();

  if (savedFocus && savedWeek === currentWeek) {
    return savedFocus;
  }

  return null;
}

function setLockedWeeklyFocus(focus) {
  if (!focus) return;

  localStorage.setItem(WEEKLY_FOCUS_KEY, focus);
  localStorage.setItem(WEEKLY_FOCUS_WEEK_KEY, getCurrentWeekKey());
}

function clearLockedWeeklyFocus() {
  localStorage.removeItem(WEEKLY_FOCUS_KEY);
  localStorage.removeItem(WEEKLY_FOCUS_WEEK_KEY);
}

// ========================
// INSIGHTS (REAL DATA)
// ========================

function renderInsights() {
  return renderInsightsModel();
  const container = document.getElementById("insightsList");
  if (!container) return;

  container.innerHTML = "";

  const insights = [];

  // ========================
  // SAFE FALLBACK (no data)
  // ========================
  if ((!matches || !matches.length) && (!logEntries || !logEntries.length)) {
    insights.push({
      type: "warn",
      title: "No Data Yet",
      preview: "Play matches or log sessions to generate insights",
      what: "No matches available for analysis",
      why: "Insights require match or logging data",
      action: "Play 3–5 matches or add logs to unlock insights",
      sources: ["System"]
    });
  }

  // ========================
  // LOGGING ONLY STATE
  // ========================
  if ((!matches || !matches.length) && logEntries.length) {
    insights.push({
      type: "good",
      title: "Logging Active",
      preview: "Insights improving as you log sessions",
      what: "You are actively tracking performance",
      why: "Logging builds awareness of habits",
      action: "Continue logging to unlock deeper insights",
      sources: ["Logging"]
    });
  }

  // ========================
  // MATCH-BASED INSIGHTS
  // ========================
  if (matches && matches.length) {
    const logs = getRecentLogs(10);

    // ========================
    // BEHAVIOR: LOGGING INSIGHTS
    // ========================
    if (logs.length) {
      const tiltScores = logs
        .map((l) => Number(l.tilt || l.mood || 0))
        .filter((v) => v > 0);

      const tiltAvg = avg(tiltScores);

      if (tiltAvg >= 3) {
        insights.push({
          type: "bad",
          title: "Tilt Detected",
          preview: `Average tilt level ${tiltAvg.toFixed(1)} in recent sessions`,
          what: "Tilt levels are consistently elevated",
          why: "Emotional play is affecting decision making",
          action: "Take breaks after losses and reset mental before next match",
          sources: ["Logging", "Behavior"]
        });
      }

      const focusList = logs.map((l) => l.focus).filter(Boolean);
      const focusMap = {};

      focusList.forEach((f) => {
        focusMap[f] = (focusMap[f] || 0) + 1;
      });

      const sortedFocus = Object.entries(focusMap).sort((a, b) => b[1] - a[1]);

      if (sortedFocus.length) {
        const [topFocus, count] = sortedFocus[0];

        if (count >= 4) {
          insights.push({
            type: "good",
            title: "Consistent Focus Area",
            preview: `${topFocus} focus category is reported in ${count} recent sessions`,
            what: `You are repeatedly logging the ${topFocus} focus category`,
            why: "Deliberate practice is being applied",
            action: "Continue this focus category and measure improvement in stats",
            sources: ["Logging"]
          });
        }
      }

      const ratings = logs
        .map((l) => Number(l.rating || 0))
        .filter((v) => v > 0);

      const ratingAvg = avg(ratings);

      if (ratingAvg && ratingAvg < 3) {
        insights.push({
          type: "warn",
          title: "Low Performance Confidence",
          preview: `Average self-rating ${ratingAvg.toFixed(1)}`,
          what: "You rate your performance below average",
          why: "Possible inconsistency or frustration",
          action: "Review strong games to reinforce confidence",
          sources: ["Logging", "Behavior"]
        });
      }

      // ========================
      // HYBRID INSIGHT
      // ========================
      let recentLosses = 0;

      matches.slice(-5).forEach((m) => {
        if (m.metadata?.result === "loss") recentLosses++;
      });

      const recentTilt = avg(
        logs
          .slice(-5)
          .map((l) => Number(l.tilt || l.mood || 0))
          .filter((v) => v > 0)
      );

      if (recentLosses >= 3 && recentTilt >= 3) {
        insights.push({
          type: "bad",
          title: "Loss + Tilt Pattern",
          preview: "Loss streak aligns with high tilt levels",
          what: `${recentLosses} losses in last 5 matches`,
          why: "Tilt is likely impacting performance",
          action: "Stop queueing after 2 consecutive losses",
          sources: ["Riot API", "Logging", "Behavior"]
        });
      }
    }

    // ========================
    // STREAK DETECTION
    // ========================
    let streak = 0;
    let lastResult = null;

    for (let i = matches.length - 1; i >= 0; i--) {
      const result = matches[i].metadata?.result;

      if (!lastResult) {
        lastResult = result;
        streak = 1;
      } else if (result === lastResult) {
        streak++;
      } else {
        break;
      }
    }

    if (streak >= 3) {
      if (lastResult === "win") {
        insights.push({
          type: "good",
          title: "Win Streak Active",
          preview: `${streak} consecutive wins`,
          what: `You are on a ${streak} game win streak`,
          why: "Current playstyle is effective",
          action: "Continue same approach and avoid over-aggression",
          sources: ["Riot API", "Trend"]
        });
      }

      if (lastResult === "loss") {
        insights.push({
          type: "bad",
          title: "Loss Streak",
          preview: `${streak} consecutive losses`,
          what: `You are on a ${streak} game loss streak`,
          why: "Performance or decisions are trending negatively",
          action: "Take a break or reset approach",
          sources: ["Riot API", "Trend"]
        });
      }
    }

    // ========================
    // AGENT PERFORMANCE
    // ========================
    const agentStats = {};

    (matches || []).forEach((m) => {
      const agent =
        m.metadata?.agent ||
        m.metadata?.character ||
        m.segments?.[0]?.metadata?.agent ||
        "Unknown";

      if (!agentStats[agent]) {
        agentStats[agent] = { games: 0, wins: 0 };
      }

      agentStats[agent].games++;

      if (m.metadata?.result === "win") {
        agentStats[agent].wins++;
      }
    });

    const agentArr = Object.entries(agentStats).map(([agent, data]) => ({
      agent,
      wr: (data.wins / data.games) * 100,
      games: data.games
    }));

    agentArr.sort((a, b) => b.wr - a.wr);

    if (agentArr.length >= 2) {
      const best = agentArr[0];
      const worst = agentArr[agentArr.length - 1];

      if (best.games >= 3) {
        insights.push({
          type: "good",
          title: "Best Performing Agent",
          preview: `${best.agent} (${Math.round(best.wr)}% WR)`,
          what: `Highest win rate agent is ${best.agent}`,
          why: "Strong familiarity or role fit",
          action: "Prioritize this agent in ranked",
          sources: ["Riot API"]
        });
      }

      if (worst.games >= 3 && worst.wr < 40) {
        insights.push({
          type: "warn",
          title: "Weak Agent Performance",
          preview: `${worst.agent} (${Math.round(worst.wr)}% WR)`,
          what: `Low success rate on ${worst.agent}`,
          why: "Possible discomfort or role mismatch",
          action: "Review gameplay or avoid this agent",
          sources: ["Riot API"]
        });
      }
    }

    // ========================
    // ROLE IMPACT
    // ========================
    const roleMap = {};

    (matches || []).forEach((m) => {
      const agent =
        m.metadata?.agent ||
        m.metadata?.character ||
        m.segments?.[0]?.metadata?.agent;

      const role = agentRoles?.[agent] || "unknown";

      if (!roleMap[role]) {
        roleMap[role] = { games: 0, wins: 0 };
      }

      roleMap[role].games++;

      if (m.metadata?.result === "win") {
        roleMap[role].wins++;
      }
    });

    const roleArr = Object.entries(roleMap).map(([role, data]) => ({
      role,
      wr: (data.wins / data.games) * 100
    }));

    roleArr.sort((a, b) => b.wr - a.wr);

    if (roleArr.length >= 2) {
      const bestRole = roleArr[0];
      const worstRole = roleArr[roleArr.length - 1];

      if (bestRole.wr > worstRole.wr + 15) {
        insights.push({
          type: "warn",
          title: "Role Performance Gap",
          preview: `${bestRole.role} outperforming ${worstRole.role}`,
          what: "Different success rates across roles",
          why: "Role playstyle mismatch",
          action: "Queue into your strongest role more consistently",
          sources: ["Riot API", "Trend"]
        });
      }
    }

    // ========================
    // IMPROVEMENT TREND
    // ========================
    if (matches.length >= 6) {
      const recent = matches.slice(-3);
      const previous = matches.slice(-6, -3);

      function calcKD(set) {
        let k = 0;
        let d = 0;

        set.forEach((m) => {
          const s = m.segments?.[0]?.stats;
          if (s) {
            k += Number(s.kills?.value || 0);
            d += Number(s.deaths?.value || 0);
          }
        });

        return d ? k / d : k;
      }

      const recentKD = calcKD(recent);
      const prevKD = calcKD(previous);

      if (recentKD > prevKD + 0.2) {
        insights.push({
          type: "good",
          title: "Performance Improving",
          preview: `KD rising (${prevKD.toFixed(2)} → ${recentKD.toFixed(2)})`,
          what: "Recent matches show improvement",
          why: "Better consistency or decision making",
          action: "Continue current playstyle",
          sources: ["Riot API", "Trend"]
        });
      }

      if (recentKD < prevKD - 0.2) {
        insights.push({
          type: "bad",
          title: "Performance Dropping",
          preview: `KD falling (${prevKD.toFixed(2)} → ${recentKD.toFixed(2)})`,
          what: "Recent performance is declining",
          why: "Possible fatigue or inconsistency",
          action: "Review recent matches or take break",
          sources: ["Riot API", "Trend"]
        });
      }
    }

    // ========================
    // LOSS RATE INSIGHT
    // ========================
    let lossCount = 0;

    (matches || []).forEach((m) => {
      if (m.metadata?.result === "loss") lossCount++;
    });

    const lossRate = (lossCount / matches.length) * 100;

    if (lossRate > 55) {
      insights.push({
        type: "bad",
        title: "High Loss Rate",
        preview: `${Math.round(lossRate)}% of recent matches are losses`,
        what: `Loss rate is ${Math.round(lossRate)}%`,
        why: "Recent performance trend is negative",
        action: "Review last 3 losses and identify repeated mistakes",
        sources: ["Riot API", "Trend"]
      });
    }

    // ========================
    // KD INSIGHT
    // ========================
    let totalKills = 0;
    let totalDeaths = 0;

    (matches || []).forEach((m) => {
      const s = m.segments?.[0]?.stats;
      if (s) {
        totalKills += Number(s.kills?.value || 0);
        totalDeaths += Number(s.deaths?.value || 0);
      }
    });

    const kd = totalDeaths ? totalKills / totalDeaths : totalKills;

    if (kd > 1.2) {
      insights.push({
        type: "good",
        title: "Strong Duel Performance",
        preview: `KD averaging ${kd.toFixed(2)}`,
        what: `KD is ${kd.toFixed(2)}`,
        why: "You are winning more fights than losing",
        action: "Take more opening engagements",
        sources: ["Riot API"]
      });
    }

    if (kd < 0.9) {
      insights.push({
        type: "bad",
        title: "Low Duel Success",
        preview: `KD averaging ${kd.toFixed(2)}`,
        what: "KD is below 1.0",
        why: "Losing more fights than winning",
        action: "Focus on crosshair placement and positioning",
        sources: ["Riot API"]
      });
    }

    // ========================
    // MAP CONSISTENCY
    // ========================
    const mapStats = {};

    (matches || []).forEach((m) => {
      const map = m.metadata?.mapName || "Unknown";

      if (!mapStats[map]) {
        mapStats[map] = { games: 0, wins: 0 };
      }

      mapStats[map].games++;

      if (m.metadata?.result === "win") {
        mapStats[map].wins++;
      }
    });

    const mapArray = Object.entries(mapStats).map(([map, data]) => ({
      map,
      wr: (data.wins / data.games) * 100
    }));

    mapArray.sort((a, b) => b.wr - a.wr);

    if (mapArray.length >= 2) {
      const best = mapArray[0];
      const worst = mapArray[mapArray.length - 1];

      if (best.wr - worst.wr > 25) {
        insights.push({
          type: "warn",
          title: "Map Performance Gap",
          preview: `${best.map} (${Math.round(best.wr)}%) vs ${worst.map} (${Math.round(worst.wr)}%)`,
          what: "Large performance difference across maps",
          why: "Inconsistent map understanding or strategy",
          action: "Review gameplay on weakest map",
          sources: ["Riot API", "Trend"]
        });
      }
    }
  }

  // ========================
  // STABILITY: ENSURE MINIMUM INSIGHTS
  // ========================
  if (insights.length < 3) {
    insights.push({
      type: "good",
      title: "Building Momentum",
      preview: "Keep playing to unlock deeper insights",
      what: "Not enough data for advanced insights yet",
      why: "Insights improve with more matches and logs",
      action: "Play 3–5 more matches or continue logging",
      sources: ["System"]
    });
  }

  if (insights.length < 3) {
    insights.push({
      type: "warn",
      title: "Limited Data",
      preview: "Insights accuracy increases with more sessions",
      what: "Current data sample is small",
      why: "Patterns need repetition to detect",
      action: "Continue consistent play to improve tracking",
      sources: ["System"]
    });
  }

  // ========================
  // REMOVE DUPLICATES
  // ========================
  const seenTitles = new Set();
  const uniqueInsights = [];

  insights.forEach((i) => {
    const key = (i.title || "").toLowerCase();

    if (!seenTitles.has(key)) {
      seenTitles.add(key);
      uniqueInsights.push(i);
    }
  });

  insights.length = 0;
  insights.push(...uniqueInsights);

  // ========================
  // REFINED SCORING SYSTEM
  // ========================
  insights.forEach((ins) => {
    let score = 0;

    const title = (ins.title || "").toLowerCase();
    const preview = (ins.preview || "").toLowerCase();

    if (ins.type === "bad") score += 100;
    if (ins.type === "warn") score += 70;
    if (ins.type === "good") score += 40;

    if (title.includes("loss streak")) score += 40;
    if (title.includes("tilt")) score += 35;
    if (title.includes("dropping")) score += 30;
    if (title.includes("low")) score += 20;
    if (title.includes("gap")) score += 20;
    if (title.includes("improving")) score += 15;
    if (title.includes("strong")) score += 10;

    if (preview.includes("recent") || preview.includes("last")) {
      score += 15;
    }

    if (ins.sources && ins.sources.includes("Behavior")) score += 25;
    if (ins.sources && ins.sources.includes("Logging")) score += 15;
    if (ins.sources && ins.sources.length >= 2) score += 20;
    if (ins.action && ins.action.length > 40) score += 10;

    ins.priority = score;
  });

  insights.sort((a, b) => b.priority - a.priority);

  // ========================
  // TOP INSIGHT LOCK
  // ========================
  if (insights.length) {
    const top = insights[0];

    if (top.type === "good") {
      const stronger = insights.find((i) => i.type !== "good");

      if (stronger) {
        insights.splice(insights.indexOf(stronger), 1);
        insights.unshift(stronger);
      }
    }
  }

  // ========================
  // REMOVE LOW VALUE INSIGHTS
  // ========================
  const filteredInsights = insights.filter((i) => i.priority >= 60);

  if (filteredInsights.length >= 3) {
    insights.length = 0;
    insights.push(...filteredInsights);
  }

  // ========================
  // BALANCE TYPES
  // ========================
  const balanced = [];

  const typeBuckets = {
    bad: insights.filter((i) => i.type === "bad"),
    warn: insights.filter((i) => i.type === "warn"),
    good: insights.filter((i) => i.type === "good")
  };

  if (typeBuckets.bad.length) balanced.push(typeBuckets.bad[0]);
  if (typeBuckets.warn.length) balanced.push(typeBuckets.warn[0]);
  if (typeBuckets.good.length) balanced.push(typeBuckets.good[0]);

  insights.forEach((i) => {
    if (!balanced.includes(i) && balanced.length < 4) {
      balanced.push(i);
    }
  });

  const topInsights = balanced.slice(0, 6);

  // ========================
  // SET ACTIVE FOCUS FROM TOP INSIGHT
  // ========================

  const topInsight = topInsights[0] || null;
  const lockedFocus = getLockedWeeklyFocus();

  if (lockedFocus) {
    activeInsightFocus = lockedFocus;
  } else {
    activeInsightFocus = topInsight
      ? getNextFocusFromInsight(topInsight)
      : null;

    if (activeInsightFocus) {
      setLockedWeeklyFocus(activeInsightFocus);
    }
  }

  calculateFocusProgress();
  updateFocusProgressUI();
  updateInsightFocusUI();
  syncWeeklyFocus(topInsights);

  // ========================
  // RENDER
  // ========================

  cachedInsights = topInsights.slice();
  renderInsightCards();
  renderTrendBreakdown();
}

