function updateFocusProgressUI() {
  const bar = document.querySelector(".insight-progress-bar");
  if (!bar) return;

  bar.style.width = focusProgress + "%";

  bar.style.background =
    focusProgress > 70
      ? "linear-gradient(90deg,#22c55e,#4ade80)"
      : "linear-gradient(90deg,#ff4655,#f97316)";
}

function getWeeklySessions() {
  const start = getWeekStart();
  const end = getWeekEnd();
  const grouped = new Map();

  (logEntries || []).forEach(entry => {
    const createdAt = new Date(entry.createdAt || nowISO());
    if (createdAt < start || createdAt > end) return;

    const key = createdAt.toISOString().slice(0, 10);
    if (!grouped.has(key)) {
      grouped.set(key, []);
    }
    grouped.get(key).push(entry);
  });

  return [...grouped.entries()]
    .map(([key, entries]) => ({ key, entries }))
    .sort((a, b) => new Date(b.key) - new Date(a.key));
}

function updateWeeklyFocusDetails(topInsights = []) {
  return updateWeeklyFocusDetailsModel(topInsights);
  const whyEl = document.getElementById("insightFocusWhy");
  const howEl = document.getElementById("insightFocusHow");
  const sourceEl = document.getElementById("insightFocusSource");
  const secondaryEl = document.getElementById("weeklyFocusSecondary");
  const tertiaryEl = document.getElementById("weeklyFocusTertiary");
  const weeklySessions = getWeeklySessions();

  const recentEntries = weeklySessions.slice(0, 3).flatMap(session => session.entries);
  const focusCounts = {};
  const lowRated = {};
  const moodCounts = {};

  recentEntries.forEach(entry => {
    const focus = entry.focus || "General";
    focusCounts[focus] = (focusCounts[focus] || 0) + 1;

    if (Number(entry.rating || 0) <= 2) {
      lowRated[focus] = (lowRated[focus] || 0) + 1;
    }

    const mood = String(entry.mood || "").trim();
    if (mood) {
      moodCounts[mood] = (moodCounts[mood] || 0) + 1;
    }
  });

  const weakFocus = Object.entries(lowRated).sort((a, b) => b[1] - a[1])[0];
  const topMood = Object.entries(moodCounts).sort((a, b) => b[1] - a[1])[0];
  const focusLeader = Object.entries(focusCounts).sort((a, b) => b[1] - a[1])[0];
  const leadInsight = topInsights[0] || cachedInsights[0] || null;

  if (secondaryEl) {
    secondaryEl.textContent = weakFocus
      ? `${weakFocus[0]} (${weakFocus[1]} low-rating sessions)`
      : "No low-rating pattern yet";
  }

  if (tertiaryEl) {
    tertiaryEl.textContent = topMood
      ? `${topMood[0]} (${topMood[1]} mentions)`
      : "No mood trend yet";
  }

  if (whyEl) {
    whyEl.textContent = leadInsight?.preview
      || (focusLeader ? `${focusLeader[0]} focus category was reported in ${focusLeader[1]} sessions this week.` : "Add session logs to reveal the weekly focus category formula.");
  }

  if (howEl) {
    howEl.textContent = leadInsight?.action
      || "Use the most recent weekly sessions to isolate one training point, then review by day instead of by individual match.";
  }

  if (sourceEl) {
    sourceEl.textContent = weeklySessions.length
      ? `${weeklySessions.length} weekly session${weeklySessions.length === 1 ? "" : "s"} from Monday to Sunday`
      : "Waiting for current-week sessions";
  }
}

