function getRRTotalAnimationStorageKey() {
  const profile = getActiveProfile?.();
  const key = String(profile?.id || activeProfileId || "default").trim();
  return `vt_rr_total_display_${key || "default"}`;
}

function readPersistedRRTotalDisplay() {
  try {
    const raw = localStorage.getItem(getRRTotalAnimationStorageKey());
    const value = Number(raw);
    return Number.isFinite(value) ? value : null;
  } catch (_error) {
    return null;
  }
}

function writePersistedRRTotalDisplay(value) {
  try {
    localStorage.setItem(getRRTotalAnimationStorageKey(), String(Number(value) || 0));
  } catch (_error) {
    // ignore storage failures
  }
}

function getRRTotalAnimationPayloadKey() {
  return `${getRRTotalAnimationStorageKey()}_payload`;
}

function readRRTotalAnimationPayload() {
  try {
    const raw = localStorage.getItem(getRRTotalAnimationPayloadKey());
    if (!raw) return null;
    const data = JSON.parse(raw);
    const from = Number(data?.from);
    const to = Number(data?.to);
    const ts = Number(data?.ts);
    if (!Number.isFinite(from) || !Number.isFinite(to)) return null;
    return {
      from,
      to,
      ts: Number.isFinite(ts) ? ts : 0
    };
  } catch (_error) {
    return null;
  }
}

function writeRRTotalAnimationPayload(from, to) {
  try {
    localStorage.setItem(getRRTotalAnimationPayloadKey(), JSON.stringify({
      from: Number(from) || 0,
      to: Number(to) || 0,
      ts: Date.now()
    }));
  } catch (_error) {
    // ignore storage failures
  }
}

function clearRRTotalAnimationPayload() {
  try {
    localStorage.removeItem(getRRTotalAnimationPayloadKey());
  } catch (_error) {
    // ignore storage failures
  }
}
