function ensureChartTooltipLayer(){
  if (!tooltip) tooltip = document.getElementById("chartTooltip");
  if (tooltip && tooltip.parentElement !== document.body) {
    tooltip.classList.add("chart-tooltip-floating");
    document.body.appendChild(tooltip);
  }
  return tooltip;
}

function chartScopeAllowsTooltip(size = currentSize) {
  const numericSize = Number(size);
  return Number.isFinite(numericSize) && numericSize < 50;
}

function getChartAxisWindowSize(size = currentSize, matchCount = 0) {
  const normalized = String(size || "5").toLowerCase();
  if (normalized === "all") {
    return Math.max(50, safeNumber(matchCount));
  }
  const numericSize = Number(normalized);
  return Number.isFinite(numericSize) && numericSize > 0 ? numericSize : 5;
}

function setChartTooltipSuppressed(suppressed = true) {
  chartTooltipSuppressed = Boolean(suppressed);
  if (chartTooltipSuppressed) {
    hideChartTooltip();
  }
}

function canRenderChartTooltip() {
  if (chartTooltipSuppressed) return false;
  if (!chartScopeAllowsTooltip(currentSize)) return false;
  const chartPage = chartRow?.closest?.(".page");
  if (!chartPage || chartPage.id !== "page-home") return false;
  if (!chartPage.classList.contains("active")) return false;
  if (chartPage.classList.contains("exiting")) return false;
  if (document.body.classList.contains("has-active-modal")) return false;
  return true;
}

function hideChartTooltip(){
  if (selectedChartTooltipRaf) {
    window.cancelAnimationFrame(selectedChartTooltipRaf);
    selectedChartTooltipRaf = 0;
  }
  const tip = tooltip || document.getElementById("chartTooltip");
  if (tip) {
    tip.classList.remove("chart-tooltip-pop");
    tip.style.opacity = 0;
    tip.style.visibility = "hidden";
  }
  if (crosshair) {
    crosshair.style.opacity = 0;
    crosshair.setAttribute("opacity", "0");
  }
}

function animateChartTooltipPop() {
  const tip = ensureChartTooltipLayer();
  if (!tip) return;
  tip.classList.remove("chart-tooltip-pop");
  void tip.offsetWidth;
  tip.classList.add("chart-tooltip-pop");
}

function positionTooltipToHit(hit, options = {}){
  const { pop = false } = options;

  const tip = ensureChartTooltipLayer();
  if(!tip || !chartRow || !hit) return;
  if (!canRenderChartTooltip()) {
    hideChartTooltip();
    return;
  }
  const svg = chartRow.querySelector("svg");
  if(!svg) return;
  const anchorEl = getChartDotFromHit(hit) || hit;
  const viewBox = svg.viewBox.baseVal;
  const svgRect = svg.getBoundingClientRect();
  const anchorCx = Number(anchorEl.getAttribute("cx") || hit.getAttribute("cx") || 0);
  const anchorCy = Number(anchorEl.getAttribute("cy") || hit.getAttribute("cy") || 0);
  const x = svgRect.left + (((anchorCx - viewBox.x) / viewBox.width) * svgRect.width);
  const y = svgRect.top + (((anchorCy - viewBox.y) / viewBox.height) * svgRect.height);

  tip.style.visibility = "visible";
  tip.style.opacity = 1;
  tip.textContent = `${safeNumber(hit.dataset.totalRr, hit.dataset.rr)} RR`;

  // ========================
  // SMART TOOLTIP POSITION
  // ========================

  const DOT_CLEARANCE_BELOW = 22;
  const DOT_CLEARANCE_ABOVE = 12;
  const tipWidth = tip.offsetWidth || 96;
  const tipHeight = tip.offsetHeight || 32;
  const viewportPad = 10;
  const left = Math.max(viewportPad + tipWidth / 2, Math.min(window.innerWidth - viewportPad - tipWidth / 2, x));
  const flipBelow = (y - DOT_CLEARANCE_ABOVE - tipHeight) < Math.max(viewportPad, svgRect.top);

  tip.style.left = left + "px";

  if (flipBelow) {
    tip.style.top = Math.min(window.innerHeight - viewportPad - tipHeight, y + DOT_CLEARANCE_BELOW) + "px";
    tip.style.setProperty("--chart-tooltip-base-transform", "translate(-50%, 0%)");
    tip.style.transform = "var(--chart-tooltip-base-transform)";
  } else {
    tip.style.top = Math.max(viewportPad + tipHeight, y - DOT_CLEARANCE_ABOVE) + "px";
    tip.style.setProperty("--chart-tooltip-base-transform", "translate(-50%, -100%)");
    tip.style.transform = "var(--chart-tooltip-base-transform)";
  }

  if (pop) animateChartTooltipPop();

}

