function openLensModal(lens){

  hideChartTooltip();
  if (document.activeElement instanceof HTMLElement) {
    document.activeElement.blur();
  }

  const overlay = document.getElementById("lensModalOverlay");
  const title = document.getElementById("lensModalTitle");
  const weightingBlock = document.getElementById("lensWeightingBlock");
  const list = document.getElementById("lensStatsList");
  const weightingTitle = document.getElementById("lensModalWeightingTitle");
  const statsTitle = document.getElementById("lensModalStatsTitle");

  if (!overlay || !title || !weightingBlock || !list) return;

  const model = getPlayerModel();
  const lensDetail = model?.compass?.detailTabs?.[lens];

  title.textContent = lensDetail?.title || "Lens";
  if (weightingTitle) weightingTitle.textContent = "Weighting";
  if (statsTitle) statsTitle.textContent = "Stats Behind This";
  weightingBlock.innerHTML = "";
  list.innerHTML = "";

  (lensDetail?.weighting || []).forEach(item => {
    const pill = document.createElement("div");
    pill.className = "lens-weight-pill";
    pill.innerHTML = `<span>${escapeHtml(item.label)}</span><strong>${escapeHtml(item.stat)}</strong>`;
    weightingBlock.appendChild(pill);
  });

  (lensDetail?.stats || []).forEach(item => {
    const li = document.createElement("li");
    li.className = `lens-stat${item.formula ? " lens-stat-has-formula" : ""}`;
    if (item.formula) {
      li.dataset.formula = item.formula;
    }
    li.innerHTML = `<span>${escapeHtml(item.label)}</span><strong>${escapeHtml(item.stat)}</strong>`;
    list.appendChild(li);
  });

  showModalById("lensModalOverlay");
}

