// ========================
// STORAGE KEYS
// ========================
const STORAGE_KEY_PROFILES = "valtracker_profiles_v1";
const STORAGE_KEY_ACTIVE_ID = "valtracker_active_profile_id";
const STORAGE_KEY_LOG_ENTRIES = "valtracker_log_entries_v1";
const STORAGE_KEY_LAST_BACKEND_SYNC = "valtracker_last_backend_sync_v1";
const STORAGE_KEY_INSIGHT_FEEDBACK = "rankedcoach_insight_feedback_v1";

const backendSyncState = {
  applyingRemote: false,
  saveTimer: null,
  lastSaveReason: "",
  lastError: null
};

let insightFeedbackEntries = readInsightFeedbackEntries();

function readInsightFeedbackEntries() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY_INSIGHT_FEEDBACK);
    const parsed = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed) ? parsed : [];
  } catch (_error) {
    return [];
  }
}

function saveInsightFeedbackEntries(options = {}) {
  try {
    localStorage.setItem(STORAGE_KEY_INSIGHT_FEEDBACK, JSON.stringify(insightFeedbackEntries || []));
  } catch (error) {
    console.warn("Unable to save local insight feedback", error);
  }

  if (!options.skipBackend) {
    queuePersistentAccountSave("insight-feedback");
  }
}

function getInsightSignature(insight = {}) {
  return [
    insight.title,
    insight.type,
    insight.focus,
    insight.what,
    insight.action
  ]
    .map(part => String(part || "").trim().toLowerCase())
    .filter(Boolean)
    .join("|")
    .slice(0, 420);
}

function getLatestInsightFeedback(signature = "") {
  const key = String(signature || "").trim();
  if (!key) return null;
  return (insightFeedbackEntries || [])
    .slice()
    .reverse()
    .find(entry => entry.signature === key) || null;
}

function recordInsightFeedback(insight = {}, rating = "helpful") {
  const signature = getInsightSignature(insight);
  if (!signature) return null;

  const model = getPlayerModel();
  const entry = {
    id: uuid(),
    signature,
    rating,
    title: insight.title || "",
    type: insight.type || "",
    focus: insight.focus || model?.focus || "",
    priority: safeNumber(insight.priority),
    confidenceScore: safeNumber(model?.confidenceScore),
    currentAct: model?.currentAct || "Current Window",
    profileId: activeProfileId || "",
    sourceCount: Array.isArray(insight.sources) ? insight.sources.length : 0,
    context: {
      matchesPlayed: safeNumber(model?.overview?.matchesPlayed),
      winrate: safeNumber(model?.overview?.winrate),
      kd: safeNumber(model?.overview?.kd),
      bestAgent: model?.agents?.[0]?.agent || "",
      strongestMap: model?.maps?.[0]?.map || "",
      weaponReliance: model?.coachingContext?.relianceFlags || []
    },
    createdAt: nowISO()
  };

  insightFeedbackEntries = [
    ...(insightFeedbackEntries || []).filter(item => item.signature !== signature),
    entry
  ].slice(-300);
  saveInsightFeedbackEntries();
  return entry;
}

function getInsightFeedbackSummary() {
  const entries = insightFeedbackEntries || [];
  const helpful = entries.filter(entry => entry.rating === "helpful").length;
  const inaccurate = entries.filter(entry => entry.rating === "inaccurate").length;
  return {
    total: entries.length,
    helpful,
    inaccurate,
    helpfulRate: entries.length ? safeDivide(helpful * 100, entries.length) : 0
  };
}

function readLocalLogEntries() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY_LOG_ENTRIES);
    const parsed = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed) ? parsed : [];
  } catch (_error) {
    return [];
  }
}

function saveLogEntries(options = {}) {
  try {
    localStorage.setItem(STORAGE_KEY_LOG_ENTRIES, JSON.stringify(logEntries || []));
  } catch (error) {
    console.warn("Unable to save local log cache", error);
  }

  if (!options.skipBackend) {
    queuePersistentAccountSave("logs");
  }
}

function mergeLogEntries(primary = [], secondary = []) {
  const merged = new Map();
  [...secondary, ...primary].forEach((entry) => {
    if (!entry || typeof entry !== "object") return;
    const id = String(entry.id || "").trim() || uuid();
    merged.set(id, { ...entry, id });
  });

  return [...merged.values()].sort((a, b) =>
    new Date(b?.createdAt || 0).getTime() - new Date(a?.createdAt || 0).getTime()
  );
}

function serializePersistentAccountState() {
  return {
    schemaVersion: 1,
    savedAt: nowISO(),
    activeProfileId,
    profiles: (profiles || []).map(normalizeProfileRecord),
    logEntries: logEntries || [],
    insightFeedbackEntries: insightFeedbackEntries || [],
    themeBuilderState: THEME_BUILDER_LAUNCH_LOCKED ? {} : (typeof themeBuilderState !== "undefined" ? themeBuilderState : {}),
    themeBuilderUiState: THEME_BUILDER_LAUNCH_LOCKED ? {} : (typeof themeBuilderUiState !== "undefined" ? themeBuilderUiState : {}),
    currentThemeKey: getActiveProfile()?.themeKey || getCurrentThemeBuilderThemeKey?.() || "default"
  };
}

function applyPersistentAccountState(state = {}) {
  if (!state || typeof state !== "object") return;

  backendSyncState.applyingRemote = true;
  try {
    if (Array.isArray(state.profiles) && state.profiles.length) {
      profiles = state.profiles.map(normalizeProfileRecord);
      activeProfileId = state.activeProfileId || profiles[0]?.id || activeProfileId;
      localStorage.setItem(STORAGE_KEY_PROFILES, JSON.stringify(profiles));
      localStorage.setItem(STORAGE_KEY_ACTIVE_ID, activeProfileId || "");
    }

    if (Array.isArray(state.logEntries)) {
      logEntries = mergeLogEntries(state.logEntries, readLocalLogEntries());
      saveLogEntries({ skipBackend: true });
    }

    if (Array.isArray(state.insightFeedbackEntries)) {
      const mergedFeedback = new Map();
      [...readInsightFeedbackEntries(), ...state.insightFeedbackEntries].forEach((entry) => {
        if (!entry || typeof entry !== "object") return;
        const id = String(entry.id || uuid());
        mergedFeedback.set(id, { ...entry, id });
      });
      insightFeedbackEntries = [...mergedFeedback.values()]
        .sort((a, b) => new Date(a?.createdAt || 0).getTime() - new Date(b?.createdAt || 0).getTime())
        .slice(-300);
      saveInsightFeedbackEntries({ skipBackend: true });
    }

    if (state.themeBuilderState && typeof state.themeBuilderState === "object" && typeof themeBuilderState !== "undefined") {
      if (THEME_BUILDER_LAUNCH_LOCKED) {
        archiveThemeBuilderLocalStorageForLaunchLock();
      } else {
      const mergedThemeBuilderState = mergeLocalAndRemoteThemeBuilderState(
        themeBuilderState,
        state.themeBuilderState
      );
      themeBuilderState = normalizeLoadedThemeBuilderState(
        mergeBakedThemeBuilderState(mergedThemeBuilderState)
      );
      localStorage.setItem(THEME_BUILDER_STORAGE_KEY, JSON.stringify(themeBuilderState));
      applyThemeBuilderFontImports?.();
      applyThemeBuilderRuntimeStyles?.();
      }
    }

    const active = getActiveProfile();
    matches = active?.matches ? active.matches.slice() : [];
    recomputeFromMatches?.();
    renderProfilesUI?.();
    rebuildProfileListUI?.();
    updateProfileHeaderUI?.();
    updateDisplays?.();
    initStatsPage?.();
    renderStatsAgents?.();
    renderStatsMaps?.();
    renderInsights?.();
    renderLogFeed?.();
    renderChart?.(currentSize);
  } finally {
    backendSyncState.applyingRemote = false;
  }
}

async function getSupabaseUser() {
  if (!supabaseClient?.auth) return null;
  const { data: { user } = {}, error } = await supabaseClient.auth.getUser();
  if (error) {
    backendSyncState.lastError = error;
    return null;
  }
  return user || null;
}

function queuePersistentAccountSave(reason = "state") {
  if (backendSyncState.applyingRemote || !supabaseClient?.auth) return;

  backendSyncState.lastSaveReason = reason;
  window.clearTimeout(backendSyncState.saveTimer);
  backendSyncState.saveTimer = window.setTimeout(() => {
    void savePersistentAccountState(reason);
  }, 550);
}

function buildLogRowsForSupabase(userId) {
  const activeProfile = getActiveProfile();
  return (logEntries || []).map((entry) => ({
    id: String(entry.id || uuid()),
    user_id: userId,
    profile_id: String(activeProfile?.id || activeProfileId || "default"),
    match_id: entry.matchId || null,
    agent: entry.agent || null,
    role: entry.role || null,
    map: entry.map || null,
    focus: entry.focus || null,
    rating: Number.isFinite(Number(entry.rating)) ? Number(entry.rating) : null,
    mood: entry.mood || null,
    team_comms: entry.teamComms || null,
    self_comms: entry.selfComms || null,
    notes: entry.notes || "",
    warmup: Boolean(entry.warmup),
    entry_json: entry,
    created_at: entry.createdAt || nowISO(),
    updated_at: nowISO()
  }));
}

function buildMatchRowsForSupabase(userId) {
  const rows = [];
  (profiles || []).forEach((profile) => {
    (profile.matches || []).forEach((match, index) => {
      const core = getMatchCore(match);
      const matchId = String(match?.id || match?.matchId || match?.metadata?.matchId || `${profile.id}_${index}`);
      rows.push({
        id: matchId,
        user_id: userId,
        profile_id: String(profile.id || "default"),
        riot_match_id: match?.metadata?.matchId || match?.matchId || null,
        source: profile.importSource || match?.source || "app",
        map: core?.map || match?.map || match?.metadata?.map || null,
        agent: core?.agent || match?.agent || match?.metadata?.agent || null,
        role: match?.role || null,
        result: match?.result || match?.metadata?.result || null,
        rr_change: safeNumber(match?.rr),
        kills: Number.isFinite(core?.kills) ? core.kills : safeNumber(match?.kills, null),
        deaths: Number.isFinite(core?.deaths) ? core.deaths : safeNumber(match?.deaths, null),
        assists: Number.isFinite(core?.assists) ? core.assists : safeNumber(match?.assists, null),
        acs: Number.isFinite(core?.acs) ? core.acs : safeNumber(match?.acs, null),
        match_json: match,
        played_at: match?.createdAt || match?.metadata?.playedAt || nowISO(),
        updated_at: nowISO()
      });
    });
  });
  return rows;
}

async function savePersistentAccountState(reason = "state") {
  if (backendSyncState.applyingRemote || !supabaseClient?.auth) return;

  const user = await getSupabaseUser();
  if (!user) return;

  const state = serializePersistentAccountState();
  const active = getActiveProfile();

  const { error: appStateError } = await supabaseClient
    .from("vip_app_state")
    .upsert({
      user_id: user.id,
      active_profile_id: activeProfileId || null,
      profiles_json: state.profiles,
      log_entries_json: state.logEntries,
      theme_builder_json: state.themeBuilderState,
      theme_builder_ui_json: state.themeBuilderUiState,
      current_theme_key: state.currentThemeKey,
      last_save_reason: reason,
      updated_at: nowISO()
    }, { onConflict: "user_id" });

  if (appStateError) {
    backendSyncState.lastError = appStateError;
    console.warn("Supabase app-state save failed", appStateError);
    return;
  }

  if (active) {
    await supabaseClient
      .from("users_profiles")
      .upsert({
        user_id: user.id,
        riot_id: active.riotId || null,
        region: active.region || "NA",
        profile_json: active,
        updated_at: nowISO()
      }, { onConflict: "user_id" });
  }

  const logRows = buildLogRowsForSupabase(user.id);
  if (logRows.length) {
    const { error } = await supabaseClient
      .from("reflection_logs")
      .upsert(logRows, { onConflict: "id" });
    if (error) console.warn("Supabase log save failed", error);
  }

  const matchRows = buildMatchRowsForSupabase(user.id);
  if (matchRows.length) {
    const { error } = await supabaseClient
      .from("match_snapshots")
      .upsert(matchRows, { onConflict: "id" });
    if (error) console.warn("Supabase match save failed", error);
  }

  localStorage.setItem(STORAGE_KEY_LAST_BACKEND_SYNC, nowISO());
  backendSyncState.lastError = null;
}

async function deletePersistentLogEntry(id) {
  if (!id || !supabaseClient?.auth) return;
  const user = await getSupabaseUser();
  if (!user) return;

  const { error } = await supabaseClient
    .from("reflection_logs")
    .delete()
    .eq("user_id", user.id)
    .eq("id", String(id));

  if (error) console.warn("Supabase log delete failed", error);
}

async function loadPersistentAccountState(user) {
  if (!user || !supabaseClient) return;

  const { data, error } = await supabaseClient
    .from("vip_app_state")
    .select("*")
    .eq("user_id", user.id)
    .maybeSingle();

  if (error) {
    backendSyncState.lastError = error;
    console.warn("Supabase app-state load failed", error);
    return;
  }

  if (data) {
    applyPersistentAccountState({
      activeProfileId: data.active_profile_id,
      profiles: data.profiles_json,
      logEntries: data.log_entries_json,
      themeBuilderState: data.theme_builder_json,
      themeBuilderUiState: data.theme_builder_ui_json
    });
  }

  await savePersistentAccountState(data ? "auth-merge" : "auth-initial-save");
}

async function handleSignedInUser(user) {
  currentAuthUser = user || null;
  updateAuthUI(user || null);
  if (!user) return;
  await loadPersistentAccountState(user);
}

