// ========================
// COMPASS HELPERS
// ========================

function updateCompassPercentages(aim, sense, team, discipline){
  const normalize = (value) => {
    const n = safeNumber(value);
    return clampPercent(n <= 1 ? n * 100 : n);
  };

  const pAim = normalize(aim);
  const pSense = normalize(sense);
  const pTeam = normalize(team);
  const pDisc = normalize(discipline);

  document.querySelector(".percent-aim").textContent = `${pAim}`;
  document.querySelector(".percent-sense").textContent = `${pSense}`;
  document.querySelector(".percent-team").textContent = `${pTeam}`;
  document.querySelector(".percent-discipline").textContent = `${pDisc}`;

  updateCompassPolygon(pAim, pSense, pTeam, pDisc);
}

function updateCompassPolygon(a,s,t,d){

  const polygon = document.getElementById("compassPolygon");
  if(!polygon) return;

  const cx = 100;
  const cy = 100;
  const rMax = 80;
  const toRadius = (percent) => rMax * (clampPercent(percent) / 100);

  const points = [
    `${cx},${cy - toRadius(a)}`,
    `${cx + toRadius(s)},${cy}`,
    `${cx},${cy + toRadius(t)}`,
    `${cx - toRadius(d)},${cy}`
  ].join(" ");

  polygon.setAttribute("points",points);
}

function setCrestPreviewMeta(isPlaying, label = "Live Build") {
  if (crestCycleBtn) {
    crestCycleBtn.classList.toggle("is-playing", !!isPlaying);
    crestCycleBtn.textContent = isPlaying ? "Stop Cycle" : "Cycle Profiles";
  }

  if (crestCycleLabelEl) {
    crestCycleLabelEl.textContent = label;
  }
}

function getCompassTierLabel(score) {
  const value = clampPercent(score);
  if (value >= 80) return "Strong";
  if (value >= 65) return "Stable";
  if (value >= 45) return "Developing";
  return "Needs Work";
}

function getCompassProfileLabel(values = {}) {
  const entries = Object.entries(values).sort((a, b) => safeNumber(b[1]) - safeNumber(a[1]));
  const top = entries[0]?.[0];
  const second = entries[1]?.[0];
  const topValue = safeNumber(entries[0]?.[1]);
  const secondValue = safeNumber(entries[1]?.[1]);
  const hasAnyScore = entries.some(([, value]) => safeNumber(value) > 0);

  if (!hasAnyScore) return "No Data";
  if (!top) return "Balanced Build";
  if (Math.abs(topValue - secondValue) <= 4) return "Balanced Build";

  return `${COMPASS_LENS_META[top]?.label || "Skill"} Primary`;
}

const COMPASS_RANK_AVERAGE_TARGETS = {
  iron: 36,
  bronze: 40,
  silver: 46,
  gold: 54,
  platinum: 62,
  diamond: 70,
  ascendant: 77,
  immortal: 84,
  radiant: 90
};

function getCompassRankExpectation(tierLabel = "") {
  const key = String(tierLabel || "").trim().toLowerCase().split(/\s+/)[0] || "iron";
  const order = ["iron", "bronze", "silver", "gold", "platinum", "diamond", "ascendant", "immortal", "radiant"];
  const index = Math.max(0, order.indexOf(key));
  const currentKey = order[index] || "iron";
  const nextKey = order[index + 1] || null;

  return {
    key: currentKey,
    currentTarget: COMPASS_RANK_AVERAGE_TARGETS[currentKey] || 36,
    nextKey,
    nextTarget: nextKey ? COMPASS_RANK_AVERAGE_TARGETS[nextKey] || null : null,
    nextLabel: nextKey ? nextKey.charAt(0).toUpperCase() + nextKey.slice(1) : ""
  };
}

function getCompassRoleContext(roleName = "", strongestLens = "", weakestLens = "") {
  const roleKey = String(roleName || "").trim().toLowerCase();
  const comboKey = `${roleKey}:${strongestLens}:${weakestLens}`;
  const comboMap = {
    "duelist:aim:teamplay": "On a duelist-leaning sample, that usually means you can open fights but still bleed rounds when trades and follow-through are not synced.",
    "duelist:aim:discipline": "On a duelist-leaning sample, that often looks like strong first-fight mechanics getting wasted by overpeeks or forcing one fight too many.",
    "controller:gamesense:discipline": "On a controller-leaning sample, that usually shows up as good reads that still need cleaner utility pacing and economy discipline.",
    "initiator:gamesense:teamplay": "On an initiator-leaning sample, it often means your reads are solid but the setup timing is not always turning into full team value.",
    "sentinel:discipline:aim": "On a sentinel-leaning sample, that usually means your structure is stable but your punish damage still needs to convert more cleanly."
  };

  if (comboMap[comboKey]) {
    return comboMap[comboKey];
  }

  const roleMap = {
    duelist: "Because the recent sample leans duelist, entry pressure, follow-through, and self-created fights weigh heavily in this read.",
    initiator: "Because the recent sample leans initiator, setup timing, info value, and teammate conversion weigh heavily in this read.",
    controller: "Because the recent sample leans controller, utility pacing, map control, and round structure weigh heavily in this read.",
    sentinel: "Because the recent sample leans sentinel, anchor stability, survival value, and punish timing weigh heavily in this read."
  };

  return roleMap[roleKey] || "";
}

function buildCompassProfileDescription(values = {}, model = null) {
  if (values?.noData || (model && !safeNumber(model?.overview?.matchesPlayed))) {
    return "Import match history before RankedCoach builds a compass read. The four category scores stay at zero until real player data is available.";
  }

  const strongestLens = values?.strongestLens || "aim";
  const weakestLens = values?.weakestLens || "discipline";
  const averageScore = Math.round(averageValue([
    safeNumber(values?.aim),
    safeNumber(values?.gamesense),
    safeNumber(values?.teamplay),
    safeNumber(values?.discipline)
  ]));
  const currentRank = getTierRank(computeCurrentRRAbsolute())?.tierLabel || "Iron 1";
  const rankExpectation = getCompassRankExpectation(currentRank);
  const roleName = String(model?.scoring?.activeRoleName || model?.roles?.[0]?.role || "").trim();
  const agentName = String(model?.scoring?.activeAgentName || model?.agents?.[0]?.agent || "").trim();
  const strongestReadMap = {
    aim: "Your strongest category is raw mechanical conversion and direct duel pressure.",
    gamesense: "Your strongest category is timing, round awareness, and better decision flow.",
    teamplay: "Your strongest category is spacing, trade value, and coordinated round play.",
    discipline: "Your strongest category is steadiness, restraint, and repeatable round structure."
  };
  const weakestReadMap = {
    aim: "The main leak is still finishing fights cleanly enough to cash those rounds in.",
    gamesense: "The main leak is still reading the round early enough to turn good spots into cleaner outcomes.",
    teamplay: "The main leak is still linking your value with teammates through trades, timing, and follow-through.",
    discipline: "The main leak is still protecting value through patience, economy control, and fewer unnecessary commits."
  };
  const baselineGap = averageScore - rankExpectation.currentTarget;
  const nextGap = rankExpectation.nextTarget == null
    ? null
    : Math.max(0, Math.round(rankExpectation.nextTarget - averageScore));
  const lowRankNote = ["iron", "bronze", "silver"].includes(rankExpectation.key)
    ? "Lower ranks naturally run lower four-lens averages, so the goal is steady improvement rather than forcing every category into elite territory immediately."
    : "";
  const agentRoleLabel = [agentName, roleName].filter(Boolean).join(" / ");
  const benchmarkSentence = baselineGap >= 0
    ? `At ${averageScore} average, this profile is about ${Math.abs(Math.round(baselineGap))} points above the usual ${currentRank} benchmark.`
    : `At ${averageScore} average, this profile is about ${Math.abs(Math.round(baselineGap))} points below the usual ${currentRank} benchmark.`;
  const nextRankSentence = rankExpectation.nextTarget == null
    ? "At the top end, progress usually comes from shaving down the last weak lens rather than adding one more specialty."
    : `${rankExpectation.nextLabel} profiles tend to be closer to ${rankExpectation.nextTarget} average, so roughly ${nextGap} more average points is the next rung to chase.`;
  const roleSentence = getCompassRoleContext(roleName, strongestLens, weakestLens);

  return [
    `${agentRoleLabel ? `${agentRoleLabel} is reading as a ` : "This is a "}${COMPASS_LENS_META[strongestLens]?.label || "core"}-leaning profile. ${strongestReadMap[strongestLens] || ""} ${weakestReadMap[weakestLens] || ""}`.trim(),
    roleSentence || benchmarkSentence,
    roleSentence ? `${benchmarkSentence} ${nextRankSentence} ${lowRankNote}`.trim() : `${nextRankSentence} ${lowRankNote}`.trim()
  ].filter(Boolean).join(" ");
}

function updateBuildCoreVisual(aim, sense, team, discipline) {
  const values = {
    aim: clampPercent(aim),
    sense: clampPercent(sense),
    team: clampPercent(team),
    discipline: clampPercent(discipline)
  };

  const topLength = 80 * (values.aim / 100);
  const rightLength = 80 * (values.sense / 100);
  const bottomLength = 80 * (values.team / 100);
  const leftLength = 80 * (values.discipline / 100);
  const topNode = document.getElementById("coreNodeAim");
  const rightNode = document.getElementById("coreNodeSense");
  const bottomNode = document.getElementById("coreNodeTeam");
  const leftNode = document.getElementById("coreNodeDiscipline");

  if (topNode) {
    topNode.setAttribute("cx", "100");
    topNode.setAttribute("cy", `${100 - topLength}`);
    topNode.setAttribute("r", `${4 + (values.aim / 40)}`);
  }
  if (rightNode) {
    rightNode.setAttribute("cx", `${100 + rightLength}`);
    rightNode.setAttribute("cy", "100");
    rightNode.setAttribute("r", `${4 + (values.sense / 40)}`);
  }
  if (bottomNode) {
    bottomNode.setAttribute("cx", "100");
    bottomNode.setAttribute("cy", `${100 + bottomLength}`);
    bottomNode.setAttribute("r", `${4 + (values.team / 40)}`);
  }
  if (leftNode) {
    leftNode.setAttribute("cx", `${100 - leftLength}`);
    leftNode.setAttribute("cy", "100");
    leftNode.setAttribute("r", `${4 + (values.discipline / 40)}`);
  }

  updateCompassPolygon(values.aim, values.sense, values.team, values.discipline);
}

function getLiveCompassValues() {
  const model = getPlayerModel();
  return {
    aim: safeNumber(model?.compass?.aim),
    gamesense: safeNumber(model?.compass?.gamesense),
    teamplay: safeNumber(model?.compass?.teamplay),
    discipline: safeNumber(model?.compass?.discipline),
    source: model?.compass?.source || model?.currentAct || "Current Window",
    profileShare: model?.compass?.profileShare || {},
    strongestLens: model?.compass?.strongestLens,
    weakestLens: model?.compass?.weakestLens,
    noData: model?.compass?.noData || !safeNumber(model?.overview?.matchesPlayed),
    model
  };
}

function applyCompassVisual(values = {}) {
  const hasModelContext = Boolean(values?.model);
  const noData = Boolean(values?.noData || (hasModelContext && !safeNumber(values?.model?.overview?.matchesPlayed)));
  const profileShare = values?.profileShare || normalizeDistributionTo100({
    aim: safeNumber(values?.aim),
    gamesense: safeNumber(values?.gamesense),
    teamplay: safeNumber(values?.teamplay),
    discipline: safeNumber(values?.discipline)
  });
  const strongestLens = noData ? "" : (values?.strongestLens || Object.entries({
    aim: safeNumber(values?.aim),
    gamesense: safeNumber(values?.gamesense),
    teamplay: safeNumber(values?.teamplay),
    discipline: safeNumber(values?.discipline)
  }).sort((a, b) => b[1] - a[1])[0]?.[0] || "aim");
  const weakestLens = noData ? "" : (values?.weakestLens || Object.entries({
    aim: safeNumber(values?.aim),
    gamesense: safeNumber(values?.gamesense),
    teamplay: safeNumber(values?.teamplay),
    discipline: safeNumber(values?.discipline)
  }).sort((a, b) => a[1] - b[1])[0]?.[0] || "discipline");
  const averageScore = Math.round(averageValue([
    safeNumber(values?.aim),
    safeNumber(values?.gamesense),
    safeNumber(values?.teamplay),
    safeNumber(values?.discipline)
  ]));
  const profileLabel = noData ? "No Data" : (values?.profileLabel || getCompassProfileLabel({
    aim: safeNumber(values?.aim),
    gamesense: safeNumber(values?.gamesense),
    teamplay: safeNumber(values?.teamplay),
    discipline: safeNumber(values?.discipline)
  }));

  updateCompassPercentages(
    safeNumber(values?.aim),
    safeNumber(values?.gamesense),
    safeNumber(values?.teamplay),
    safeNumber(values?.discipline)
  );
  updateBuildCoreVisual(
    safeNumber(values?.aim),
    safeNumber(values?.gamesense),
    safeNumber(values?.teamplay),
    safeNumber(values?.discipline)
  );

  const sourcePill = document.getElementById("compassSourcePill");
  const profileTitle = document.getElementById("compassProfileTitle");
  const profileCopy = document.getElementById("compassProfileCopy");
  const averageScoreEl = document.getElementById("compassAverageScore");
  const strongestEl = document.getElementById("compassStrongestCallout");
  const weakestEl = document.getElementById("compassWeakestCallout");
  const profileDescriptionEl = document.getElementById("compassProfileDescription");

  if (sourcePill) sourcePill.textContent = noData ? "No Data" : (values?.source || "Current Window");
  if (profileTitle) profileTitle.textContent = profileLabel;
  if (profileCopy) {
    profileCopy.textContent = noData
      ? "Import match history to unlock category scores."
      : values?.summary
      || `${COMPASS_LENS_META[strongestLens]?.label || "Aim"} is your best category, while ${COMPASS_LENS_META[weakestLens]?.label || "Teamwork"} has the most room to improve.`;
  }
  if (averageScoreEl) averageScoreEl.textContent = `Avg ${averageScore}`;
  if (strongestEl) strongestEl.textContent = noData ? "Strongest: No Data" : `Strongest: ${COMPASS_LENS_META[strongestLens]?.label || "Aim"}`;
  if (weakestEl) weakestEl.textContent = noData ? "Weakest: No Data" : `Weakest: ${COMPASS_LENS_META[weakestLens]?.label || "Teamwork"}`;
  if (profileDescriptionEl) {
    profileDescriptionEl.textContent = values?.description || buildCompassProfileDescription(values, values?.model || null);
  }
  syncCompassDescriptionToggleState(false);

  [
    { key: "aim", suffix: "Aim" },
    { key: "gamesense", suffix: "Sense" },
    { key: "teamplay", suffix: "Team" },
    { key: "discipline", suffix: "Discipline" }
  ].forEach(({ key, suffix }) => {
    const score = Math.round(clampPercent(safeNumber(values?.[key])));
    const scoreEl = document.getElementById(`compassScore${suffix}`);
    const tierEl = document.getElementById(`compassTier${suffix}`);
    const metaEl = document.getElementById(`compassMeta${suffix}`);
    const barEl = document.getElementById(`compassBar${suffix}`);
    const cardEl = document.getElementById(`compassCard${suffix}`);
    const share = noData ? 0 : Math.round(safeNumber(profileShare?.[key]));

    if (scoreEl) scoreEl.textContent = `${score}`;
    if (tierEl) tierEl.textContent = noData ? "No Data" : getCompassTierLabel(score);
    if (metaEl) metaEl.textContent = `Profile share ${share}% · ${COMPASS_LENS_META[key]?.summary || ""}`;
    if (metaEl && noData) metaEl.textContent = "No match data yet.";
    if (barEl) barEl.style.width = `${score}%`;
    if (cardEl) cardEl.classList.toggle("is-strongest", !noData && key === strongestLens);
  });
}

function stopCrestPreview() {
  if (crestPreviewTimer) {
    clearInterval(crestPreviewTimer);
    crestPreviewTimer = null;
  }
  crestPreviewActive = false;
  crestPreviewIndex = 0;
  setCrestPreviewMeta(false, "Live Snapshot");
  applyCompassVisual(getLiveCompassValues());
}

function stepCrestPreview() {
  const state = CREST_PREVIEW_STATES[crestPreviewIndex % CREST_PREVIEW_STATES.length];
  crestPreviewIndex += 1;
  setCrestPreviewMeta(true, state.label);
  applyCompassVisual(state);
}

function startCrestPreview() {
  if (crestPreviewTimer) {
    clearInterval(crestPreviewTimer);
  }

  crestPreviewActive = true;
  crestPreviewIndex = 0;
  stepCrestPreview();
  crestPreviewTimer = setInterval(() => {
    stepCrestPreview();
  }, 1400);
}

// ========================
// CHART HELPERS
// ========================

function cancelChartFrame() {
  if (chartAnimFrame) {
    cancelAnimationFrame(chartAnimFrame);
    chartAnimFrame = null;
  }
}

function resetChartFlags() {
  chartAnimating = false;
  chartBusy = false;
  isUndoAnimating = false;
  undoDirection = false;
  skipNextChartAnimation = false;
}

function buildCumulativeRR(matchList) {
  const cumulative = [];
  let total = 0;

  matchList.forEach(match => {
    total += Number(match?.rr || 0);
    cumulative.push(total);
  });

  return cumulative;
}

function getMatchIdentityKey(match = {}) {
  if (!match) return "";

  const id = String(match?.id || match?.matchId || "").trim();
  if (id) {
    return `id:${id}`;
  }

  const core = getMatchCore(match);
  const createdAt = String(match?.createdAt || match?.metadata?.playedAt || core?.createdAt || "").trim();
  const agent = String(match?.metadata?.agent || match?.agent || core?.agent || "").trim().toLowerCase();
  const map = String(match?.metadata?.mapName || match?.map || core?.map || "").trim().toLowerCase();
  const rr = Number(match?.rr);

  if (!createdAt && !agent && !map && !Number.isFinite(rr)) {
    return "";
  }

  return `fallback:${createdAt}|${agent}|${map}|${Number.isFinite(rr) ? rr : ""}`;
}

function findImpactSnapshotForMatch(match, matchIndex, impactSnapshots = []) {
  if (!Array.isArray(impactSnapshots) || !impactSnapshots.length) {
    return null;
  }

  const matchKey = getMatchIdentityKey(match);
  if (matchKey) {
    const exact = impactSnapshots.find(snapshot => getMatchIdentityKey(snapshot) === matchKey);
    if (exact) {
      return exact;
    }
  }

  const matchId = String(match?.id || match?.matchId || "").trim();
  if (matchId) {
    const byId = impactSnapshots.find(snapshot =>
      String(snapshot?.id || "").trim() === matchId ||
      String(snapshot?.matchId || "").trim() === matchId
    );
    if (byId) {
      return byId;
    }
  }

  if (Number.isInteger(matchIndex) && matchIndex >= 0) {
    return impactSnapshots.find(snapshot => Number(snapshot?.matchIndex) === matchIndex) || null;
  }

  return null;
}

function getChartSlice(cumulative, size, matchCount) {
  const maxWindow = size === "all"
    ? matchCount
    : Math.min(matchCount, Number(size) || 5);

  const slice = cumulative.slice(-maxWindow);
  slice.unshift(0);
  return slice;
}

function getChartIntroTiming(size, segmentCount, useContinuousIntro = false) {
  const normalizedSize = String(size || "5").toLowerCase();
  const baseSegmentMs = 360;
  const readableMinMs = 70;

  if (!useContinuousIntro) {
    return {
      segmentMs: baseSegmentMs,
      finalPauseMs: 120,
      finalSegmentMs: 620
    };
  }

  let segmentMs = baseSegmentMs;

  if (normalizedSize === "20") {
    segmentMs = baseSegmentMs / 2;
  } else if (normalizedSize === "50") {
    segmentMs = baseSegmentMs / 3;
  } else if (normalizedSize === "all") {
    const visibleSegments = Math.max(1, Number(segmentCount) || 1);
    segmentMs = 6000 / visibleSegments;
  }

  const minimumSegmentMs = normalizedSize === "all" ? 1 : readableMinMs;
  segmentMs = Math.max(minimumSegmentMs, Math.round(segmentMs * 1000) / 1000);

  return {
    segmentMs,
    finalPauseMs: 0,
    finalSegmentMs: segmentMs
  };
}

function getChartBounds(slice) {
  const rawMax = Math.max(...slice, 25);
  const rawMin = Math.min(...slice, -25);

  const maxTick = Math.ceil(rawMax / 25) * 25;
  const minTick = Math.floor(rawMin / 25) * 25;

  return { minTick, maxTick };
}

function makeChartY(minTick, maxTick) {
  return function y(v) {
    return PAD_BOTTOM - ((v - minTick) / (maxTick - minTick)) * (PAD_BOTTOM - PAD_TOP);
  };
}

function buildChartPoints(slice, y) {
  const plotWidth = CHART_W - PAD_LEFT - PAD_RIGHT;
  const step = slice.length > 1 ? plotWidth / (slice.length - 1) : 0;
  const visibleMatchCount = Math.max(0, slice.length - 1);
  const startMatchIndex = Math.max(0, matches.length - visibleMatchCount);
  const impactSnapshots = getPlayerModel()?.scoring?.impactSnapshots || [];

  return slice.map((value, index) => {
    if (index === 0) {
      return {
        x: PAD_LEFT + index * step,
        y: y(value),
        rr: 0,
        value,
        matchIndex: -1,
        match: null,
        snapshot: null,
        matchId: "",
        matchKey: ""
      };
    }

    const matchIndex = startMatchIndex + index - 1;
    const match = matches[matchIndex] || null;
    const snapshot = findImpactSnapshotForMatch(match, matchIndex, impactSnapshots);

    return {
      x: PAD_LEFT + index * step,
      y: y(value),
      rr: value - slice[index - 1],
      value,
      matchIndex,
      match,
      snapshot,
      matchId: String((match?.id || match?.matchId || snapshot?.id || snapshot?.matchId || "")),
      matchKey: getMatchIdentityKey(match || snapshot || {})
    };
  });
}

function buildDotMarkup(point, { final = false, intro = false, introDelayMs = 0 } = {}) {
  if (!point || !Number.isInteger(point.matchIndex) || point.matchIndex < 0) {
    return "";
  }

  const snapshot = point.snapshot || {};
  const fill = snapshot?.impactColor || (final ? "#facc15" : "#e5e7eb");
  const dotClass = `${final ? "final-end" : "rr-dot"}${intro ? " chart-intro-dot" : ""}${final && intro ? " chart-intro-dot-final" : ""}`;
  const matchStats = {
    kills: Number.isFinite(Number(snapshot?.kills)) ? Number(snapshot.kills) : getMatchPanelStats(point.match || {}).kills,
    deaths: Number.isFinite(Number(snapshot?.deaths)) ? Number(snapshot.deaths) : getMatchPanelStats(point.match || {}).deaths,
    assists: Number.isFinite(Number(snapshot?.assists)) ? Number(snapshot.assists) : getMatchPanelStats(point.match || {}).assists,
    acs: Number.isFinite(Number(snapshot?.acs)) ? Number(snapshot.acs) : getMatchPanelStats(point.match || {}).acs
  };
  const statsAttrs = `
data-kills="${Number.isFinite(Number(matchStats.kills)) ? Math.round(Number(matchStats.kills)) : ""}"
data-deaths="${Number.isFinite(Number(matchStats.deaths)) ? Math.round(Number(matchStats.deaths)) : ""}"
data-assists="${Number.isFinite(Number(matchStats.assists)) ? Math.round(Number(matchStats.assists)) : ""}"
data-acs="${Number.isFinite(Number(matchStats.acs)) ? Math.round(Number(matchStats.acs)) : ""}"
data-map="${escapeHtml(snapshot?.map || point?.match?.metadata?.mapName || point?.match?.map || "")}"
data-agent="${escapeHtml(snapshot?.agent || point?.match?.metadata?.agent || point?.match?.agent || "")}"
data-result="${escapeHtml(point?.match?.result || point?.match?.metadata?.result || "")}"
data-created-at="${escapeHtml(point?.match?.createdAt || point?.match?.metadata?.playedAt || snapshot?.createdAt || "")}"
data-impact-tier="${escapeHtml(snapshot?.impactTier || "")}"
data-impact-score="${Number.isFinite(Number(snapshot?.impactScore)) ? Math.round(Number(snapshot?.impactScore)) : ""}"
data-impact-color="${escapeHtml(snapshot?.impactColor || "")}"
data-match-id="${escapeHtml(point?.matchId || snapshot?.id || point?.match?.id || point?.match?.matchId || "")}"
data-match-key="${escapeHtml(point?.matchKey || "")}"`;

  const introStyle = intro
    ? `--intro-delay:${introDelayMs}ms;opacity:0;transform:scale(.2);transform-box:fill-box;transform-origin:center;`
    : "";

  return `
<circle class="rr-hit"
cx="${point.x}"
cy="${point.y}"
r="${HIT_RADIUS}"
data-rr="${point.rr}"
data-total-rr="${point.value}"
data-index="${point.matchIndex}"
data-match-index="${point.matchIndex}"
${statsAttrs}/>

<circle class="${dotClass}"
cx="${point.x}"
cy="${point.y}"
r="${DOT_RADIUS}"
data-rr="${point.rr}"
data-total-rr="${point.value}"
data-index="${point.matchIndex}"
data-match-index="${point.matchIndex}"
data-match-id="${escapeHtml(point?.matchId || snapshot?.id || point?.match?.id || point?.match?.matchId || "")}"
data-match-key="${escapeHtml(point?.matchKey || "")}"
data-impact-tier="${escapeHtml(snapshot?.impactTier || "")}"
data-impact-score="${Number.isFinite(Number(snapshot?.impactScore)) ? Math.round(Number(snapshot?.impactScore)) : ""}"
fill="${fill}"
style="${introStyle}"/>`;
}

function buildXTicks(points, sliceLength, matchCount) {
  let xTicks = "";

  const visibleMatches = Math.min(matchCount, sliceLength - 1);
  const startGame = matchCount - visibleMatches + 1;

  if (points[0]) {
    xTicks += `
<line x1="${points[0].x}" y1="${PAD_BOTTOM}"
      x2="${points[0].x}" y2="${PAD_BOTTOM + 4}"
      stroke="#64748b" stroke-width="1"/>

<text x="${points[0].x}" y="${PAD_BOTTOM + 24}"
      font-size="18"
      fill="#94a3b8"
      text-anchor="middle">${startGame - 1}</text>
`;
  }

  for (let i = 1; i <= visibleMatches; i++) {

    const p = points[i];
    if (!p) continue;

    const game = startGame + i - 1;

    let showLabel = true;

    if (visibleMatches === 50) {
      showLabel =
        game === matchCount ||
        game === matchCount - 25 ||
        game === matchCount - 50 + 1;
    }

    if (visibleMatches === matchCount) {
      showLabel = game === matchCount;
    }

    if (!showLabel) continue;

    xTicks += `
<line x1="${p.x}" y1="${PAD_BOTTOM}"
      x2="${p.x}" y2="${PAD_BOTTOM + 4}"
      stroke="#64748b" stroke-width="1"/>

<text x="${p.x}" y="${PAD_BOTTOM + 24}"
      font-size="18"
      fill="#94a3b8"
      text-anchor="middle">${game}</text>
`;
  }

  return xTicks;
}

function buildYTicks(minTick, maxTick, y) {
  let yTicks = "";

  for (let i = 0; i <= 4; i++) {
    const val = minTick + ((maxTick - minTick) / 4) * i;
    const yy = y(val);

    yTicks += `
<line x1="${PAD_LEFT}" y1="${yy}"
      x2="${CHART_W - PAD_RIGHT}" y2="${yy}"
      stroke="rgba(148,163,184,0.25)"/>

<text x="${PAD_LEFT - 10}" y="${yy + 4}"
      fill="#94a3b8"
      font-size="18"
      font-weight="600"
      text-anchor="end">${Math.round(val)}</text>
`;
  }

  return yTicks;
}

