function getNextTierRank(rr){
  const current =
    RANK_THRESHOLDS.findIndex(r => rr >= r.min && rr < r.max);

  if(current === -1 || current === RANK_THRESHOLDS.length - 1){
    return RANK_THRESHOLDS[RANK_THRESHOLDS.length - 1];
  }

  return RANK_THRESHOLDS[current + 1];
}

function getTierBoundsByLabel(label){
  if(!label) return null;

  return RANK_THRESHOLDS.find(
    r => r.tierLabel.toLowerCase() === String(label).toLowerCase()
  );
}

