function renderAgentModal(){

  console.log("renderAgentModal", agentGrid);

  if(!agentGrid){
    agentGrid = document.getElementById("agentModalGrid");
  }

  if(!agentGrid) return;
  agentGrid.style.pointerEvents = "auto";

  agentGrid.innerHTML = "";

  allAgents.forEach(agent => {

    if(agentRoles[agent] !== activeRole) return;

    const card = document.createElement("div");
    card.className = "agent-card";

    const key = agent.toLowerCase();

    card.innerHTML = `
      <img src="${getAgentIconUrl(key)}" />
      <span>${agent}</span>
    `;

card.style.cursor = "pointer";
card.style.pointerEvents = "auto";

const img = card.querySelector("img");
if (img) {
  img.style.pointerEvents = "none";
}

    card.setAttribute("data-agent", agent);

    card.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();

      const isLogging = !!document.querySelector("#page-logging.active");

      if(isLogging){
        selectAgentInstant(agent);
      } else {
        selectAgentFromModal(agent);
      }
    });

    agentGrid.appendChild(card);

  });

}

// ========================
// ROLE SELECTOR
// ========================

function renderRoleSelector(){

  const container = document.getElementById("agentRoleSelect");
  if(!container) return;

  container.innerHTML = "";

  const roles = ["duelist","initiator","controller","sentinel"];

  roles.forEach(role => {

    const btn = document.createElement("div");
    btn.className = "agent-role-btn";

    if(role === activeRole){
      btn.classList.add("active");
    }

    const icon = ROLE_ICON_MAP[role];

    btn.innerHTML = icon
      ? `<img src="${icon}" />`
      : `<span>${role}</span>`;

    btn.onclick = () => {

      activeRole = role;
      activeRoleFilter = role;

      renderRoleSelector();
      setTimeout(()=>{ renderRoleSelector(); },0);

      renderAgentModal();

      const agentRoleDropdown = document.getElementById("agentRoleDropdown");
      if(agentRoleDropdown){
        agentRoleDropdown.value = role;
      }

      document.querySelectorAll(".role-filter-btn").forEach(btn => {
        btn.classList.toggle(
          "active",
          btn.dataset.role?.toLowerCase() === role
        );
      });
    };

    container.appendChild(btn);

  });

}

