      "gold 2": "gold_2_rank.png",
      "gold 3": "gold_3_rank.png",
      "platinum 1": "platinum_1_rank.png",
      "platinum 2": "platinum_2_rank.png",
      "platinum 3": "platinum_3_rank.png",
      "diamond 1": "diamond_1_rank.png",
      "diamond 2": "diamond_2_rank.png",
