// ========================
// AGENT SELECTION (SPIN)
// ========================

function selectAgentFromModal(agent){

  const reel = document.getElementById("agentReel");
  const strip = reel?.querySelector(".reel-strip");
  const frame = document.getElementById("agentFrame");

  if(!reel || !strip || !frame) return;

  hideModalById("agentModal");

  reel.classList.remove("reel-placeholder");
  reel.classList.add("reel-spinning");
  frame.classList.add("reel-active");

  if(agentPlaceholder){
    agentPlaceholder.style.display = "none";
  }

  resetPlaceholder();
  runPlaceholderExitAnimation();

  clearAgentFxRuntime();

  frame.classList.remove(
    "duelist","controller","initiator","sentinel",
    "agent-glow-flash","agent-pulse","agent-frame-anim","agent-glow-fadeout"
  );

  strip.innerHTML = "";

  const SPIN_FRAMES = 18;

  for(let i=0;i<SPIN_FRAMES;i++){
    const fake = allAgents[Math.floor(Math.random() * allAgents.length)];

    const img = document.createElement("img");
    img.src = getAgentIconUrl(fake);
    img.className = "reel-icon";

    strip.appendChild(img);
  }

  const finalImg = document.createElement("img");
  finalImg.src = getAgentIconUrl(agent);
  finalImg.className = "reel-icon";

  strip.appendChild(finalImg);

  const frameHeight = syncAgentReelGeometry(reel, strip, frame);
  const finalY = -(frameHeight * SPIN_FRAMES);

  strip.style.transition = "none";
  strip.style.transform = "translateY(0px)";
  void strip.offsetWidth;

  strip.style.transition = `transform ${spinDuration}ms cubic-bezier(.23,1,.32,1)`;
  strip.style.transform = `translateY(${finalY}px)`;

  setTimeout(() => {

    const role = agentRoles[agent];

    if(agentName){
      agentName.textContent = agent;
    }

    // ========================
    // AUTO DEFAULT FOCUS
    // ========================

    if(focusDisplay && (!focusDisplay.textContent || focusDisplay.textContent === "-")){

      const defaultFocusMap = {
        duelist: "Aim",
        initiator: "Utility",
        controller: "Game Sense",
        sentinel: "Positioning"
      };

      const defaultFocus = defaultFocusMap[role];

      if(defaultFocus){
        focusDisplay.textContent = defaultFocus;
        focusDisplay.classList.remove("focus-neutral");

        const logFocusSelect = document.getElementById("logFocusSelect");
        if(logFocusSelect){
          logFocusSelect.value = defaultFocus;
        }
      }
    }

    if(role){

      frame.classList.remove("duelist","controller","initiator","sentinel");
      frame.classList.add(role);

      applyAgentRoleFrame(role);

      agentName?.classList.remove(
        "role-duelist","role-controller","role-initiator","role-sentinel"
      );
      focusDisplay?.classList.remove(
        "role-duelist","role-controller","role-initiator","role-sentinel"
      );

      agentName?.classList.add(`role-${role}`);
      focusDisplay?.classList.add(`role-${role}`);

      const logAgentText = document.getElementById("logAgentText");
      const logFocusSelect = document.getElementById("logFocusSelect");
      const logFocusOther = document.getElementById("logFocusOther");
      const focusPreviewText = document.getElementById("focusPreviewText");

      logAgentText?.classList.remove(
        "role-duelist","role-controller","role-initiator","role-sentinel"
      );
      logFocusSelect?.classList.remove(
        "role-duelist","role-controller","role-initiator","role-sentinel"
      );
      logFocusOther?.classList.remove(
        "role-duelist","role-controller","role-initiator","role-sentinel"
      );
      focusPreviewText?.classList.remove(
        "role-duelist","role-controller","role-initiator","role-sentinel"
      );

      logAgentText?.classList.add(`role-${role}`);
      logFocusSelect?.classList.add(`role-${role}`);
      logFocusOther?.classList.add(`role-${role}`);
      focusPreviewText?.classList.add(`role-${role}`);

      activeRole = role;
      activeRoleFilter = role;

      renderRoleSelector();
      setTimeout(()=>{ renderRoleSelector(); },0);

      renderAgentModal();

      const agentRoleDropdown = document.getElementById("agentRoleDropdown");
      if(agentRoleDropdown){
        agentRoleDropdown.value = role;
      }

      document.querySelectorAll(".role-filter-btn").forEach(btn=>{
        btn.classList.toggle(
          "active",
          btn.dataset.role?.toLowerCase() === role
        );
      });
      updateImpactRolePill({ agent }, null);
    }

    applyAgentFx(agent.toLowerCase());
    applyAgentSilhouette(agent.toLowerCase());
    syncAgentReelGeometry(reel, strip, frame);
    settleReelVisualState(reel);
    strip.style.transition = "none";

    // ========================
    // PRESERVE FOCUS
    // ========================

    const currentFocus =
      document.getElementById("logFocusSelect")?.value === "Other"
        ? document.getElementById("logFocusOther")?.value
        : document.getElementById("logFocusSelect")?.value;

    syncLogInputs();

    if(currentFocus && focusDisplay){
      focusDisplay.textContent = currentFocus;
      focusDisplay.classList.remove("focus-neutral");
    }

    frame.classList.add("agent-glow-flash","agent-pulse","agent-frame-anim");

    // ========================
    // LOGGING ICON SYNC
    // ========================

    activeAgent = agent;
    updateLogAgentDisplay(agent);

    setTimeout(()=>{
      frame.classList.add("agent-glow-fadeout");
    },300);

  }, spinDuration);
  
  // APPLY LAST LOGGED FOCUS IF EXISTS
if(pendingFocusFromLog){
  focusDisplay.textContent = pendingFocusFromLog;
  pendingFocusFromLog = null;
}
  
}

// ========================
// AGENT INSTANT SELECT (LOGGING)
// ========================

function selectAgentInstant(agent){

  if(!agent) return;

  activeAgent = agent;
  // SYNC TO HOME AGENT
applyAgentToHome(agent);

// CLEAR PENDING SYNC FLAGS
pendingAgentFromLog = null;

  activeRole = agentRoles?.[agent] || activeRole || "duelist";

  if(agentName){
    agentName.textContent = agent;
  }

  if(typeof renderRoleSelector === "function"){
    renderRoleSelector();
    setTimeout(()=>{ renderRoleSelector(); },0);
  }

  if (typeof syncLogInputs === "function") {
    syncLogInputs();
  }

  hideModalById("agentModal");
}

function applyAgentToHome(agent){
  if(!agent) return;

  const frame = document.getElementById("agentFrame");
  const nameEl = document.getElementById("agentName");
  const reel = document.getElementById("agentReel");
  const strip = reel?.querySelector(".reel-strip");
  const role = agentRoles?.[agent] || activeRole || "duelist";

  activeAgent = agent;
  activeRole = role;
  activeRoleFilter = role;

  if(agentPlaceholder){
    agentPlaceholder.style.display = "none";
  }

  if(reel){
    reel.classList.remove("reel-placeholder", "reel-spinning");
  }

  if(strip){
    strip.innerHTML = "";
    strip.style.transition = "none";
    strip.style.transform = "translateY(0px)";

    const img = document.createElement("img");
    img.src = getAgentIconUrl(agent);
    img.className = "reel-icon";
    strip.appendChild(img);
    syncAgentReelGeometry(reel, strip, frame);
  }

  if(frame){
    frame.classList.remove("duelist", "controller", "initiator", "sentinel");
    frame.classList.remove("reel-active");
    frame.classList.add("agent-frame", "frame", role, "agent-selected");
  }

  applyAgentFx(agent.toLowerCase());

  if(nameEl){
    nameEl.textContent = agent;
    nameEl.classList.remove(
      "role-duelist","role-controller","role-initiator","role-sentinel"
    );
    nameEl.classList.add(`role-${role}`);
  }

  if(focusDisplay){
    focusDisplay.classList.remove(
      "role-duelist","role-controller","role-initiator","role-sentinel"
    );
    focusDisplay.classList.add(`role-${role}`);
  }

  updateImpactRolePill({ agent }, null);

  applyAgentRoleFrame(role);
  applyAgentFx(agent.toLowerCase());
  applyAgentSilhouette(agent.toLowerCase());
  updateLogAgentDisplay(agent);

}

// =========================
// IMPROVEMENT TIMELINE ENGINE
// =========================

const TIMELINE_POOL = [

{
  key: "winRate",
  label: "Win Rate",
  format: v => `${v}%`,
  tone: v => v >= 52 ? "positive" : v <= 48 ? "negative" : "neutral"
},
{
  key: "kd",
  label: "K/D",
  format: v => Number(v).toFixed(2),
  tone: v => v >= 1.05 ? "positive" : v < 0.95 ? "negative" : "neutral"
},
{
  key: "hs",
  label: "Headshot %",
  format: v => `${v}%`,
  tone: v => v >= 24 ? "positive" : v < 18 ? "negative" : "neutral"
},
{
  key: "adr",
  label: "ADR",
  format: v => `${v}`,
  tone: v => v >= 145 ? "positive" : v < 125 ? "negative" : "neutral"
},
{
  key: "kast",
  label: "KAST",
  format: v => `${v}%`,
  tone: v => v >= 72 ? "positive" : v < 66 ? "negative" : "neutral"
},
{
  key: "firstKills",
  label: "First Kills",
  format: v => `${v}`,
  tone: v => v >= 8 ? "positive" : v < 5 ? "negative" : "neutral"
},
{
  key: "clutch",
  label: "Clutch Rate",
  format: v => `${v}%`,
  tone: v => v >= 18 ? "positive" : v < 10 ? "negative" : "neutral"
},
{
  key: "ecoWins",
  label: "Eco Wins",
  format: v => `${v}`,
  tone: v => v >= 3 ? "positive" : v < 2 ? "negative" : "neutral"
}

];

// ========================
// HELPERS
// ========================

function shuffleArray(arr) {
  const copy = [...arr];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}

function pickUniqueTimelineStats(sourceStats, count = 4) {
  const valid = TIMELINE_POOL.filter(item => sourceStats[item.key] != null);

  return shuffleArray(valid)
    .slice(0, count)
    .map(item => ({
      ...item,
      value: sourceStats[item.key]
    }));
}

function getTimelineToneFromDelta(delta) {
  const value = Number(delta);
  if (!Number.isFinite(value)) return "neutral";
  if (value > 0) return "positive";
  if (value < 0) return "negative";
  return "neutral";
}

function buildTimelineItemsFromModel(model = getPlayerModel()) {
  const improvements = model?.scoring?.recentImprovements || [];
  const mapped = improvements
    .filter(Boolean)
    .map((item, index) => ({
      key: item.key || `improvement_${index}`,
      label: item.label || "Coaching read",
      value: item.value || "--",
      detail: item.detail || "Current scoring-model coaching note.",
      delta: Number(item.delta),
      deltaDisplay: item.deltaDisplay || "",
      comparisonLabel: item.comparisonLabel || "",
      sourceLabel: item.sourceLabel || "",
      formula: item.formula || "",
      tone: () => getTimelineToneFromDelta(item.delta),
      format: value => String(value ?? "--")
    }));

  if (mapped.length) {
    return mapped
      .slice()
      .sort((a, b) => safeNumber(b.delta) - safeNumber(a.delta))
      .slice(0, 4);
  }

  return [
    {
      key: "sample_build",
      label: "Build sample",
      value: "Play 3-5 games",
      detail: "Recent improvement pills unlock once the profile has enough current-window matches.",
      delta: 0,
      tone: () => "neutral",
      format: value => String(value ?? "--")
    }
  ];
}

function getTimelineContext() {
  const latestIndex = matches.length - 1;
  const hasSelection = Number.isInteger(selectedTimelineMatchIndex) && selectedTimelineMatchIndex >= 0;
  const selectedIndex = hasSelection
    ? Math.max(0, Math.min(selectedTimelineMatchIndex, latestIndex))
    : latestIndex;

  if (selectedIndex < 0 || !matches.length) {
    return {
      latestIndex,
      selectedIndex: -1,
      isLatest: true,
      scopeLabel: "Latest",
      scopeDetail: "Latest cumulative sample",
      model: getPlayerModel()
    };
  }

  const scopedMatches = matches.slice(0, selectedIndex + 1);
  const cutoffTime = new Date(getMatchCore(scopedMatches[scopedMatches.length - 1]).createdAt).getTime();
  const scopedLogs = Number.isFinite(cutoffTime)
    ? logEntries.filter(entry => {
        const entryTime = new Date(entry?.createdAt || 0).getTime();
        return !Number.isFinite(entryTime) || entryTime <= cutoffTime;
      })
    : logEntries.slice();
  const importedAnalytics = getActiveProfile()?.trackerAnalytics || null;

  return {
    latestIndex,
    selectedIndex,
    isLatest: selectedIndex === latestIndex,
    scopeLabel: selectedIndex === latestIndex ? "Latest" : `Game ${selectedIndex + 1}`,
    scopeDetail: selectedIndex === latestIndex ? "Latest cumulative sample" : `Game ${selectedIndex + 1} cumulative`,
    model: buildPlayerModel(scopedMatches, scopedLogs, importedAnalytics)
  };
}

function syncImprovementCardSub(scope = getTimelineContext()) {
  const sub = document.getElementById("improvementCardSub");
  if (!sub) return;
  const roleName = String(scope?.model?.scoring?.activeRoleName || "").trim();
  const agentName = String(scope?.model?.scoring?.activeAgentName || "").trim();
  const roleAgentLabel = [roleName, agentName].filter(Boolean).join(" / ");
  sub.textContent = roleAgentLabel
    ? `Recent Improvement | ${scope.scopeDetail} | ${roleAgentLabel}`
    : `Recent Improvement | ${scope.scopeDetail}`;
}

function getTimelineDeltaUnit(item = {}) {
  const value = String(item?.value || "");
  if (value.includes("%")) return "%";
  if (/ACS/i.test(value)) return " ACS";
  return " pts";
}

function formatTimelineDelta(item = {}) {
  if (String(item?.deltaDisplay || "").trim()) {
    return String(item.deltaDisplay).trim();
  }
  const delta = Number(item?.delta);
  if (!Number.isFinite(delta)) return "--";
  if (Math.abs(delta) < 0.05) return "→ even";

  const unit = getTimelineDeltaUnit(item);
  const arrow = delta > 0 ? "↑" : "↓";
  const abs = Math.abs(delta);
  const rounded = Math.abs(abs - Math.round(abs)) < 0.05
    ? String(Math.round(abs))
    : abs.toFixed(1);
  const sign = delta > 0 ? "+" : "-";
  return `${arrow} ${sign}${rounded}${unit}`;
}

function setSelectedTimelineContext(matchIndex = null, { animate = true } = {}) {
  const latestIndex = matches.length - 1;
  const isValidSelection = Number.isInteger(matchIndex) && matchIndex >= 0 && matchIndex < latestIndex;
  selectedTimelineMatchIndex = isValidSelection ? matchIndex : null;
  refreshImprovementTimeline({ animate });
}

function shouldAnimateImprovementTimeline(animate = true) {
  const now = window.performance?.now?.() || Date.now();
  return Boolean(animate) && now >= suppressImprovementTimelineAnimationUntil;
}

function buildTimelineEventsFromModel(model = getPlayerModel()) {
  const snapshots = (model?.scoring?.impactSnapshots || []).slice(-3);
  const weeklyCandidates = (model?.scoring?.weeklyCandidates || []).slice(0, 2);
  const events = [];

  snapshots.forEach((snapshot, index) => {
    const date = new Date(snapshot?.createdAt || Date.now());
    events.push({
      date: Number.isNaN(date.getTime())
        ? "Current Window"
        : date.toLocaleDateString(undefined, { month: "short", day: "numeric" }),
      title: `Game ${safeNumber(snapshot?.matchIndex, index) + 1} | ${snapshot?.impactTier || "Impact"} ${Math.round(safeNumber(snapshot?.impactScore, 0))} on ${snapshot?.map || "Unknown"}`
    });
  });

  weeklyCandidates.forEach(candidate => {
    events.push({
      date: "Focus",
      title: `${candidate?.label || "Weekly focus category"} | ${candidate?.confidence || "Low"} confidence`
    });
  });

  return events.slice(-4);
}

function setTimelinePillVisual(pill, item) {

  const labelEl = pill.querySelector(".timeline-pill-label");
  const valueEl = pill.querySelector(".timeline-pill-value");
  const deltaEl = pill.querySelector(".timeline-pill-delta");

  if (!labelEl || !valueEl || !deltaEl) return;

  labelEl.textContent = item.label;
  valueEl.textContent = item.format(item.value);
  deltaEl.textContent = formatTimelineDelta(item);
  pill.removeAttribute("title");

  pill.classList.remove("is-positive", "is-negative", "is-neutral");
  pill.classList.add(`is-${item.tone(item.value)}`);
}

// ========================
// ANIMATION ENGINE
// ========================

function cycleTimelinePill(pill, options) {

  const {
    finalItem,
    sourceItems,
    spinDuration = 1100,
    tickEvery = 90,
    settleDelay = 0,
    animationVersion = improvementTimelineAnimationVersion
  } = options;

  if (!pill) return Promise.resolve();

  const labelEl = pill.querySelector(".timeline-pill-label");
  const valueEl = pill.querySelector(".timeline-pill-value");
  const deltaEl = pill.querySelector(".timeline-pill-delta");

  if (!labelEl || !valueEl || !deltaEl) return Promise.resolve();

  pill.classList.remove("is-settled", "is-positive", "is-negative", "is-neutral");
  pill.classList.add("is-loading", "is-spinning");

  return new Promise(resolve => {

    const start = performance.now() + settleDelay;
    let lastSwap = 0;
    let rafId = null;

    function frame(now) {
      if (animationVersion !== improvementTimelineAnimationVersion) {
        if (rafId) cancelAnimationFrame(rafId);
        resolve();
        return;
      }

      if (now < start) {
        rafId = requestAnimationFrame(frame);
        return;
      }

      const elapsed = now - start;

      if (elapsed < spinDuration) {

        if (elapsed - lastSwap >= tickEvery) {

          lastSwap = elapsed;

          const temp =
            sourceItems[Math.floor(Math.random() * sourceItems.length)];

          labelEl.textContent = temp.label;
          valueEl.textContent = temp.format(temp.value);
          deltaEl.textContent = formatTimelineDelta(temp);
        }

        rafId = requestAnimationFrame(frame);
        return;
      }

      if (rafId) cancelAnimationFrame(rafId);

      pill.classList.remove("is-loading", "is-spinning");

      setTimelinePillVisual(pill, finalItem);

      pill.classList.remove("is-settled");
      void pill.offsetWidth;
      pill.classList.add("is-settled");

      resolve();
    }

    rafId = requestAnimationFrame(frame);

  });
}

// ========================
// MAIN TIMELINE ANIMATION
// ========================

async function runImprovementTimelineAnimation() {
  const animationVersion = improvementTimelineAnimationVersion;

  const scope = getTimelineContext();
  syncImprovementCardSub(scope);
  const selected = buildTimelineItemsFromModel(scope.model);

  const pills = [
    document.getElementById("timelinePill0"),
    document.getElementById("timelinePill1"),
    document.getElementById("timelinePill2"),
    document.getElementById("timelinePill3")
  ].filter(Boolean);

  if (pills.length !== 4) return;

  const spinPool = selected.length
    ? selected
    : [{
        key: "sample_build",
        label: "Build sample",
        value: "Play 3-5 games",
        detail: "Recent improvement pills unlock once the profile has enough current-window matches.",
        delta: 0,
        comparisonLabel: "Needs more role history before a trustworthy comparison can be made.",
        sourceLabel: "Waiting for Riot match history and/or Logging volume.",
        formula: "No formula yet because the sample is still too small.",
        tone: () => "neutral",
        format: value => String(value ?? "--")
      }];

  pills.forEach((pill, index) => {
    const item = selected[index];
    pill.dataset.timelineKey = item?.key || "";
  });

  await Promise.all(
    pills.map((pill, index) =>
      cycleTimelinePill(pill, {
        finalItem: selected[index] || spinPool[index % spinPool.length],
        sourceItems: spinPool,
        spinDuration: 950 + (index * 180),
        tickEvery: 75,
        settleDelay: index * 160,
        animationVersion
      })
    )
  );

}

