function renderTimeline(){

  const wrap = document.getElementById("timelineEvents");
  if(!wrap) return;

  const scope = getTimelineContext();
  syncImprovementCardSub(scope);
  wrap.innerHTML = "";

  buildTimelineEventsFromModel(scope.model)
    .slice()
    .reverse()
    .forEach((e, index)=>{

      const el = document.createElement("div");
      el.className = `timeline-event event-rank-${Math.min(index, 3)}`;

      el.innerHTML = `
        <div class="timeline-dot"></div>
        <div class="timeline-title">${e.title}</div>
        <div class="timeline-date">${e.date}</div>
      `;

      wrap.appendChild(el);

    });

}

function setTimelinePulloutOpen(isOpen = false) {
  const pullout = document.getElementById("timelinePullout");
  const tab = document.getElementById("timelinePulloutTab");
  if (!pullout || !tab) return;
  pullout.classList.toggle("is-open", !!isOpen);
  tab.setAttribute("aria-expanded", isOpen ? "true" : "false");
}

function refreshImprovementTimeline({ animate = true } = {}) {
  improvementTimelineAnimationVersion += 1;
  renderTimeline();
  if (shouldAnimateImprovementTimeline(animate)) {
    runImprovementTimelineAnimation();
    return;
  }

  const scope = getTimelineContext();
  const items = buildTimelineItemsFromModel(scope.model);
  const pills = [
    document.getElementById("timelinePill0"),
    document.getElementById("timelinePill1"),
    document.getElementById("timelinePill2"),
    document.getElementById("timelinePill3")
  ].filter(Boolean);

  pills.forEach((pill, index) => {
    const item = items[index] || items[0] || null;
    if (!item) return;
    pill.dataset.timelineKey = item.key || "";
    pill.classList.remove("is-loading", "is-spinning", "is-settled");
    setTimelinePillVisual(pill, item);
  });
}

