// ========================
// LOGGING UI STATE
// ========================
let selectedLogRating = null;
let selectedLogMood = null;
let selectedLogTeamComms = null;
let selectedLogSelfComms = null;
let loggingFeedRendered = false;
let loggingFeedDirty = true;
let loggingFeedRenderRaf = 0;

function isLoggingPageActive() {
  return Boolean(document.querySelector("#page-logging.active"));
}

function cancelScheduledLoggingFeedRender() {
  if (loggingFeedRenderRaf) {
    cancelAnimationFrame(loggingFeedRenderRaf);
    loggingFeedRenderRaf = 0;
  }
}

function markLoggingFeedDirty() {
  loggingFeedDirty = true;
}

function scheduleLoggingFeedRender(options = {}) {
  const force = options.force === true;
  if (!force && !isLoggingPageActive()) {
    markLoggingFeedDirty();
    return;
  }

  cancelScheduledLoggingFeedRender();
  loggingFeedRenderRaf = requestAnimationFrame(() => {
    loggingFeedRenderRaf = 0;
    renderLogFeed({ force: true });
  });
}

function isFirstGameOfCurrentSession() {
  const todayKey = new Date().toISOString().slice(0, 10);
  const todaysEntries = (logEntries || []).filter(entry => String(entry?.createdAt || "").slice(0, 10) === todayKey);
  return todaysEntries.length === 0;
}

function updateWarmupQuickChipState() {
  const chip = document.getElementById("logWarmupChip");
  if (!chip) return;
  const enabled = isFirstGameOfCurrentSession();
  chip.disabled = !enabled;
  chip.title = enabled ? "Use this on the first game of the session." : "Warmup is only recorded on the first logged game of the session.";
}

function getLoggingQuickChipButtons() {
  return [...document.querySelectorAll("[data-log-quick]")];
}

function getNormalizedLoggingQuickSnippet(value = "") {
  return String(value || "").trim();
}

function getLoggingNoteLines(value = "") {
  return String(value || "").split(/\r?\n/);
}

function normalizeLoggingNoteLines(lines = []) {
  const normalized = lines.map(line => String(line ?? ""));
  while (normalized.length && !normalized[0].trim()) normalized.shift();
  while (normalized.length && !normalized[normalized.length - 1].trim()) normalized.pop();
  return normalized.filter((line, index, source) => line.trim() || source[index - 1]?.trim());
}

function notesContainLoggingQuickSnippet(value = "", snippet = "") {
  const target = getNormalizedLoggingQuickSnippet(snippet);
  if (!target) return false;
  return getLoggingNoteLines(value).some(line => line.trim() === target);
}

function syncLoggingQuickChipStates() {
  const notesValue = document.getElementById("logNotes")?.value || "";
  let activeCount = 0;

  getLoggingQuickChipButtons().forEach((button) => {
    const snippet = getNormalizedLoggingQuickSnippet(button.dataset.logQuick || "");
    const isActive = notesContainLoggingQuickSnippet(notesValue, snippet);
    button.classList.toggle("active", isActive);
    button.setAttribute("aria-pressed", isActive ? "true" : "false");
    if (isActive) activeCount += 1;
  });

  const countEl = document.getElementById("logQuickCount");
  if (countEl) {
    countEl.hidden = activeCount === 0;
    countEl.textContent = String(activeCount);
  }

  document.getElementById("logQuickToggleBtn")?.classList.toggle("has-active-selections", activeCount > 0);
}

function setLoggingQuickMenuOpen(nextOpen = false, { restoreFocus = false } = {}) {
  const shell = document.getElementById("loggingNotesShell");
  const menu = document.getElementById("logQuickMenu");
  const toggle = document.getElementById("logQuickToggleBtn");
  if (!shell || !menu || !toggle) return;

  const isOpen = Boolean(nextOpen);
  shell.classList.toggle("quick-add-open", isOpen);
  menu.hidden = !isOpen;
  toggle.setAttribute("aria-expanded", isOpen ? "true" : "false");

  if (!isOpen && restoreFocus) {
    toggle.focus();
  }
}

function toggleLoggingQuickSnippet(snippet = "", forceActive = null) {
  const notes = document.getElementById("logNotes");
  const normalizedSnippet = getNormalizedLoggingQuickSnippet(snippet);
  if (!notes || !normalizedSnippet) return;

  const currentLines = getLoggingNoteLines(notes.value);
  const isActive = notesContainLoggingQuickSnippet(notes.value, normalizedSnippet);
  const nextActive = forceActive == null ? !isActive : Boolean(forceActive);
  let nextLines = currentLines;

  if (nextActive) {
    if (!isActive) {
      const appended = normalizeLoggingNoteLines(currentLines);
      appended.push(normalizedSnippet);
      nextLines = appended;
    }
  } else {
    nextLines = normalizeLoggingNoteLines(
      currentLines.filter(line => line.trim() !== normalizedSnippet)
    );
  }

  notes.value = nextLines.join("\n");
  syncLoggingQuickChipStates();
  updateLoggingDebriefPreview();
  notes.focus();
  notes.setSelectionRange(notes.value.length, notes.value.length);
}

function setExclusiveChipSelection(selector, nextValue, datasetKey){
  document.querySelectorAll(selector).forEach(btn => {
    const isActive = String(btn.dataset?.[datasetKey] || "") === String(nextValue ?? "");
    btn.classList.toggle("active", nextValue !== null && nextValue !== undefined && isActive);
  });
}

