// DELETE LOG ENTRY
// ========================

function deleteLogEntry(id){

  logEntries = logEntries.filter(e => e.id !== id);
  saveLogEntries();
  void deletePersistentLogEntry(id);

  renderLogFeed();
  renderInsights();
}

// ========================
// EDIT LOG ENTRY
// ========================

function editLogEntry(id){

  const entry = logEntries.find(e => e.id === id);
  if(!entry) return;

  const focusSelect = document.getElementById("logFocusSelect");
  const focusOther = document.getElementById("logFocusOther");
  const focusOtherWrap = document.getElementById("focusOtherWrap");
  const preview = document.getElementById("focusPreviewText");
  const logMapEl = document.getElementById("logMap");
  const notesEl = document.getElementById("logNotes");

  activeAgent = entry.agent || activeAgent;
  if(entry.agent && agentRoles?.[entry.agent]){
    activeRole = agentRoles[entry.agent];
  }
  updateLogAgentDisplay(entry.agent || "");

  if(focusSelect){

    const exists = [...focusSelect.options]
      .some(opt => opt.value === entry.focus);

    if(exists){
      focusSelect.value = entry.focus;
      setFocusOtherVisibility(false);
      if(preview) preview.textContent = entry.focus || "Focus";
      setCustomFocusCommitted("");
    } else {
      focusSelect.value = "Other";
      if(focusOther) focusOther.value = entry.focus;
      setFocusOtherVisibility(true, entry.focus);
      setCustomFocusCommitted(entry.focus);
    }

  }

  if(logMapEl) logMapEl.value = entry.map || "";
  if(notesEl) notesEl.value = entry.notes;

  selectedLogRating = Number.isFinite(Number(entry.rating)) ? Number(entry.rating) : null;
  selectedLogMood = entry.mood || null;
  selectedLogTeamComms = Number.isFinite(Number(entry.teamComms)) ? Number(entry.teamComms) : null;
  selectedLogSelfComms = Number.isFinite(Number(entry.selfComms)) ? Number(entry.selfComms) : null;

  setExclusiveChipSelection("[data-rating]", selectedLogRating, "rating");
  setExclusiveChipSelection("[data-mood]", selectedLogMood, "mood");
  setExclusiveChipSelection("[data-team-comms]", selectedLogTeamComms, "teamComms");
  setExclusiveChipSelection("[data-self-comms]", selectedLogSelfComms, "selfComms");
  setLoggingQuickMenuOpen(false);
  syncLoggingQuickChipStates();
  updateLoggingDebriefPreview();

  deleteLogEntry(id);
}

// ========================
// SYNC LOG INPUTS
// ========================

function syncLogInputs(){

  const focusSelect = document.getElementById("logFocusSelect");
  const focusOther = document.getElementById("logFocusOther");
  const focusOtherWrap = document.getElementById("focusOtherWrap");

  if(!focusSelect || !focusOther) return;

  if(pendingFocusFromLog){

    const exists = [...focusSelect.options]
      .some(opt => opt.value === pendingFocusFromLog);

    if(exists){
      focusSelect.value = pendingFocusFromLog;
      setFocusOtherVisibility(false);
      setCustomFocusCommitted("");
    } else {
      focusSelect.value = "Other";
      focusOther.value = pendingFocusFromLog;
      setFocusOtherVisibility(true, pendingFocusFromLog);
      setCustomFocusCommitted(pendingFocusFromLog);
    }

    pendingFocusFromLog = null;
  }

  if(pendingAgentFromLog){
    applyAgentToHome(pendingAgentFromLog);
    pendingAgentFromLog = null;
  }

}

function getLogRatingBadge(rating){
  const score = Number(rating || 0);

  if(score >= 5){
    return { icon: "⭐", label: String(score || 5), tone: "good" };
  }

  if(score >= 3){
    return { icon: "◐", label: String(score), tone: "okay" };
  }

  return { icon: "✕", label: String(score || "-"), tone: "bad" };
}

function getMoodTone(mood){
  const key = String(mood || "").toLowerCase();

  if(key === "tilted") return "bad";
  if(key === "focused") return "good";
  if(key === "calm") return "calm";
  return "neutral";
}

function getLogSessions() {
  const grouped = new Map();

  (logEntries || []).forEach(entry => {
    const key = String(entry.createdAt || nowISO()).slice(0, 10);
    if (!grouped.has(key)) {
      grouped.set(key, []);
    }
    grouped.get(key).push(entry);
  });

  return [...grouped.entries()]
    .map(([key, entries]) => ({ key, entries }))
    .sort((a, b) => new Date(b.key) - new Date(a.key));
}

function renderLogSessionSelector() {
  const select = document.getElementById("logSessionSelect");
  if (!select) return;

  const sessions = getLogSessions();
  select.innerHTML = `<option value="all">All Sessions</option>`;

  sessions.forEach((session, index) => {
    const option = document.createElement("option");
    option.value = session.key;
    option.textContent = index === 0
      ? `Today / Latest | ${formatDateLabel(session.key)}`
      : formatDateLabel(session.key);
    select.appendChild(option);
  });

  if (!sessions.some(session => session.key === activeLogSessionFilter)) {
    activeLogSessionFilter = "all";
  }

  select.value = activeLogSessionFilter;
  select.onchange = () => {
    activeLogSessionFilter = select.value || "all";
    renderLogFeed();
  };
}

function buildDemoLogEntriesFromMatches(matchList = []) {
  const focusOptions = [
    "Trade Conversion",
    "Crosshair Discipline",
    "Spacing",
    "Eco Conversion",
    "Mid Round Discipline",
    "Comms Discipline",
    "Retake Timing",
    "Utility Efficiency"
  ];
  const scenarioNotes = [
    "AFK teammate on defense led to two free site hits and a broken bonus conversion.",
    "Enemy disconnect mid-half created easier spacing windows but masked weak retake structure.",
    "Played with music on and team comms muted. Missed one rotate call that turned a 4v3 post-plant into a loss.",
    "Queued with a duo and had cleaner trade spacing on entry rounds, especially on low-buy fights.",
    "Solo queue with voice disabled made late-round info thin and produced slower rotate timing.",
    "Won eco rounds when staying close enough to trade instead of dry swinging after utility.",
    "Lost a key round after overbuying utility and entering without rifle support.",
    "First death kept happening in the same lane when peeking before utility landed."
  ];

  return (matchList || []).map((match, index) => {
    const createdAt = match?.createdAt || match?.metadata?.playedAt || nowISO();
    const result = String(match?.result || match?.metadata?.result || "draw").toLowerCase();
    const demoRoundData = match?.advanced?.rounds || [];
    const role = agentRoles?.[match?.metadata?.agent] || activeRole || "";
    const roleBase = {
      duelist: { rolePlan: 74, utility: 69, entry: 76, spacing: 71 },
      initiator: { rolePlan: 77, utility: 81, entry: 70, spacing: 75 },
      controller: { rolePlan: 79, utility: 84, entry: 68, spacing: 78 },
      sentinel: { rolePlan: 81, utility: 79, entry: 66, spacing: 80 }
    }[String(role || "").toLowerCase()] || { rolePlan: 74, utility: 74, entry: 72, spacing: 72 };
    const resultBoost = result === "win" ? 8 : result === "loss" ? -6 : 2;

    return {
      id: uuid(),
      createdAt,
      agent: match?.metadata?.agent || "Jett",
      focus: focusOptions[index % focusOptions.length],
      map: match?.metadata?.mapName || "Unknown",
      rating: result === "win" ? 5 - (index % 2) : result === "loss" ? 2 + (index % 2) : 3,
      mood: result === "win" ? "Focused" : result === "loss" ? "Tilted" : "Calm",
      teamComms: result === "win" ? 4 + (index % 2) : result === "loss" ? 2 + (index % 2) : 3,
      selfComms: result === "win" ? 4 : result === "loss" ? 2 + (index % 2) : 3,
      warmup: index === 0,
      notes: `${scenarioNotes[index % scenarioNotes.length]} ${result === "win"
        ? "Won more rounds when respecting teammate spacing and delaying peeks until utility connected."
        : "Losses stacked when first deaths came early and the round economy snowballed poorly."}`,
      role,
      musicOn: index % 3 === 0,
      commsDisabled: index % 4 === 0,
      duoQueued: index % 2 === 0,
      afkMention: index % 5 === 0,
      disconnectMention: index % 4 === 1,
      rolePlanScore: clampScore(roleBase.rolePlan + resultBoost + ((index % 3) - 1) * 2, 40, 100),
      utilityTimingScore: clampScore(roleBase.utility + resultBoost + ((index % 4) - 1.5) * 2, 40, 100),
      entryTimingScore: clampScore(roleBase.entry + resultBoost + ((index % 5) - 2) * 2, 40, 100),
      spacingScore: clampScore(roleBase.spacing + resultBoost + ((index % 4) - 1.5) * 2, 40, 100),
      roundExamples: demoRoundData
    };
  });
}

// ========================
// LOG FEED RENDER
// ========================

function renderLogFeed(options = {}){

  const container = document.getElementById("logFeed");
  if(!container) return;

  const force = options.force === true;
  if (!force && !isLoggingPageActive()) {
    markLoggingFeedDirty();
    return;
  }

  renderLogSessionSelector();
  updateWarmupQuickChipState();
  container.innerHTML = "";
  loggingFeedDirty = false;
  loggingFeedRendered = true;

  if(!logEntries.length){
    container.innerHTML = `
      <div class="log-empty">
        No logs yet -- track your sessions to unlock insights
      </div>
    `;
    return;
  }

  const sessions = getLogSessions().filter(session =>
    activeLogSessionFilter === "all" || session.key === activeLogSessionFilter
  );

  const fragment = document.createDocumentFragment();
  sessions.forEach(session => {
    const sessionWrap = document.createElement("div");
    sessionWrap.className = "log-session-group";
    sessionWrap.innerHTML = `
      <div class="log-session-heading">
        <span class="log-session-date">${formatDateLabel(session.key)}</span>
        <span class="log-session-count">${session.entries.length} game${session.entries.length === 1 ? "" : "s"}</span>
      </div>
    `;

    session.entries.forEach(entry => {

      const ratingBadge = getLogRatingBadge(entry.rating);
      const moodLabel = entry.mood || entry.tilt || "-";
      const moodTone = getMoodTone(moodLabel);
      const el = document.createElement("div");
      el.className = "log-entry";

      el.innerHTML = `
        <div class="log-header">
          <span class="log-meta-agent">${
            entry.agent
              ? `<img src="${getAgentIconUrl(entry.agent)}" alt="${entry.agent}">`
              : "?"
          }</span>
          <span class="log-rating">⭐ ${entry.rating}</span>
        </div>

        <div class="log-body">
          <div class="log-meta">
            <span class="log-meta-agent">${
              entry.agent
                ? `<img src="${getAgentIconUrl(entry.agent)}" alt="${entry.agent}">`
                : "?"
            }</span>
            <span>${entry.role || "-"}</span>
            <span>Tilt: ${entry.tilt}</span>
          </div>

          <div class="log-notes">
            ${entry.notes || ""}
          </div>
        </div>

        <div class="log-actions">
          <button class="log-edit-btn">Edit</button>
          <button class="log-delete-btn">Delete</button>
        </div>
      `;

      const headerRating = el.querySelector(".log-header .log-rating");
      if(headerRating){
        headerRating.style.display = "none";
      }

      const meta = el.querySelector(".log-meta");
      if(meta){
        meta.innerHTML = `
          <div class="log-tier-row">
            <span class="log-tier-label">Focus Category</span>
            <span class="log-tier-value">${entry.focus || "-"}</span>
          </div>
          <div class="log-tier-row">
            <span class="log-tier-label">Map</span>
            <span class="log-tier-value">${entry.map || "-"}</span>
          </div>
          <div class="log-tier-row">
            <span class="log-tier-label">Self Rating</span>
            <span class="log-tier-value log-rating log-rating-${ratingBadge.tone}">${entry.rating || "-"}</span>
          </div>
          <div class="log-tier-row">
            <span class="log-tier-label">Mood</span>
            <span class="log-tier-value log-mood log-mood-${moodTone}">${moodLabel}</span>
          </div>
          <div class="log-tier-row">
            <span class="log-tier-label">Team Comms</span>
            <span class="log-tier-value">${entry.teamComms || "-"}</span>
          </div>
          <div class="log-tier-row">
            <span class="log-tier-label">Self Comms</span>
            <span class="log-tier-value">${entry.selfComms || "-"}</span>
          </div>
          <div class="log-tier-row">
            <span class="log-tier-label">Warmup</span>
            <span class="log-tier-value">${entry.warmup ? "Yes" : "No"}</span>
          </div>
        `;
      }

      const notes = el.querySelector(".log-notes");
      if(notes){
        notes.outerHTML = `
          <div class="log-tier-row log-tier-notes">
            <span class="log-tier-label">Notes</span>
            <div class="log-notes">${entry.notes || ""}</div>
          </div>
        `;
      }

      const editBtn = el.querySelector(".log-edit-btn");
      const deleteBtn = el.querySelector(".log-delete-btn");

      editBtn?.addEventListener("click", () => editLogEntry(entry.id));
      deleteBtn?.addEventListener("click", () => deleteLogEntry(entry.id));

      sessionWrap.appendChild(el);

    });

    fragment.appendChild(sessionWrap);
  });

  container.appendChild(fragment);

}

