function saveProfiles(){

  localStorage.setItem(
    STORAGE_KEY_PROFILES,
    JSON.stringify(profiles)
  );

  localStorage.setItem(
    STORAGE_KEY_ACTIVE_ID,
    activeProfileId
  );

  queuePersistentAccountSave("profiles");
}

