function getDefaultProfileAvatarAgent() {
  return "jett";
}

function getDefaultProfileAvatarUrl(agentName = getDefaultProfileAvatarAgent()) {
  return getAgentIconUrl(String(agentName || "jett").toLowerCase());
}

function normalizeAccessibilityLayoutMode(value) {
  return value === "mobile" ? "mobile" : "web";
}

function normalizeProfileRecord(profile = {}) {
  const avatarAgent = String(profile.avatarAgent || "").trim() || getDefaultProfileAvatarAgent();
  return {
    ...profile,
    name: profile.name || "Main",
    riotId: profile.riotId || "",
    region: profile.region || "NA",
    startingRR: safeNumber(profile.startingRR),
    startingRRDate: String(profile.startingRRDate || ""),
    startingRRSource: String(profile.startingRRSource || ""),
    goalRank: profile.goalRank || null,
    matches: Array.isArray(profile.matches) ? profile.matches : [],
    themeKey: profile.themeKey || "default",
    frameTheme: profile.frameTheme || profile.themeKey || "default",
    avatarAgent,
    avatarUrl: profile.avatarUrl || getDefaultProfileAvatarUrl(avatarAgent),
    navBackgroundUrl: profile.navBackgroundUrl || "",
    profileBorder: normalizeProfileBorderStyle(profile.profileBorder || "standard"),
    bannerStyle: normalizeProfileBannerStyle(profile.bannerStyle || "theme"),
    accessibility: {
      contrastMode: profile?.accessibility?.contrastMode || "standard",
      motionMode: profile?.accessibility?.motionMode || "standard",
      layoutMode: normalizeAccessibilityLayoutMode(profile?.accessibility?.layoutMode)
    }
  };
}

function loadProfiles(){

  try{
    const raw = localStorage.getItem(STORAGE_KEY_PROFILES);
    profiles = raw ? JSON.parse(raw) : [];
  }catch(e){
    profiles = [];
  }

  profiles = (profiles || []).map(normalizeProfileRecord);
  logEntries = readLocalLogEntries();

  activeProfileId =
    localStorage.getItem(STORAGE_KEY_ACTIVE_ID);

  if (profiles.length && !profiles.some(profile => profile.id === activeProfileId)) {
    activeProfileId = profiles[0].id;
  }

  if(!profiles.length){

    const defaultProfile = {
      id: uuid(),
      name: "Main",
      riotId: "",
      region: "NA",
      startingRR: 0,
      startingRRDate: "",
      startingRRSource: "",
      themeKey: "default",
      frameTheme: "default",
      avatarAgent: getDefaultProfileAvatarAgent(),
      avatarUrl: getDefaultProfileAvatarUrl(),
      navBackgroundUrl: "",
      profileBorder: "standard",
      bannerStyle: "theme",
      accessibility: {
        contrastMode: "standard",
        motionMode: "standard",
        layoutMode: "web"
      }
    };

    profiles.push(normalizeProfileRecord(defaultProfile));
    activeProfileId = defaultProfile.id;

    saveProfiles();
  }

}

// ========================
// GET ACTIVE PROFILE
// ========================

function getActiveProfile(){

  return profiles.find(p => p.id === activeProfileId) || null;

}

// ========================
// CREATE PROFILE
// ========================

function createProfile(data){

  const profile = normalizeProfileRecord({
    id: uuid(),
    name: data.name || "New Profile",
    riotId: data.riotId || "",
    region: data.region || "NA",
    startingRR: 0,
    startingRRDate: "",
    startingRRSource: "",
    themeKey: data.themeKey || "default",
    frameTheme: data.frameTheme || data.themeKey || "default",
    avatarAgent: data.avatarAgent || getDefaultProfileAvatarAgent(),
    avatarUrl: data.avatarUrl || getDefaultProfileAvatarUrl(data.avatarAgent),
    navBackgroundUrl: data.navBackgroundUrl || "",
    profileBorder: normalizeProfileBorderStyle(data.profileBorder || "standard"),
    bannerStyle: normalizeProfileBannerStyle(data.bannerStyle || "theme"),
    accessibility: {
      contrastMode: data?.accessibility?.contrastMode || "standard",
      motionMode: data?.accessibility?.motionMode || "standard",
      layoutMode: normalizeAccessibilityLayoutMode(data?.accessibility?.layoutMode)
    }
  });

  profiles.push(profile);

  activeProfileId = profile.id;

  saveProfiles();
  renderProfilesUI();

}

// ========================
// DELETE PROFILE
// ========================

function deleteProfile(id){

  profiles = profiles.filter(p => p.id !== id);

  if(activeProfileId === id){
    activeProfileId = profiles[0]?.id || null;
  }

  saveProfiles();
  renderProfilesUI();

}

// ========================
// UPDATE PROFILE
// ========================

function updateProfile(id, data){

  const profile = profiles.find(p => p.id === id);
  if(!profile) return;

  const previousRiotId = String(profile.riotId || "").trim().toLowerCase();
  const nextRiotId = data.riotId != null
    ? String(data.riotId || "").trim().toLowerCase()
    : previousRiotId;
  const previousRegion = String(profile.region || "").trim().toUpperCase();
  const nextRegion = data.region != null
    ? String(data.region || "").trim().toUpperCase()
    : previousRegion;

  profile.name = data.name ?? profile.name;
  profile.riotId = data.riotId ?? profile.riotId;
  profile.region = data.region ?? profile.region;

  if (nextRiotId !== previousRiotId || nextRegion !== previousRegion) {
    profile.startingRRDate = "";
    profile.startingRRSource = "";
  }

  if (data.themeKey != null || data.frameTheme != null) {
    const nextTheme = String(data.themeKey || data.frameTheme || "default");
    profile.themeKey = nextTheme;
    profile.frameTheme = nextTheme;
  }

  if (data.avatarAgent != null) {
    profile.avatarAgent = String(data.avatarAgent || getDefaultProfileAvatarAgent()).toLowerCase();
    profile.avatarUrl = getDefaultProfileAvatarUrl(profile.avatarAgent);
  }

  if (data.navBackgroundUrl != null) {
    profile.navBackgroundUrl = String(data.navBackgroundUrl || "").trim();
  }

  if (data.profileBorder != null) {
    profile.profileBorder = normalizeProfileBorderStyle(data.profileBorder || "standard");
  }

  if (data.bannerStyle != null) {
    profile.bannerStyle = normalizeProfileBannerStyle(data.bannerStyle || "theme");
  }

  if (data.accessibility != null) {
    profile.accessibility = {
      contrastMode: data?.accessibility?.contrastMode || profile?.accessibility?.contrastMode || "standard",
      motionMode: data?.accessibility?.motionMode || profile?.accessibility?.motionMode || "standard",
      layoutMode: normalizeAccessibilityLayoutMode(data?.accessibility?.layoutMode || profile?.accessibility?.layoutMode)
    };
  }

  saveProfiles();
  renderProfilesUI();
  updateProfileHeaderUI();
  initStatsPage();
  scheduleRiotAutoSync();

}

// ========================
// SET ACTIVE PROFILE
// ========================

function setActiveProfile(id){

  const current = getActiveProfile();

  // save current matches
  if(current){
    current.matches = matches.slice();
  }

  activeProfileId = id;

  const next = getActiveProfile();

  // restore matches
  matches = next?.matches ? next.matches.slice() : [];

  recomputeFromMatches();

  saveProfiles();

  renderProfilesUI();
  updateProfileHeaderUI();
  updateDisplays();

  renderChart(currentSize);
  renderInsights?.();
  scheduleRiotAutoSync();

}

// ========================
// PROFILE ACTIONS (MANUAL)
// ========================

function handleAddProfile() {

  const name = prompt(
    "New profile name:",
    "Alt Account"
  );

  if (!name) return;

  const riotId =
    prompt(
      "Riot ID (Name#TAG):",
      "RiotID#TAG"
    ) || "RiotID#TAG";

  const region =
    prompt(
      "Region (e.g. NA, EU):",
      "NA"
    ) || "NA";

  const newProfile = {

    id: "p_" + Date.now(),
    name,
    riotId,
    region,

    startingRR: 0,
    themeKey: "default",
    frameTheme: "default",
    avatarAgent: getDefaultProfileAvatarAgent(),
    avatarUrl: getDefaultProfileAvatarUrl(),
    navBackgroundUrl: "",
    profileBorder: "standard",
    bannerStyle: "theme",
    accessibility: {
      contrastMode: "standard",
      motionMode: "standard",
      layoutMode: "web"
    },
    goalRank: null,
    matches: []
  };

  profiles.push(normalizeProfileRecord(newProfile));

  saveProfiles();

  setActiveProfile(newProfile.id);
}

function hardResetAllData(){

  const confirmReset = confirm(
    "This will delete ALL stored profiles and match history.\n\nContinue?"
  );

  if(!confirmReset) return;

  localStorage.removeItem(STORAGE_KEY_PROFILES);
  localStorage.removeItem(STORAGE_KEY_ACTIVE_ID);
  localStorage.removeItem(STORAGE_KEY_LOG_ENTRIES);

  location.reload();
}

// ========================
// PROFILES UI
// ========================

function renderProfilesUI(){

  if(!profileListEl) return;

  profileListEl.innerHTML = "";

  profiles.forEach(profile => {

    const row = document.createElement("div");
    row.className = "profile-row";

    if(profile.id === activeProfileId){
      row.classList.add("active");
    }

    row.innerHTML = `
      <div class="profile-info">
        <div class="profile-name">${profile.name}</div>
        <div class="profile-sub">
          ${profile.riotId || "No Riot ID"} | ${profile.region}
        </div>
      </div>

      <div class="profile-actions">
        <button class="profile-select-btn">Select</button>
        <button class="profile-delete-btn">✕</button>
      </div>
    `;

    const selectBtn = row.querySelector(".profile-select-btn");
    const deleteBtn = row.querySelector(".profile-delete-btn");

    selectBtn?.addEventListener("click", ()=>{
      setActiveProfile(profile.id);
      closeProfileDropdown();
    });

    deleteBtn?.addEventListener("click", ()=>{
      deleteProfile(profile.id);
    });

    profileListEl.appendChild(row);

  });

  const active = getActiveProfile();

  if(profileProfileNameEl){
    profileProfileNameEl.textContent = active?.name || "-";
  }

  if(profileRiotIdEl){
    profileRiotIdEl.textContent = active?.riotId || "Not set";
  }

  if(profileRegionEl){
    profileRegionEl.textContent = active?.region || "-";
  }

  if(profileStartingRREl){
    profileStartingRREl.textContent =
      safeNumber(active?.startingRR);
  }

}

function closeProfileDropdown(){
  if(!profileDropdown) return;
  profileDropdown.classList.remove("open");
}

function computePeakProfileProgress(profile = getActiveProfile()) {
  const start = safeNumber(profile?.startingRR);
  const matchList = Array.isArray(profile?.matches) ? profile.matches : [];
  let running = start;
  let peak = start;

  matchList.forEach((match) => {
    running += safeNumber(match?.rr);
    if (running > peak) peak = running;
  });

  const tier = getTierRank(peak) || getTierRank(start);
  return {
    peakRR: peak,
    tierLabel: tier?.tierLabel || "Iron 1",
    rankIconUrl: getRankIconUrl(tier?.tierLabel || "Iron 1"),
    gainFromStart: peak - start
  };
}

function getThemePreset(themeKey = "default") {
  const resolvedThemeKey = String(themeKey || "default").toLowerCase() === "reaver"
    ? "default"
    : themeKey;
  return PROFILE_THEME_PRESETS.find(theme => theme.value === resolvedThemeKey) || PROFILE_THEME_PRESETS[0];
}

function getProfileBorderStyle(borderStyle = "standard") {
  return PROFILE_BORDER_STYLES.find(style => style.value === String(borderStyle || "standard")) || PROFILE_BORDER_STYLES[0];
}

function normalizeProfileBorderStyle(borderStyle = "standard") {
  return getProfileBorderStyle(borderStyle).value;
}

function getProfileBannerStyle(bannerStyle = "theme") {
  return PROFILE_BANNER_STYLES.find(style => style.value === String(bannerStyle || "theme")) || PROFILE_BANNER_STYLES[0];
}

function normalizeProfileBannerStyle(bannerStyle = "theme") {
  return getProfileBannerStyle(bannerStyle).value;
}

function getBannerImageUrl(bannerStyle = "theme") {
  return getProfileBannerStyle(bannerStyle)?.image || "";
}

function toCssUrl(url = "") {
  const cleanUrl = String(url || "").trim().replace(/\\/g, "\\\\").replace(/"/g, '\\"');
  return cleanUrl ? `url("${cleanUrl}")` : "none";
}

function getBannerPattern(bannerStyle = "theme", theme = getThemePreset()) {
  const banner = getProfileBannerStyle(bannerStyle);
  if (banner?.image) return "none";

  const accent = theme?.colors?.accent || "#ff4655";
  const accent2 = theme?.colors?.accent2 || "#f97316";
  const soft = theme?.colors?.text || "#ffffff";
  const presets = {
    theme: theme?.colors?.pattern2 || "none",
    default: `radial-gradient(circle at 18% 18%, ${soft}18, transparent 20%), linear-gradient(120deg, ${accent}16, transparent 38%, ${accent2}14 72%, transparent 100%)`
  };
  return presets[bannerStyle] || presets.theme;
}

function renderThemeGallery(selectedThemeKey = "default") {
  const gallery = document.getElementById("editProfileThemeGallery");
  const themeSelect = document.getElementById("editProfileTheme");
  if (!gallery) return;

  gallery.innerHTML = PROFILE_THEME_PRESETS.map((theme) => {
    const colors = theme?.colors || {};
    const isActive = String(theme.value) === String(selectedThemeKey);
    return `
      <button
        type="button"
        class="theme-card ${isActive ? "is-active" : ""}"
        data-theme-card="${escapeHtml(theme.value)}"
        aria-pressed="${isActive ? "true" : "false"}">
        <div
          class="theme-card-preview"
          style="
            --theme-card-text:${colors.text || "#f8fafc"};
            --theme-card-border:${colors.borderStrong || colors.border || "rgba(255,255,255,.14)"};
            --theme-card-surface:${colors.card || "#0b1220"};
            --theme-card-surface-2:${colors.card2 || "#0f172a"};
            --theme-card-pattern:${colors.pattern || "none"};
            --theme-card-pattern-2:${colors.pattern2 || "none"};
            background:linear-gradient(180deg, ${colors.base || "#071029"}, ${colors.base2 || "#071b2b"});
          ">
          <div class="theme-card-surfaces">
            <div class="theme-card-pills">
              <span class="theme-card-pill" style="background:${colors.accent || "#ff4655"}"></span>
              <span class="theme-card-pill" style="background:${colors.accent2 || "#f97316"}"></span>
            </div>
          </div>
        </div>
      </button>
    `;
  }).join("");

  gallery.querySelectorAll("[data-theme-card]").forEach((button) => {
    button.addEventListener("click", () => {
      const nextTheme = button.getAttribute("data-theme-card") || "default";
      if (themeSelect) themeSelect.value = nextTheme;
      renderThemeGallery(nextTheme);
      previewEditProfileVisuals();
    });
  });
}

function renderAvatarGallery(selectedAgent = getDefaultProfileAvatarAgent()) {
  const gallery = document.getElementById("editProfileAvatarGallery");
  const avatarSelect = document.getElementById("editProfileAvatarAgent");
  if (!gallery) return;

  gallery.innerHTML = allAgents.map((agent) => {
    const key = String(agent || "").toLowerCase();
    const isActive = key === String(selectedAgent || "").toLowerCase();
    return `
      <button type="button" class="avatar-card ${isActive ? "is-active" : ""}" data-avatar-card="${escapeHtml(key)}" aria-pressed="${isActive ? "true" : "false"}">
        <div class="avatar-card-shell">
          <div class="avatar-card-ring">
            <img class="avatar-card-img" src="${escapeHtml(getAgentIconUrl(key))}" alt="${escapeHtml(agent)} icon">
          </div>
          <div class="avatar-card-name">${escapeHtml(agent)}</div>
        </div>
      </button>
    `;
  }).join("");

  gallery.querySelectorAll("[data-avatar-card]").forEach((button) => {
    button.addEventListener("click", () => {
      const nextAgent = button.getAttribute("data-avatar-card") || getDefaultProfileAvatarAgent();
      if (avatarSelect) avatarSelect.value = nextAgent;
      renderAvatarGallery(nextAgent);
      previewEditProfileVisuals();
    });
  });
}

function renderBorderGallery(selectedBorder = "standard") {
  const gallery = document.getElementById("editProfileBorderGallery");
  const borderSelect = document.getElementById("editProfileBorderStyle");
  if (!gallery) return;

  const profile = getActiveProfile();
  const selectedThemeKey = document.getElementById("editProfileTheme")?.value || profile?.themeKey || "default";
  const selectedAgent = document.getElementById("editProfileAvatarAgent")?.value || profile?.avatarAgent || getDefaultProfileAvatarAgent();
  const theme = getThemePreset(selectedThemeKey);
  const colors = theme?.colors || {};
  const avatarUrl = getDefaultProfileAvatarUrl(selectedAgent);
  const activeBorder = normalizeProfileBorderStyle(selectedBorder);

  gallery.innerHTML = PROFILE_BORDER_STYLES.map((style) => {
    const isActive = style.value === activeBorder;
    return `
      <button type="button" class="border-card border-card-${escapeHtml(style.value)} ${isActive ? "is-active" : ""}" data-border-card="${escapeHtml(style.value)}" aria-pressed="${isActive ? "true" : "false"}">
        <div
          class="border-card-preview"
          style="
            --border-card-accent:${colors.accent || "#ff4655"};
            --border-card-accent-2:${colors.accent2 || "#f97316"};
            --border-card-text:${colors.text || "#f8fafc"};
            --border-card-muted:${colors.muted || "#94a3b8"};
            --border-card-surface:${colors.card || "#0b1220"};
            --border-card-surface-2:${colors.card2 || "#0f172a"};
            --border-card-glow:${colors.glow || "rgba(255,70,85,.22)"};
          ">
          <div class="border-card-avatar">
            <img src="${escapeHtml(avatarUrl)}" alt="${escapeHtml(style.label)} border preview">
          </div>
          <div class="border-card-copy">
            <div class="border-card-name">${escapeHtml(style.label)}</div>
            <div class="border-card-note">${escapeHtml(style.note || "Profile ring")}</div>
          </div>
        </div>
      </button>
    `;
  }).join("");

  gallery.querySelectorAll("[data-border-card]").forEach((button) => {
    button.addEventListener("click", () => {
      const nextBorder = normalizeProfileBorderStyle(button.getAttribute("data-border-card") || "standard");
      if (borderSelect) borderSelect.value = nextBorder;
      renderBorderGallery(nextBorder);
      previewEditProfileVisuals();
    });
  });
}

function renderBannerGallery(selectedBanner = "theme", themeKey = "default") {
  const gallery = document.getElementById("editProfileBannerGallery");
  const bannerSelect = document.getElementById("editProfileBannerStyle");
  if (!gallery) return;

  const theme = getThemePreset(themeKey);
  const colors = theme?.colors || {};
  const activeBanner = normalizeProfileBannerStyle(selectedBanner);

  gallery.innerHTML = PROFILE_BANNER_STYLES.map((style) => {
    const isActive = String(style.value) === activeBanner;
    const pattern = getBannerPattern(style.value, theme);
    const previewBackground = style.image
      ? `linear-gradient(90deg, rgba(2,6,23,.34), rgba(2,6,23,.08) 52%, rgba(2,6,23,.44)), url('${escapeHtml(style.image)}') center / cover no-repeat`
      : `linear-gradient(180deg, ${colors.nav || colors.base || "#071029"}, ${colors.card || "#0b1220"})`;
    return `
      <button type="button" class="banner-card ${isActive ? "is-active" : ""}" data-banner-card="${escapeHtml(style.value)}" aria-pressed="${isActive ? "true" : "false"}">
        <div
          class="banner-card-preview"
          style="
            --banner-card-text:${colors.text || "#f8fafc"};
            --banner-card-accent:${colors.accent || "#ff4655"};
            --banner-card-pattern:${pattern};
            background:${previewBackground};
          ">
          <div class="banner-card-name">${escapeHtml(style.label)}</div>
          <div class="banner-card-strip">${style.image ? "Player Card" : "Theme Default"}</div>
        </div>
      </button>
    `;
  }).join("");

  gallery.querySelectorAll("[data-banner-card]").forEach((button) => {
    button.addEventListener("click", () => {
      const nextBanner = normalizeProfileBannerStyle(button.getAttribute("data-banner-card") || "theme");
      if (bannerSelect) bannerSelect.value = nextBanner;
      renderBannerGallery(nextBanner, document.getElementById("editProfileTheme")?.value || themeKey);
      previewEditProfileVisuals();
    });
  });
}

function applyProfileVisuals(profile = getActiveProfile()) {
  const avatarImg = document.getElementById("profileAvatarImg");
  const rankIcon = document.getElementById("profileRankIcon");
  const header = document.querySelector(".app-header");
  const panel = document.getElementById("profilePanel");
  const ring = document.querySelector(".profile-avatar-ring");
  const peak = computePeakProfileProgress(profile);
  const avatarUrl = profile?.avatarUrl || getDefaultProfileAvatarUrl(profile?.avatarAgent);
  const requestedThemeKey = String(profile?.themeKey || profile?.frameTheme || "default").toLowerCase();
  const themeKey = requestedThemeKey === "reaver" ? "default" : requestedThemeKey;
  const theme = getThemePreset(themeKey);
  const borderStyle = normalizeProfileBorderStyle(profile?.profileBorder || "standard");
  const bannerStyle = normalizeProfileBannerStyle(profile?.bannerStyle || "theme");
  const accessibility = profile?.accessibility || {};
  const root = document.documentElement;
  const body = document.body;
  const colors = theme?.colors || {};

  if (avatarImg) {
    avatarImg.src = avatarUrl;
    avatarImg.alt = `${profile?.avatarAgent || "Agent"} avatar`;
  }

  if (rankIcon) {
    rankIcon.src = getRankIconUrl(getTierRank(computeCurrentRRAbsolute())?.tierLabel || peak.tierLabel);
    rankIcon.alt = peak.tierLabel;
  }

  if (panel) {
    panel.classList.remove("theme-classic", "theme-ember", "theme-ocean", "theme-verdant", "theme-cosmic", "border-standard", "border-gilded", "border-prismatic", "border-runed", "border-tactical");
    panel.classList.add(`theme-classic`);
    panel.classList.add(`border-${borderStyle}`);
  }

  if (ring) {
    ring.style.setProperty("--profile-ring-border", colors.accent || "#64748b");
    ring.style.setProperty(
      "--profile-ring-bg",
      colorMixOrFallback(
        `linear-gradient(135deg, ${colors.card || "#0b1220"}, color-mix(in srgb, ${colors.accent || "#ff4655"} 18%, ${colors.card2 || "#0f172a"}))`,
        `linear-gradient(135deg, ${colors.card || "#0b1220"}, ${colors.card2 || "#0f172a"})`
      )
    );
    ring.style.setProperty("--profile-ring-glow", colors.glow || "rgba(255,70,85,0.55)");
  }

  if (root) {
    root.style.setProperty("--surface-base", colors.base || "#071029");
    root.style.setProperty("--surface-base-2", colors.base2 || "#071b2b");
    root.style.setProperty("--surface-nav", colors.nav || "rgba(11,18,32,.84)");
    root.style.setProperty("--surface-card", colors.card || "#0b1220");
    root.style.setProperty("--surface-card-2", colors.card2 || "#0f172a");
    root.style.setProperty("--surface-input", colors.input || "#0f172a");
    root.style.setProperty("--surface-modal", colors.modal || "#020617");
    root.style.setProperty("--surface-overlay", colors.overlay || "rgba(15,23,42,.7)");
    root.style.setProperty("--border-soft", colors.border || "rgba(148,163,184,.14)");
    root.style.setProperty("--border-strong", colors.borderStrong || "rgba(148,163,184,.38)");
    root.style.setProperty("--text-main", colors.text || "#e6eef8");
    root.style.setProperty("--text-muted", colors.muted || "#94a3b8");
    root.style.setProperty("--accent", colors.accent || "#ff4655");
    root.style.setProperty("--accent-2", colors.accent2 || "#f97316");
    root.style.setProperty("--button-bg", colors.button || "#1e293b");
    root.style.setProperty("--button-hover", colors.buttonHover || "#334155");
    root.style.setProperty("--theme-glow", colors.glow || "rgba(255,70,85,.22)");
    root.style.setProperty("--theme-bg-gradient", `linear-gradient(180deg, ${colors.base || "#071029"}, ${colors.base2 || "#071b2b"})`);
    root.style.setProperty("--theme-bg-pattern", colors.pattern || "radial-gradient(circle at 20% 20%, rgba(255,255,255,.06), transparent 36%)");
    root.style.setProperty("--theme-bg-pattern-2", colors.pattern2 || "radial-gradient(circle at 78% 12%, rgba(255,70,85,.14), transparent 30%)");
  }

  if (body) {
    body.classList.remove("theme-static", "theme-kinetic", "theme-rings", "theme-orbit", "theme-shimmer", "theme-tide", "access-high-contrast", "access-readable", "access-reduced-motion", "access-mobile-layout");
    body.dataset.theme = themeKey;
    body.classList.add(`theme-${theme.motion || "static"}`);
    if (accessibility.contrastMode === "high") body.classList.add("access-high-contrast");
    if (accessibility.layoutMode === "mobile") body.classList.add("access-mobile-layout");
    if (accessibility.motionMode === "reduced") body.classList.add("access-reduced-motion");
  }

  if (header) {
    const selectedBannerUrl = getBannerImageUrl(bannerStyle);
    const activeBannerUrl = selectedBannerUrl;
    const bannerPattern = getBannerPattern(bannerStyle, theme);
    const imageLayer = activeBannerUrl
      ? `linear-gradient(90deg, rgba(2,6,23,.46), rgba(2,6,23,.12) 44%, rgba(2,6,23,.52)), ${toCssUrl(activeBannerUrl)}`
      : "none";
    header.style.setProperty("--nav-bg-image", imageLayer);
    header.style.setProperty("--nav-banner-pattern", activeBannerUrl ? "none" : bannerPattern);
    header.style.setProperty("--nav-bg-opacity", activeBannerUrl ? ".52" : ".18");
  }

  ensureThemeBuilderThemeState(getCurrentThemeBuilderThemeKey());
  if (themeBuilderNeedsSave) {
    saveThemeBuilderState();
    themeBuilderNeedsSave = false;
  }
  applyThemeBuilderRuntimeStyles();
  syncThemeBuilderUI();
}

function populateEditProfileModal(profile = getActiveProfile()) {
  const themeSelect = document.getElementById("editProfileTheme");
  const avatarSelect = document.getElementById("editProfileAvatarAgent");
  const borderSelect = document.getElementById("editProfileBorderStyle");
  const bannerSelect = document.getElementById("editProfileBannerStyle");

  if (themeSelect && !themeSelect.options.length) {
    themeSelect.innerHTML = PROFILE_THEME_PRESETS
      .map(theme => `<option value="${theme.value}">${theme.label}</option>`)
      .join("");
  }

  if (avatarSelect && !avatarSelect.options.length) {
    avatarSelect.innerHTML = allAgents
      .map(agent => `<option value="${String(agent).toLowerCase()}">${agent}</option>`)
      .join("");
  }

  if (borderSelect && !borderSelect.options.length) {
    borderSelect.innerHTML = PROFILE_BORDER_STYLES
      .map(style => `<option value="${style.value}">${style.label}</option>`)
      .join("");
  }

  if (bannerSelect && !bannerSelect.options.length) {
    bannerSelect.innerHTML = PROFILE_BANNER_STYLES
      .map(style => `<option value="${style.value}">${style.label}</option>`)
      .join("");
  }

  document.getElementById("editProfileName").value = profile?.name || "";
  document.getElementById("editProfileRiotId").value = profile?.riotId || "";
  document.getElementById("editProfileRegion").value = profile?.region || "NA";
  const startingRREl = document.getElementById("editProfileStartingRR");
  const startingRRNoteEl = document.getElementById("editProfileStartingRRNote");
  if (startingRREl) {
    startingRREl.value = safeNumber(profile?.startingRR);
  }
  if (startingRRNoteEl) {
    const syncDateLabel = profile?.startingRRDate
      ? new Date(`${profile.startingRRDate}T00:00:00`).toLocaleDateString()
      : "the first Riot sync";
    startingRRNoteEl.textContent = profile?.startingRRDate
      ? `Captured automatically on ${syncDateLabel}. This value is locked.`
      : "Captured automatically on the first Riot sync of the day. This value is locked.";
  }
  const selectedThemeKey = String(profile?.themeKey || profile?.frameTheme || "default").toLowerCase() === "reaver"
    ? "default"
    : (profile?.themeKey || profile?.frameTheme || "default");
  const selectedBorder = normalizeProfileBorderStyle(profile?.profileBorder || "standard");
  const selectedBanner = normalizeProfileBannerStyle(profile?.bannerStyle || "theme");
  if (themeSelect) themeSelect.value = selectedThemeKey;
  renderThemeGallery(selectedThemeKey);
  if (avatarSelect) avatarSelect.value = String(profile?.avatarAgent || getDefaultProfileAvatarAgent()).toLowerCase();
  renderAvatarGallery(profile?.avatarAgent || getDefaultProfileAvatarAgent());
  if (borderSelect) borderSelect.value = selectedBorder;
  renderBorderGallery(selectedBorder);
  if (bannerSelect) bannerSelect.value = selectedBanner;
  renderBannerGallery(selectedBanner, selectedThemeKey);
  const contrastModeEl = document.getElementById("editProfileContrastMode");
  const motionModeEl = document.getElementById("editProfileMotionMode");
  const layoutModeEl = document.getElementById("editProfileLayoutMode");
  if (contrastModeEl) contrastModeEl.value = profile?.accessibility?.contrastMode || "standard";
  if (motionModeEl) motionModeEl.value = profile?.accessibility?.motionMode || "standard";
  if (layoutModeEl) layoutModeEl.value = normalizeAccessibilityLayoutMode(profile?.accessibility?.layoutMode);
}

function openEditProfileModal() {
  populateEditProfileModal();
  activateProfileEditTab("theme");
  showModalById("editProfileModal");
}

function activateProfileEditTab(tabKey = "theme") {
  document.querySelectorAll(".profile-edit-tab").forEach((tab) => {
    tab.classList.toggle("is-active", tab.dataset.profileTab === tabKey);
  });
  document.querySelectorAll(".profile-edit-panel").forEach((panel) => {
    panel.classList.toggle("is-active", panel.dataset.profilePanel === tabKey);
  });
}

function saveEditProfileModal() {
  const profile = getActiveProfile();
  if (!profile) return;

  updateProfile(profile.id, {
    name: document.getElementById("editProfileName")?.value?.trim() || profile.name,
    riotId: document.getElementById("editProfileRiotId")?.value?.trim() || "",
    region: document.getElementById("editProfileRegion")?.value?.trim() || "NA",
    themeKey: document.getElementById("editProfileTheme")?.value || profile.themeKey || "default",
    avatarAgent: document.getElementById("editProfileAvatarAgent")?.value || profile.avatarAgent,
    profileBorder: normalizeProfileBorderStyle(document.getElementById("editProfileBorderStyle")?.value || profile.profileBorder || "standard"),
    bannerStyle: normalizeProfileBannerStyle(document.getElementById("editProfileBannerStyle")?.value || profile.bannerStyle || "theme"),
    navBackgroundUrl: "",
    accessibility: profile?.accessibility || { contrastMode: "standard", motionMode: "standard", layoutMode: "web" }
  });

  hideModalById("editProfileModal");
}

function previewEditProfileVisuals() {
  const profile = getActiveProfile();
  if (!profile) return;
  const activeThemeKey = document.getElementById("editProfileTheme")?.value || profile.themeKey || "default";
  const activeAvatar = document.getElementById("editProfileAvatarAgent")?.value || profile.avatarAgent;
  const activeBorder = normalizeProfileBorderStyle(document.getElementById("editProfileBorderStyle")?.value || profile.profileBorder || "standard");
  const activeBanner = normalizeProfileBannerStyle(document.getElementById("editProfileBannerStyle")?.value || profile.bannerStyle || "theme");
  renderThemeGallery(activeThemeKey);
  renderAvatarGallery(activeAvatar);
  renderBorderGallery(activeBorder);
  renderBannerGallery(activeBanner, activeThemeKey);
  applyProfileVisuals({
    ...profile,
    themeKey: activeThemeKey,
    frameTheme: activeThemeKey,
    avatarAgent: activeAvatar,
    avatarUrl: getDefaultProfileAvatarUrl(activeAvatar || profile.avatarAgent),
    profileBorder: activeBorder,
    bannerStyle: activeBanner,
    navBackgroundUrl: "",
    accessibility: profile?.accessibility || { contrastMode: "standard", motionMode: "standard", layoutMode: "web" }
  });
}

// ========================
// NAVIGATION
// ========================

function updateNavUnderline(){

  const activeBtn =
    document.querySelector(".nav-btn.active");

  const underline =
    document.querySelector(".nav-underline");

  const container =
    document.querySelector(".nav-links");

  if (!activeBtn || !underline || !container)
    return;

  const rect = activeBtn.getBoundingClientRect();
  const parentRect = container.getBoundingClientRect();

  underline.style.width =
    rect.width + "px";

  underline.style.left =
    (rect.left - parentRect.left) + "px";
}

let pageTransitionToken = 0;
let pageTransitionTimer = 0;

function activatePage(pageId){

  hideChartTooltip();
  if (pageId === "home") {
    scheduleLoadoutValueTextFit();
  }

  document
    .querySelectorAll(".nav-btn")
    .forEach(btn =>
      btn.classList.toggle(
        "active",
        btn.dataset.page === pageId
      )
    );

  const targetId = "page-" + pageId;
  const nextPage = document.getElementById(targetId);
  const currentPage = document.querySelector(".page.active");

  if (nextPage && currentPage !== nextPage) {
    const token = ++pageTransitionToken;
    if (pageTransitionTimer) {
      window.clearTimeout(pageTransitionTimer);
      pageTransitionTimer = 0;
    }

    document.querySelectorAll(".page").forEach(page => {
      if (page === nextPage) return;
      page.classList.remove("entering");
      if (page === currentPage) {
        page.classList.add("exiting");
      } else {
        page.classList.remove("active", "exiting");
      }
    });

    nextPage.classList.remove("exiting");
    nextPage.classList.add("active", "entering");
    window.requestAnimationFrame(() => {
      window.requestAnimationFrame(() => {
        if (token !== pageTransitionToken || !nextPage.isConnected) return;
        nextPage.classList.remove("entering");
      });
    });

    if (currentPage) {
      pageTransitionTimer = window.setTimeout(() => {
        if (token !== pageTransitionToken || !currentPage.isConnected) return;
        currentPage.classList.remove("active", "exiting");
      }, 240);
    }
  } else if (nextPage) {
    nextPage.classList.add("active");
    nextPage.classList.remove("entering", "exiting");
  }

  if(pageId === "home" && pendingAgentFromLog){

  spinLoadoutFromLogging(
    pendingAgentFromLog,
    pendingFocusFromLog
  );

  pendingAgentFromLog = null;
  pendingFocusFromLog = null;
}

  if (pageId === "home") {
    forceChartIntroAnimation = true;
    requestAnimationFrame(() => renderChart(currentSize));
  }

  if (pageId === "insights") {
    requestAnimationFrame(() => {
      enforceInsightsActionFluidWidth();
      scheduleInsightListOverflowSync(document.getElementById("insightsList"));
      replayOpenInsightTrendAnimation();
    });
  }

  if (pageId === "logging") {
    scheduleLoggingFeedRender({ force: true });
  } else {
    cancelScheduledLoggingFeedRender();
  }

  scheduleThemeBuilderAutoFitText({ resetBase: true });

  updateNavUnderline();
}


// ========================
// SCOREBOARD + DISPLAY
// ========================

function updateDisplays(){

  // ========================
  // RR TOTAL ANIMATION
  // ========================

  if(totalRRDisplay){

    const animationPayload = readRRTotalAnimationPayload();
    const payloadTs = Number(animationPayload?.ts || 0);
    const lastUsedPayloadTs = Number(totalRRDisplay.dataset.lastPayloadTs || 0);
    const persistedStart = readPersistedRRTotalDisplay();
    const datasetStart = Number(totalRRDisplay.dataset.value);
    const textStart = Number(totalRRDisplay.textContent);
    const shouldUsePayload =
      !!animationPayload &&
      Number(animationPayload.to) === Number(rrSum) &&
      payloadTs !== lastUsedPayloadTs;
    const start = shouldUsePayload
      ? Number(animationPayload.from)
      : Number.isFinite(datasetStart)
        ? datasetStart
        : Number.isFinite(persistedStart)
          ? persistedStart
        : Number.isFinite(textStart)
          ? textStart
          : 0;
    const target = rrSum;

    if (totalRRAnimFrame) {
      cancelAnimationFrame(totalRRAnimFrame);
      totalRRAnimFrame = null;
    }
    totalRRDisplay.classList.remove("rr-total-settle");
    totalRRDisplay.classList.remove("rr-total-rolling");
    totalRRDisplay.classList.remove("rr-total-positive", "rr-total-negative", "rr-total-neutral");

    const setDisplayValue = (value) => {
      totalRRDisplay.textContent = value;
      totalRRDisplay.style.color =
        value > 0 ? "#22c55e"
        : value < 0 ? "#ef4444"
        : "#e5e7eb";
    };

    const finishRRTotalAnimation = () => {
      totalRRAnimFrame = null;
      totalRRDisplay.dataset.value = String(target);
      if (shouldUsePayload && payloadTs) {
        totalRRDisplay.dataset.lastPayloadTs = String(payloadTs);
      }
      writePersistedRRTotalDisplay(target);
      totalRRDisplay.classList.remove("rr-total-rolling");
      totalRRDisplay.classList.add(
        target > 0 ? "rr-total-positive" :
        target < 0 ? "rr-total-negative" :
        "rr-total-neutral"
      );
      totalRRDisplay.classList.remove("rr-total-settle");
      void totalRRDisplay.offsetWidth;
      totalRRDisplay.classList.add("rr-total-settle");
    };

    if (start === target) {
      setDisplayValue(target);
      finishRRTotalAnimation();
    } else {
      const direction = target > start ? 1 : -1;
      const distance = Math.abs(target - start);
      const duration = 4000;
      const stepDuration = Math.max(32, duration / Math.max(distance, 1));
      let currentValue = start;
      let lastStepAt = performance.now();

      setDisplayValue(currentValue);
      totalRRDisplay.classList.add("rr-total-rolling");

      function frame(now){
        const elapsed = now - lastStepAt;
        const stepsToAdvance = Math.max(1, Math.floor(elapsed / stepDuration));

        if (elapsed >= stepDuration) {
          lastStepAt = now;
          currentValue += direction * stepsToAdvance;
          if ((direction > 0 && currentValue >= target) || (direction < 0 && currentValue <= target)) {
            currentValue = target;
          }
          setDisplayValue(currentValue);
        }

        if (currentValue !== target) {
          totalRRAnimFrame = requestAnimationFrame(frame);
        } else {
          finishRRTotalAnimation();
        }
      }

      totalRRAnimFrame = requestAnimationFrame(frame);
    }
  }

  // ========================
  // SCOREBOARD COUNTS
  // ========================

  let wins = 0;
  let losses = 0;
  let draws = 0;

  (matches || []).forEach(m => {
    if(m.result === "win") wins++;
    else if(m.result === "loss") losses++;
    else draws++;
  });

  if(winsCountEl) winsCountEl.textContent = wins;
  if(lossCountEl) lossCountEl.textContent = losses;
  if(drawCountEl) drawCountEl.textContent = draws;
  if(totalGamesEl) totalGamesEl.textContent = (matches || []).length;

  refreshImprovementTimeline({ animate: true });
  updateNavRRToRank();
  updateNavRRToGoalRank();

  const model = getPlayerModel();
  updateCompass(model?.compass || {}, model);
  scheduleLoadoutValueTextFit();

}
// ========================
// IMPACT BAR UPDATE
// ========================

function updateImpactBar(percent){

  const fill = document.getElementById("impactBarFill");
  const label = document.getElementById("impactScoreLabel");
  if(!fill) return;
  if (label && label.parentElement !== fill) {
    fill.appendChild(label);
  }

  percent = Math.max(0, Math.min(100, percent));
  const scoreTop = percent > 0
    ? Math.max(14, Math.min(92, 100 - (percent / 2)))
    : 88;

  fill.style.setProperty("--impact-fill-inset", `${100 - percent}%`);
  fill.style.setProperty("--impact-score-top", `${scoreTop}%`);
  if (label) {
    const strong = label.querySelector("strong");
    if (strong) strong.textContent = percent > 0 ? `${Math.round(percent)}%` : "--%";
    label.classList.toggle("is-empty", percent <= 0);
    label.style.setProperty("--impact-score-top", `${scoreTop}%`);
  }
  updateImpactThresholdState(percent);
}

// ========================
// RECOMPUTE RR
// ========================

function recomputeFromMatches(){

  rrSum = 0;

  let wins = 0;
  let losses = 0;
  let draws = 0;

  (matches || []).forEach(m => {

    rrSum += safeNumber(m.rr);

    if(m.result === "win") wins++;
    else if(m.result === "loss") losses++;
    else draws++;

  });

  if(winsCountEl) winsCountEl.textContent = wins;
  if(lossCountEl) lossCountEl.textContent = losses;
  if(drawCountEl) drawCountEl.textContent = draws;
  if(totalGamesEl) totalGamesEl.textContent = matches.length;

  if(totalRRDisplay && !Number.isFinite(Number(totalRRDisplay.dataset.value))){
    totalRRDisplay.textContent = rrSum;
  }

  const p = getActiveProfile();

  if(p){

    p.matches = matches.slice();

    saveProfiles();

  }

  updateNavRRToRank();
  updateNavRRToGoalRank();
  refreshImprovementTimeline({ animate: true });
}

// ========================
// ADD MATCH (REAL CORE)
// ========================

function addRRChange(delta, meta = {}){

  if(chartBusy || chartAnimating) return;

  chartBusy = true;

  isUndoAnimating = false;
  undoDirection = false;

  const rr = safeNumber(delta);

  matches.push({

    id: uuid(),

    rr,

    result:
      meta.result ||
      (rr > 0 ? "win" :
      rr < 0 ? "loss" : "draw"),

    agent:
      agentName?.textContent || "",

    focus:
      focusDisplay?.textContent || "",

    kills: meta.kills ?? null,
    deaths: meta.deaths ?? null,
    assists: meta.assists ?? null,
    acs: meta.acs ?? null,
    segments: Array.isArray(meta.segments) ? meta.segments : [],

    createdAt: nowISO()

  });

  recomputeFromMatches();

  updateDisplays();

  renderChart(currentSize);
}

// ========================
// UNDO MATCH (ANIMATED)
// ========================

function undoLastMatch(){

  if(chartBusy || chartAnimating) return;
  if(!matches.length) return;

  chartBusy = true;

  isUndoAnimating = true;
  undoDirection = true;
  pendingUndoCommit = true;

  console.log("UNDO START");

  // render current chart and let reverse animation run first
  renderChart(currentSize);
}

// ========================
// RR → RANK NAV
// ========================

function updateNavRRToRank(){
  const abs = computeCurrentRRAbsolute();
  const current = getTierRank(abs);
  const next = getNextTierRank(abs);
  const progress = getRankProgress();

  const currentIcon = document.getElementById("navCurrentTierIcon");
  const currentText = document.getElementById("navCurrentTierText");
  const nextIcon = document.getElementById("navNextTierIcon");
  const nextText = document.getElementById("navNextTierText");
  const bar = document.getElementById("navRRProgressBar");

  if(!current || !currentText || !nextText || !bar) return;

  currentText.textContent = current.tierLabel;

  if(currentIcon){
    currentIcon.src = getRankIconUrl(current.tierLabel);
    currentIcon.alt = current.tierLabel;
  }

  if(next && next.tierLabel !== current.tierLabel){
    nextText.textContent = `${progress.rrToNext} RR`;
    if(nextIcon){
      nextIcon.src = getRankIconUrl(next.tierLabel);
      nextIcon.alt = next.tierLabel;
    }
    bar.style.width = "100%";
    applyStaticTrackGradient(bar, Math.round(progress.pct * 100), "horizontal");
  } else {
    nextText.textContent = "Max Rank";
    if(nextIcon){
      nextIcon.src = getRankIconUrl(current.tierLabel);
      nextIcon.alt = current.tierLabel;
    }
    bar.style.width = "100%";
    applyStaticTrackGradient(bar, 100, "horizontal");
  }
}

// ========================
// GOAL RANK SYSTEM
// ========================

function updateNavRRToGoalRank(){
  const profile = getActiveProfile();
  const abs = computeCurrentRRAbsolute();
  const current = getTierRank(abs);
  const currentIcon = document.getElementById("navGoalCurrentIcon");
  const targetIcon = document.getElementById("navGoalTargetIcon");
  const label = document.getElementById("navGoalTierText");
  const bar = document.getElementById("navRRGoalBar");

  if(!current || !label || !bar) return;

  if(currentIcon){
    currentIcon.src = getRankIconUrl(current.tierLabel);
    currentIcon.alt = current.tierLabel;
  }

  if(!profile || !profile.goalRank){
    label.textContent = "Set Goal";
    bar.style.width = "100%";
    applyStaticTrackGradient(bar, 0, "horizontal");
    return;
  }

  const bounds = getTierBoundsByLabel(normalizeTierLabel(profile.goalRank));
  if(!bounds){
    label.textContent = "Invalid Goal";
    bar.style.width = "100%";
    applyStaticTrackGradient(bar, 0, "horizontal");
    return;
  }

  const rrNeeded = Math.max(0, bounds.min - abs);
  const span = Math.max(1, bounds.min - current.min);
  const progressPct = rrNeeded <= 0
    ? 100
    : Math.max(0, Math.min(100, ((abs - current.min) / span) * 100));

  if(targetIcon){
    targetIcon.src = getRankIconUrl(bounds.tierLabel);
    targetIcon.alt = bounds.tierLabel;
  }

  label.textContent =
    rrNeeded <= 0
      ? "Goal Reached"
      : `${rrNeeded} RR`;
  bar.style.width = "100%";
  applyStaticTrackGradient(bar, progressPct, "horizontal");
}

// ========================
// RR INPUT BUTTONS (REAL)
// ========================

function bindRRButtons(){

  addWinBtn?.addEventListener("click", () => {
    const val = safeNumber(rrInput?.value);
    addRRChange(Math.abs(val), { result: "win" });
  });

  addLossBtn?.addEventListener("click", () => {
    const val = safeNumber(rrInput?.value);
    addRRChange(-Math.abs(val), { result: "loss" });
  });

  addDrawBtn?.addEventListener("click", () => {
    addRRChange(0, { result: "draw" });
  });

  undoBtn?.addEventListener("click", () => {
    undoLastMatch();
  });

}

function handleLossInput(){

  const v = safeNumber(rrInput?.value || 0);

  if(!v) return;

  addRRChange(-Math.abs(v),{result:"loss"});
}

function handleDrawInput(){

  addRRChange(0,{result:"draw"});
}

function renderChart(size = currentSize){

  cancelChartFrame();

  chartAnimating = false;
  const previousSize = currentSize;
  const animationMode = pendingChartAnimationMode;
  pendingChartAnimationMode = null;
  currentSize = size;

  const tooltipAllowedForScope = chartScopeAllowsTooltip(size);
  const showDots = tooltipAllowedForScope;

  if(!chartRow) return;
  const renderToken = ++chartRenderToken;

  // ========================
  // RESPONSIVE WIDTH
  // ========================

const rect = chartRow.getBoundingClientRect();
const chartWidth = chartRow.clientWidth || chartRow.offsetWidth || rect.width;
const chartHeight = chartRow.clientHeight || chartRow.offsetHeight || rect.height;

if(chartWidth){
  CHART_W = chartWidth;
}

if(chartHeight){
  CHART_H = chartHeight;
}
  chartBusy = true;

  const cumulative=buildCumulativeRR(matches);

  const slice=getChartSlice(
    cumulative,
    size,
    matches.length
  );
  const chartRenderSignature = `${size}|${matches.length}|${slice.join(",")}`;

  const isUndo = isUndoAnimating === true;
  const scopeChanged = String(size) !== String(previousSize);
  const shouldAnimateIntro = Boolean(
    !isUndo && (
      animationMode === CHART_ANIMATION_MODE_EMPHASIS ||
      animationMode === CHART_ANIMATION_MODE_CONTINUOUS ||
      forceChartIntroAnimation ||
      scopeChanged
    )
  );
  const useContinuousIntro = animationMode === CHART_ANIMATION_MODE_CONTINUOUS;
  const shouldAnimateLatestOnly = Boolean(
    !isUndo && animationMode === CHART_ANIMATION_MODE_LATEST_ONLY
  );

  const shouldAnimate =
    isUndo ||
    shouldAnimateLatestOnly ||
    (!skipNextChartAnimation &&
     chartRenderSignature !== lastChartRenderSignature);

  if (!tooltipAllowedForScope || shouldAnimateIntro || shouldAnimate) {
    setChartTooltipSuppressed(true);
  } else {
    chartTooltipSuppressed = false;
  }
	 
  PAD_LEFT = CHART_W * 0.055;
  PAD_RIGHT = CHART_W * 0.055;
  PAD_TOP = CHART_H * 0.08;
  PAD_BOTTOM = CHART_H * 0.87;

// ========================
// NO MATCH PLACEHOLDER
// ========================

if(!matches || !matches.length){
  updateRRMatchStats(null);
  chartRow.classList.remove("chart-intro-active");
  setChartTooltipSuppressed(true);
  forceChartIntroAnimation = false;
  lastChartRenderSignature = `empty:${size}`;

  const min = -25;
  const max = 25;

  const y = v =>
    PAD_BOTTOM -
    ((v-min)/(max-min)) *
    (PAD_BOTTOM-PAD_TOP);

  let yTicks = "";

  for(let i=0;i<=4;i++){

    const val = min + ((max-min)/4)*i;
    const yy  = y(val);

    yTicks += `
<line
x1="${PAD_LEFT}"
y1="${yy}"
x2="${CHART_W-PAD_RIGHT}"
y2="${yy}"
stroke="rgba(148,163,184,0.25)"/>

<text
x="${PAD_LEFT-8}"
y="${yy+4}"
font-size="18"
fill="#94a3b8"
text-anchor="end">${Math.round(val)}</text>`;
  }

  let xTicks = "";
  const axisWindowSize = getChartAxisWindowSize(size, 0);
  const normalizedSize = String(size || "5").toLowerCase();

  for(let i=0;i<=4;i++){

    const xx =
      PAD_LEFT +
      ((CHART_W-PAD_LEFT-PAD_RIGHT)/4)*i;
    const tickValue = i === 4 && normalizedSize === "all"
      ? "All"
      : Math.round((axisWindowSize / 4) * i);

    xTicks += `
<text
x="${xx}"
y="${PAD_BOTTOM+28}"
font-size="18"
fill="#94a3b8"
text-anchor="middle">${tickValue}</text>`;
  }

  chartRow.innerHTML = `
<svg
width="${CHART_W}"
height="${CHART_H}"
viewBox="0 0 ${CHART_W} ${CHART_H}"
preserveAspectRatio="none">

<line
x1="${PAD_LEFT}"
y1="${y(0)}"
x2="${CHART_W-PAD_RIGHT}"
y2="${y(0)}"
stroke="rgba(148,163,184,.35)"
stroke-dasharray="6 6"/>

<line
x1="${PAD_LEFT}"
y1="${PAD_TOP}"
x2="${PAD_LEFT}"
y2="${PAD_BOTTOM}"
stroke="#94a3b8"
stroke-width="2"/>

<line
x1="${PAD_LEFT}"
y1="${PAD_BOTTOM}"
x2="${CHART_W-PAD_RIGHT}"
y2="${PAD_BOTTOM}"
stroke="#94a3b8"
stroke-width="2"/>

${yTicks}
${xTicks}

</svg>`;

  chartBusy = false;
  lastMatchesLength = 0;
  return;
}

  // ========================
  // BUILD DATA
  // ========================

  const bounds=getChartBounds(slice);

  const y=makeChartY(
    bounds.minTick,
    bounds.maxTick
  );

  const points=buildChartPoints(slice,y);

  const xTicks=buildXTicks(
    points,
    slice.length,
    matches.length
  );

  const yTicks=buildYTicks(
    bounds.minTick,
    bounds.maxTick,
    y
  );

  // ========================
  // SEGMENTS
  // ========================

  let segments="";
  let dots="";
  const introTiming = getChartIntroTiming(size, Math.max(0, points.length - 1), useContinuousIntro);
  const introSegmentDurationMs = introTiming.segmentMs;
  const introFinalPauseMs = introTiming.finalPauseMs;
  const introFinalSegmentDurationMs = introTiming.finalSegmentMs;
  const introDotPopDelayMs = 8;
  const introSettleMs = 220;

  for(let i=0;i<points.length-1;i++){

    const a=points[i];
    const b=points[i+1];

    const dx=b.x-a.x;
    const dy=b.y-a.y;

    const len=Math.sqrt(dx*dx+dy*dy);

    const color=b.rr>=0
      ? "#16a34a"
      : "#ef4444";

    const isLast=i===points.length-2;

    const animate=isLast && shouldAnimate && !shouldAnimateIntro;
    const introDelayMs = isLast
      ? (Math.max(0, points.length - 2) * introSegmentDurationMs) + introFinalPauseMs
      : i * introSegmentDurationMs;

    let cls="segment";
    let style="";

    if(shouldAnimateIntro){

      cls+=" chart-intro-segment";
      if(isLast && !useContinuousIntro){
        cls+=" chart-intro-segment-final";
      }
      style=`
--dash:${len};
stroke-dasharray:${len};
stroke-dashoffset:${len};
--intro-delay:${introDelayMs}ms;
--intro-segment-duration:${introSegmentDurationMs}ms;
--intro-final-segment-duration:${introFinalSegmentDurationMs}ms;
`;

    }else if(animate){

      cls+=" animate-segment";

      if(isUndo)
        cls+=" reverse";

      style=`
--dash:${len};
stroke-dasharray:${len};
stroke-dashoffset:${isUndo ? 0 : len};
`;

    }else{

      style=`
stroke-dasharray:${len};
stroke-dashoffset:0;
`;
    }

    segments+=`
<line class="${cls}"
x1="${a.x}" y1="${a.y}"
x2="${b.x}" y2="${b.y}"
stroke="${color}"
stroke-width="${LINE_WIDTH}"
stroke-linecap="round"
style="${style}"/>`;

if(showDots){
  dots += buildDotMarkup(b, {
    final: isLast,
    intro: shouldAnimateIntro,
    introDelayMs: introDelayMs + (isLast ? introFinalSegmentDurationMs : introSegmentDurationMs) + introDotPopDelayMs
  });

}
}
// ========================
// GRADIENT COLOR DETECT
// ========================

const hasNegative = points.some(p => p.value < 0);
const gradId = hasNegative ? "rrAreaGradRed" : "rrAreaGradGreen";

// ========================
// ZERO LINE
// ========================

const zeroY = y(0);

// ========================
// SEGMENT AREA GRADIENT
// ========================

let area = "";

for(let i = 0; i < points.length - 1; i++){

  const a = points[i];
  const b = points[i+1];

  const grad = b.value >= 0
    ? "rrAreaGradGreen"
    : "rrAreaGradRed";

  const path = `
M ${a.x} ${PAD_BOTTOM}
L ${a.x} ${a.y}
L ${b.x} ${b.y}
L ${b.x} ${PAD_BOTTOM}
Z
`;

  area += `
<path
d="${path}"
fill="url(#${grad})"
opacity=".35"
/>`;
}

 // ========================
// SVG BUILD
// ========================

chartRow.innerHTML = `
<svg
width="${CHART_W}"
height="${CHART_H}"
viewBox="0 0 ${CHART_W} ${CHART_H}"
preserveAspectRatio="none">

<defs>

<linearGradient id="rrAreaGradGreen" x1="0" y1="0" x2="0" y2="1">
<stop offset="0%" stop-color="#22c55e" stop-opacity=".35"/>
<stop offset="100%" stop-color="#22c55e" stop-opacity="0"/>
</linearGradient>

<linearGradient id="rrAreaGradRed" x1="0" y1="0" x2="0" y2="1">
<stop offset="0%" stop-color="#ef4444" stop-opacity=".35"/>
<stop offset="100%" stop-color="#ef4444" stop-opacity="0"/>
</linearGradient>

</defs>

<line x1="${PAD_LEFT}" y1="${PAD_TOP}"
x2="${PAD_LEFT}" y2="${PAD_BOTTOM}"
stroke="#94a3b8" stroke-width="2"/>

<line x1="${PAD_LEFT}" y1="${PAD_BOTTOM}"
x2="${CHART_W-PAD_RIGHT}" y2="${PAD_BOTTOM}"
stroke="#94a3b8" stroke-width="2"/>

${yTicks}
${xTicks}
${area}

<line id="chartCrosshair"
x1="0"
y1="0"
x2="0"
y2="${PAD_BOTTOM}"
stroke="rgba(250,204,21,.45)"
stroke-width="1.5"
opacity="0"/>

${segments}
${dots}

</svg>`;

chartRow.classList.toggle("chart-intro-active", shouldAnimateIntro);
if (!shouldAnimateIntro) {
  chartRow.classList.remove("chart-intro-active");
}

tooltip   = document.getElementById("chartTooltip");
crosshair = chartRow.querySelector("#chartCrosshair");

// clear stale selection when chart rebuilds
selectedDot = null;

// ========================
// ANIMATION
// ========================

const seg = chartRow.querySelector(".animate-segment");

if(shouldAnimateIntro){

  setChartTooltipSuppressed(true);

  requestAnimationFrame(() => {
    if (renderToken !== chartRenderToken) return;
    chartRow.classList.add("chart-intro-active");
  });

  const finalDotRevealDelay = Math.max(
    0,
    (Math.max(0, points.length - 2) * introSegmentDurationMs) +
    introFinalPauseMs +
    introFinalSegmentDurationMs +
    introDotPopDelayMs
  );
  const introDuration = Math.max(
    820,
    finalDotRevealDelay +
    introSettleMs
  );
  window.setTimeout(() => {
    if (renderToken !== chartRenderToken) return;
    chartTooltipSuppressed = false;
    if (tooltipAllowedForScope) {
      autoSelectLatest({ popTooltip: true });
    } else {
      hideChartTooltip();
    }
  }, finalDotRevealDelay);
  window.setTimeout(() => {
    if (renderToken !== chartRenderToken) return;
    chartBusy = false;
    chartAnimating = false;
    lastChartRenderSignature = chartRenderSignature;
  }, introDuration);

  skipNextChartAnimation = false;
  lastMatchesLength = matches.length;
  lastChartRenderSignature = chartRenderSignature;
  forceChartIntroAnimation = false;
  isUndoAnimating = false;
  undoDirection = false;

}else if(seg && shouldAnimate){

  setChartTooltipSuppressed(true);
  seg.style.animationPlayState = "paused";

requestAnimationFrame(() => {

  requestAnimationFrame(() => {  // ✅ second frame guarantees render

    if(!seg || !seg.isConnected){
      chartBusy = false;
      chartAnimating = false;
      chartTooltipSuppressed = !chartScopeAllowsTooltip(currentSize);
      return;
    }

    seg.style.animationPlayState = "running";

    // 🛡️ SAFE LENGTH CHECK
    let len = 0;

    try{
      len = seg.getTotalLength();
    }catch(e){
      chartBusy = false;
      chartAnimating = false;
      chartTooltipSuppressed = !chartScopeAllowsTooltip(currentSize);
      return;
    }

    if(!len || !Number.isFinite(len)){
      chartBusy = false;
      chartAnimating = false;
      chartTooltipSuppressed = !chartScopeAllowsTooltip(currentSize);
      return;
    }

    followSegment(seg,isUndo);

  });

});

}else{

  chartTooltipSuppressed = !tooltipAllowedForScope;
  autoSelectLatest();
  if (!tooltipAllowedForScope) {
    hideChartTooltip();
  }
  placeStaticGoldDot();

  chartBusy = false;
  chartAnimating = false;

  skipNextChartAnimation = false;
  lastMatchesLength = matches.length;
  lastChartRenderSignature = chartRenderSignature;
  forceChartIntroAnimation = false;

  isUndoAnimating = false;
  undoDirection = false;
}

// ========================
// CHART INTERACTION
// ========================

tooltip = document.getElementById("chartTooltip");
let chartPointerMoveRaf = 0;
let pendingChartPointerHit = null;

const flushChartPointerMove = () => {
  chartPointerMoveRaf = 0;
  const hit = pendingChartPointerHit;
  pendingChartPointerHit = null;
  if (chartTooltipSuppressed || !chartScopeAllowsTooltip(currentSize)) {
    hideChartTooltip();
    return;
  }
  if (!hit || selectedDot) return;

  const cx = Number(hit.getAttribute("cx"));
  const cy = Number(hit.getAttribute("cy"));

  if(crosshair){
    crosshair.style.opacity = 1;
    crosshair.setAttribute("x1", cx);
    crosshair.setAttribute("x2", cx);
    crosshair.setAttribute("y1", cy);
    crosshair.setAttribute("y2", PAD_BOTTOM);
  }

  positionTooltipToHit(hit);
  updateRRMatchStatsFromHit(hit);
};

chartRow.onpointermove = e => {
  if (chartTooltipSuppressed || !chartScopeAllowsTooltip(currentSize)) {
    hideChartTooltip();
    return;
  }
  const hit = getChartHitFromTarget(e.target);
  if(!hit) return;
  if(selectedDot) return;
  pendingChartPointerHit = hit;
  if (chartPointerMoveRaf) return;
  chartPointerMoveRaf = requestAnimationFrame(flushChartPointerMove);
};

chartRow.addEventListener("mouseleave", () => {
  if (chartPointerMoveRaf) {
    cancelAnimationFrame(chartPointerMoveRaf);
    chartPointerMoveRaf = 0;
  }
  pendingChartPointerHit = null;
  if(selectedDot) return;
  hideChartTooltip();
});

chartRow.onclick = e => {
  if (chartPointerMoveRaf) {
    cancelAnimationFrame(chartPointerMoveRaf);
    chartPointerMoveRaf = 0;
  }
  pendingChartPointerHit = null;
  if (chartTooltipSuppressed || !chartScopeAllowsTooltip(currentSize)) {
    hideChartTooltip();
    return;
  }
  const hit = getChartHitFromTarget(e.target);
  if(!hit) return;

  const dot = getChartDotFromHit(hit);
  if(!dot) return;

  if(selectedDot === dot){
    dot.classList.remove("rr-selected");
    selectedDot = null;
    autoSelectLatest();
    return;
  }

  document
    .querySelectorAll(".rr-selected")
    .forEach(d => d.classList.remove("rr-selected"));

  dot.classList.add("rr-selected");
  selectedDot = dot;

  const cx = Number(hit.getAttribute("cx"));
  const cy = Number(hit.getAttribute("cy"));

  if(crosshair){
    crosshair.style.opacity = 1;
    crosshair.setAttribute("x1", cx);
    crosshair.setAttribute("x2", cx);
    crosshair.setAttribute("y1", cy);
    crosshair.setAttribute("y2", PAD_BOTTOM);
  }

  positionTooltipToHit(hit, { pop: true });
  updateRRMatchStatsFromHit(hit);
  setSelectedTimelineContext(Number(hit?.dataset?.matchIndex), { animate: true });
};
}

function scheduleSelectedChartTooltipPosition() {
  if (selectedChartTooltipRaf) return;
  selectedChartTooltipRaf = window.requestAnimationFrame(() => {
    selectedChartTooltipRaf = 0;
    if (!canRenderChartTooltip()) {
      hideChartTooltip();
      return;
    }
    if(!selectedDot) return;
    const hit = selectedDot.previousElementSibling;
    if(hit) positionTooltipToHit(hit);
  });
}

window.addEventListener("scroll", scheduleSelectedChartTooltipPosition, { passive: true });
document.addEventListener("scroll", scheduleSelectedChartTooltipPosition, { capture: true, passive: true });
window.addEventListener("resize", scheduleSelectedChartTooltipPosition, { passive: true });

// ==============================
// GOLD DOT HELPERS
// ==============================

function placeStaticGoldDot(){

  const svg = chartRow?.querySelector("svg");
  if(!svg) return;

  // real gold endpoint already exists in chart markup
  if(svg.querySelector(".final-end")) return;

  const segments = svg.querySelectorAll(".segment");
  if(!segments || !segments.length) return;

  svg.querySelectorAll(".gold-follower").forEach(el=>el.remove());

  const lastSeg = segments[segments.length-1];

  const dot =
    document.createElementNS(
      "http://www.w3.org/2000/svg",
      "circle"
    );

  dot.setAttribute("cx", lastSeg.getAttribute("x2"));
  dot.setAttribute("cy", lastSeg.getAttribute("y2"));
  dot.setAttribute("r", 6);
  dot.setAttribute("fill", "#facc15");

  dot.classList.add("gold-follower");

  svg.appendChild(dot);
}

function autoSelectLatest(options = {}){
  const { popTooltip = false } = options;
  const tooltipAllowed = chartScopeAllowsTooltip(currentSize);

  const gold = chartRow.querySelector(".final-end");
  const hit  = gold?.previousElementSibling;

  if(!gold || !hit) {
    setSelectedTimelineContext(null, { animate: false });
    updateRRMatchStats(null);
    return;
  }

  document
    .querySelectorAll(".rr-selected")
    .forEach(d => d.classList.remove("rr-selected"));

  gold.classList.add("rr-selected");
  selectedDot = gold;

  const cx = Number(hit.getAttribute("cx"));
  const cy = Number(hit.getAttribute("cy"));

  if(crosshair){
    crosshair.style.opacity = 1;
    crosshair.setAttribute("x1", cx);
    crosshair.setAttribute("x2", cx);
    crosshair.setAttribute("y1", cy);
    crosshair.setAttribute("y2", PAD_BOTTOM);
  }

  if (tooltipAllowed) {
    positionTooltipToHit(hit, { pop: popTooltip });
  } else {
    hideChartTooltip();
  }
  updateRRMatchStatsFromHit(hit);
  setSelectedTimelineContext(null, { animate: true });
}

// ==============================
// GOLD DOT FOLLOWER
// ==============================

function followSegment(seg, reverse = false){

  const svg = seg.closest("svg");
  if(!svg) return;

  if(chartAnimating) return;
  chartAnimating = true;
  setChartTooltipSuppressed(true);

  svg.querySelectorAll(".gold-follower").forEach(el => el.remove());

  const len = seg.getTotalLength();
  if(!len || !Number.isFinite(len)){
    chartAnimating = false;
    chartBusy = false;
    chartTooltipSuppressed = !chartScopeAllowsTooltip(currentSize);
    return;
  }

const dot = document.createElementNS(
  "http://www.w3.org/2000/svg",
  "circle"
);

dot.setAttribute("r", 6);
dot.setAttribute("fill", "#facc15");
dot.classList.add("gold-follower");

// set initial position BEFORE appending
const initialPoint = reverse
  ? seg.getPointAtLength(len)
  : seg.getPointAtLength(0);

dot.setAttribute("cx", initialPoint.x);
dot.setAttribute("cy", initialPoint.y);

svg.appendChild(dot);

  const targetX = Number(seg.getAttribute("x2"));
  const targetY = Number(seg.getAttribute("y2"));
  const targetDot = Array.from(svg.querySelectorAll(".rr-dot, .final-end")).find((candidate) => {
    const cx = Number(candidate.getAttribute("cx"));
    const cy = Number(candidate.getAttribute("cy"));
    return Math.abs(cx - targetX) < 0.5 && Math.abs(cy - targetY) < 0.5;
  });

  if (targetDot instanceof SVGElement) {
    targetDot.style.opacity = "0";
    targetDot.dataset.chartHiddenDuringFollow = "1";
  }

  seg.style.animationPlayState = "running";

  let finished = false;

  function finishAnimation(){

    if(finished) return;
    finished = true;

    if(chartAnimFrame){
      cancelAnimationFrame(chartAnimFrame);
      chartAnimFrame = null;
    }

    const finalLen = reverse ? 0 : len;
    const finalPoint = seg.getPointAtLength(finalLen);

    dot.setAttribute("cx", finalPoint.x);
    dot.setAttribute("cy", finalPoint.y);
    dot.remove();

    if (targetDot instanceof SVGElement) {
      targetDot.style.removeProperty("opacity");
      delete targetDot.dataset.chartHiddenDuringFollow;
    }

    chartAnimating = false;

    // reverse undo commit happens ONLY after reverse animation finishes
    if(reverse && pendingUndoCommit){

      console.log("UNDO APPLY MATCH POP");

      pendingUndoCommit = false;

      matches.pop();

      recomputeFromMatches();
      updateDisplays();

      skipNextChartAnimation = true;
      isUndoAnimating = false;
      undoDirection = false;

      renderChart(currentSize);
      lastMatchesLength = matches.length;
      lastChartRenderSignature = chartRenderSignature;

      return;
    }

    chartBusy = false;
    lastMatchesLength = matches.length;
    lastChartRenderSignature = chartRenderSignature;
    skipNextChartAnimation = false;
    isUndoAnimating = false;
    undoDirection = false;

    chartTooltipSuppressed = false;
    if (!reverse && targetDot?.classList?.contains("final-end")) {
      if (chartScopeAllowsTooltip(currentSize)) {
        autoSelectLatest({ popTooltip: true });
      } else {
        hideChartTooltip();
      }
    }
  }

  function frame(){

    const dashOffset =
      parseFloat(getComputedStyle(seg).strokeDashoffset);

    if(!Number.isFinite(dashOffset)){
      finishAnimation();
      return;
    }

    // visible tip of the line is always len - dashOffset
    const pointLen = Math.max(0, Math.min(len, len - dashOffset));
    const point = seg.getPointAtLength(pointLen);

    dot.setAttribute("cx", point.x);
    dot.setAttribute("cy", point.y);

    // stop only when CSS animation has reached its real end
    const done = reverse
      ? dashOffset >= len - 0.5
      : dashOffset <= 0.5;

    if(done){
      finishAnimation();
      return;
    }

    chartAnimFrame = requestAnimationFrame(frame);
  }

  chartAnimFrame = requestAnimationFrame(frame);
}

