// ========================
// BUTTON TOOLTIP
// ========================

compassBtns.forEach(btn => {

  btn.addEventListener("mouseenter", () => {

    if (!compassTooltip || !compassWrap) return;
    if (compass?.classList.contains("stats-active")) return;

    const labels = {
      aim: "Aim",
      gamesense: "Game Sense",
      teamplay: "Teamwork",
      discipline: "Discipline"
    };

    const rect = btn.getBoundingClientRect();
    const wrapRect = compassWrap.getBoundingClientRect();

const rawX = rect.left - wrapRect.left + rect.width / 2;
const centerY = rect.top + rect.height / 2;
const wrapCenterY = wrapRect.top + wrapRect.height / 2;

let rawY;
let placeBelow;

// if button is in upper half → show below
if (centerY < wrapCenterY) {
  rawY = rect.bottom - wrapRect.top + 8;
  placeBelow = true;
} else {
  rawY = rect.top - wrapRect.top - 8;
  placeBelow = false;
}

// ========================
// CLAMP TO PANEL
// ========================

const minPad = 10;

const maxX = wrapRect.width - minPad;
const minX = minPad;

// clamp ONLY X
const x = Math.max(minX, Math.min(rawX, maxX));
const y = rawY; // 🔥 DO NOT CLAMP Y

compassTooltip.textContent = labels[btn.dataset.lens] || btn.dataset.lens;
compassTooltip.style.left = x + "px";
compassTooltip.style.top = y + "px";

// ========================
// EDGE-AWARE ALIGNMENT
// ========================

const tipWidth = compassTooltip.offsetWidth;

const yTransform = placeBelow ? "0%" : "-100%";

if (x + tipWidth / 2 > wrapRect.width) {
  compassTooltip.style.transform = `translate(-100%, ${yTransform})`;
} else if (x - tipWidth / 2 < 0) {
  compassTooltip.style.transform = `translate(0%, ${yTransform})`;
} else {
  compassTooltip.style.transform = `translate(-50%, ${yTransform})`;
}


compassTooltip.style.opacity = "1";

  });

  btn.addEventListener("mouseleave", () => {
    if (compassTooltip) compassTooltip.style.opacity = 0;
  });

});

