if (!window.__vt_riotProfileSaveBound) {
  window.__vt_riotProfileSaveBound = true;

  document.addEventListener("click", async (e) => {

    if(e.target.id !== "saveRiotProfileBtn") return;

    const saveBtn = document.getElementById("saveRiotProfileBtn");
    const originalText = saveBtn?.textContent || "Save";

    const riotId = document.getElementById("riotIdInput")?.value?.trim();
    const region = document.getElementById("riotRegionInput")?.value?.trim();

    if(!riotId){
      alert("Enter Riot ID");
      return;
    }

    try {
      if (saveBtn) {
        saveBtn.disabled = true;
        saveBtn.textContent = "Saving...";
      }

      const p = getActiveProfile();
      if(p){
        p.riotId = riotId;
        p.region = region || "NA";
        p.startingRRDate = "";
        p.startingRRSource = "";
        saveProfiles();
        updateProfileHeaderUI();
        scheduleRiotAutoSync();
      }

      if (supabaseClient?.auth) {
        const { data: { user } = {} } = await supabaseClient.auth.getUser();

        if(user){
          const { error } = await supabaseClient
            .from("users_profiles")
            .upsert({
              user_id: user.id,
              riot_id: riotId,
              region: region || "NA",
              profile_json: getActiveProfile() || {},
              updated_at: nowISO()
            }, { onConflict: "user_id" });

          if(error){
            alert(error.message);
            return;
          }
        }
      }

      if (saveBtn) {
        saveBtn.textContent = "Syncing Riot Data...";
      }

      closeRiotModal?.();
      await performRiotSync({
        silent: false,
        mode: "import",
        allowDemoFallback: false
      });
    } finally {
      if (saveBtn) {
        saveBtn.disabled = false;
        saveBtn.textContent = originalText;
      }
    }
  });
}

