function normalizeImportedMatchEntry(match = {}){
  const result = String(
    match?.result ||
    match?.metadata?.result ||
    "draw"
  ).toLowerCase();

  const createdAt =
    match?.createdAt ||
    match?.metadata?.playedAt ||
    nowISO();
  const core = getMatchCore(match);

  return {
    ...match,
    rr: safeNumber(
      match?.rr,
      result === "win" ? 18 : result === "loss" ? -16 : 0
    ),
    kills: Number.isFinite(core?.kills) ? core.kills : safeNumber(match?.kills, 0),
    deaths: Number.isFinite(core?.deaths) ? core.deaths : safeNumber(match?.deaths, 0),
    assists: Number.isFinite(core?.assists) ? core.assists : safeNumber(match?.assists, 0),
    acs: Number.isFinite(core?.acs) ? core.acs : safeNumber(match?.acs ?? match?.adr, 0),
    result,
    createdAt,
    metadata: {
      ...(match?.metadata || {}),
      result,
      playedAt: match?.metadata?.playedAt || createdAt
    }
  };
}

function applyImportedMatches(matchList = [], options = {}){

  const profile = getActiveProfile();
  if(!profile) return;
  const hadNoMatchesBeforeImport = !Array.isArray(matches) || matches.length === 0;

  const previousTotal = (matches || []).reduce((sum, match) => sum + safeNumber(match?.rr), 0);

  const normalized = (matchList || [])
    .filter(Boolean)
    .map(normalizeImportedMatchEntry);
  normalized.sort((a, b) =>
    new Date(a?.createdAt || a?.metadata?.playedAt || 0).getTime() -
    new Date(b?.createdAt || b?.metadata?.playedAt || 0).getTime()
  );
  const nextTotal = normalized.reduce((sum, match) => sum + safeNumber(match?.rr), 0);
  const importSource = options.source || "riot";

  if (importSource === "riot") {
    const todayKey = getCurrentDayKey();
    if (profile.startingRRDate !== todayKey) {
      const previousAbsolute = safeNumber(profile.startingRR) + previousTotal;
      profile.startingRR = Math.max(0, Math.round(previousAbsolute));
      profile.startingRRDate = todayKey;
      profile.startingRRSource = "riot-sync";
    }
  }

  if (previousTotal !== nextTotal) {
    writeRRTotalAnimationPayload(previousTotal, nextTotal);
  }

  profile.matches = normalized.slice();
  profile.importSource = importSource;
  profile.lastSyncAt = nowISO();

  if(options.analytics){
    profile.trackerAnalytics = options.analytics;
  }

  if(options.source === "demo-fixture"){
    logEntries = buildDemoLogEntriesFromMatches(normalized);
    saveLogEntries();
  }

  matches = normalized.slice();

  saveProfiles();
  recomputeFromMatches();

  initStatsPage();
  renderStatsAgents();
  renderStatsMaps();
  renderInsights();
  renderLogFeed();

  updateDisplays();
  updateNavRRToRank();
  updateNavRRToGoalRank();
  if (hadNoMatchesBeforeImport && normalized.length > 0) {
    forceChartIntroAnimation = true;
    queueChartAnimationMode(CHART_ANIMATION_MODE_EMPHASIS);
  } else if (options.animationMode) {
    queueChartAnimationMode(options.animationMode);
  }
  renderChart(currentSize);
  scheduleRiotAutoSync();
}

async function importDemoMatches(){
  const res = await fetchWithTimeout("/api/demo/import-example");
  const data = await res.json().catch(() => ({}));

  if(!res.ok){
    throw new Error(data?.error || `Demo import failed (${res.status})`);
  }

  const matchList = Array.isArray(data?.matches) ? data.matches : [];
  if(!matchList.length){
    throw new Error("Demo fixture did not return any matches");
  }

  applyImportedMatches(matchList, {
    source: data?.source || "demo-fixture",
    analytics: data?.analytics || null
  });

  return {
    count: matchList.length,
    source: data?.source || "demo-fixture"
  };
}

async function fetchWithTimeout(resource, options = {}, timeoutMs = RIOT_SYNC_FETCH_TIMEOUT_MS) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    return await fetch(resource, {
      ...options,
      signal: controller.signal
    });
  } catch (error) {
    if (error?.name === "AbortError") {
      throw new Error("Sync request timed out");
    }
    throw error;
  } finally {
    clearTimeout(timeoutId);
  }
}

async function importActiveProfileMatches(options = {}){
  const profile = getActiveProfile();
  if(!profile) throw new Error("No active profile");
  if(!profile.riotId) throw new Error("Set Riot ID first");
  const allowDemoFallback = options.allowDemoFallback !== false;

  try {
    const healthRes = await fetchWithTimeout("/api/riot/health");
    const health = await healthRes.json().catch(() => ({}));

    if (!healthRes.ok || health?.configured === false) {
      if (allowDemoFallback) {
        return importDemoMatches();
      }
      throw new Error("Riot sync is not configured");
    }
  } catch (_error) {
    if (allowDemoFallback) {
      return importDemoMatches();
    }
    throw new Error("Riot sync is unavailable");
  }

  try {
    const res = await fetchWithTimeout("/api/riot/import-matches", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        riotId: profile.riotId,
        region: normalizeRiotRegion(profile.region),
        count: 20
      })
    });

    const data = await res.json().catch(() => ({}));

    if(!res.ok){
      throw new Error(data?.error || `Import failed (${res.status})`);
    }

    const matchList = Array.isArray(data?.matches) ? data.matches : [];
    if(!matchList.length){
      throw new Error("No recent competitive matches found");
    }

    applyImportedMatches(matchList, {
      source: "riot",
      animationMode: options.mode === "refresh"
        ? CHART_ANIMATION_MODE_LATEST_ONLY
        : null
    });

    return {
      count: matchList.length,
      source: "riot"
    };
  } catch (error) {
    const message = String(error?.message || "");
    const shouldFallbackToDemo =
      message.includes("not configured") ||
      message.includes("500") ||
      message.includes("Import failed") ||
      message.includes("403") ||
      message.toLowerCase().includes("forbidden") ||
      message.includes("No recent competitive matches found");

    if(!shouldFallbackToDemo || !allowDemoFallback){
      throw error;
    }

    return importDemoMatches();
  }
}

async function syncActiveProfileMatches(options = {}){
  const result = await importActiveProfileMatches({
    allowDemoFallback: options.allowDemoFallback !== false
  });
  updateRRMatchStats(matches[matches.length - 1] || null);
  return {
    ...result,
    syncedAt: nowISO(),
    mode: options.mode || "sync"
  };
}

function clearRiotAutoSyncTimer() {
  if (riotAutoSyncTimer) {
    clearTimeout(riotAutoSyncTimer);
    riotAutoSyncTimer = null;
  }

  if (riotAutoSyncTicker) {
    clearInterval(riotAutoSyncTicker);
    riotAutoSyncTicker = null;
  }

  riotAutoSyncDeadline = 0;
}

function formatSyncCountdown(msRemaining) {
  const totalSeconds = Math.max(0, Math.ceil(msRemaining / 1000));
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}:${String(seconds).padStart(2, "0")}`;
}

function shouldShowIntervalCountdown(msRemaining) {
  const totalSeconds = Math.max(0, Math.ceil(msRemaining / 1000));
  return (
    (totalSeconds >= 118 && totalSeconds <= 120) ||
    (totalSeconds >= 88 && totalSeconds <= 90) ||
    (totalSeconds >= 58 && totalSeconds <= 60) ||
    (totalSeconds >= 28 && totalSeconds <= 30) ||
    totalSeconds <= 5
  );
}

function setProfileSyncStatus(timeValue, state = "idle", title = "", showTimer = false) {
  if (profileSyncCountdownEl) {
    profileSyncCountdownEl.textContent = timeValue;
  }

  if (profileSyncBtn) {
    profileSyncBtn.classList.remove("syncing", "counting", "needs-setup", "show-timer");
    if (state) {
      profileSyncBtn.classList.add(state);
    }
    if (showTimer) {
      profileSyncBtn.classList.add("show-timer");
    }

    const resolvedTitle = title || "Sync Riot data now";
    profileSyncBtn.title = resolvedTitle;
    profileSyncBtn.setAttribute("aria-label", resolvedTitle);
  }
}

function refreshProfileSyncCountdown() {
  if (riotSyncInFlight) {
    setProfileSyncStatus("", "syncing", "Syncing Riot data now", false);
    return;
  }

  if (!riotAutoSyncDeadline) {
    if (!hasSyncableRiotProfile()) {
      setProfileSyncStatus("", "needs-setup", "Add a Riot ID or load the demo dataset", false);
      return;
    }

    setProfileSyncStatus("", "counting", "Manual sync available. Auto sync will resume after the next schedule.", false);
    return;
  }

  const msRemaining = riotAutoSyncDeadline - Date.now();
  if (msRemaining <= 0) {
    setProfileSyncStatus("0:00", "counting", "Auto sync is about to run", true);
    return;
  }

  const countdownText = formatSyncCountdown(msRemaining);
  const showTimer = shouldShowIntervalCountdown(msRemaining);
  setProfileSyncStatus(
    showTimer ? countdownText : "",
    "counting",
    `Auto sync in ${countdownText}. Click to sync now and reset the timer.`,
    showTimer
  );
}

function startRiotAutoSyncCountdown() {
  if (riotAutoSyncTicker) {
    clearInterval(riotAutoSyncTicker);
  }

  refreshProfileSyncCountdown();

  if (!riotAutoSyncDeadline || riotSyncInFlight) {
    riotAutoSyncTicker = null;
    return;
  }

  riotAutoSyncTicker = setInterval(() => {
    refreshProfileSyncCountdown();

    if (!riotAutoSyncDeadline || riotSyncInFlight) {
      clearInterval(riotAutoSyncTicker);
      riotAutoSyncTicker = null;
    }
  }, 1000);
}

function hasSyncableRiotProfile() {
  const profile = getActiveProfile();
  return Boolean(currentAuthUser || profile?.riotId);
}

async function isRiotSyncConfigured() {
  try {
    const healthRes = await fetchWithTimeout("/api/riot/health");
    const health = await healthRes.json().catch(() => ({}));
    return Boolean(healthRes.ok && health?.configured !== false);
  } catch (_error) {
    return false;
  }
}

async function performRiotSync(options = {}) {
  const { silent = false, mode = "sync", allowDemoFallback = true } = options;
  const activeProfile = getActiveProfile();
  const hasRiotId = Boolean(activeProfile?.riotId);
  const hasIdentityAccess = Boolean(currentAuthUser || hasRiotId);

  if (riotSyncInFlight) {
    if (!silent) {
      alert("Riot sync is already in progress.");
    }
    scheduleRiotAutoSync();
    return null;
  }

  if (!hasIdentityAccess) {
    if (!silent) {
      alert("Sync requires either a logged-in account or a Riot ID on the active profile.");
      if (!currentAuthUser) {
        openAuthModal?.();
      } else {
        openRiotModal?.();
      }
    }

    clearRiotAutoSyncTimer();
    return null;
  }

  if (!hasRiotId) {
    if (!silent) {
      alert("Add a Riot ID to the active profile before syncing.");
      openRiotModal?.();
    }
    clearRiotAutoSyncTimer();
    return null;
  }

  if (!allowDemoFallback) {
    const configured = await isRiotSyncConfigured();
    if (!configured) {
      scheduleRiotAutoSync();
      return null;
    }
  }

  riotSyncInFlight = true;
  setProfileSyncStatus("", "syncing", "Syncing Riot data now", false);
  if (profileSyncBtn) profileSyncBtn.disabled = true;

  try {
    const result = await syncActiveProfileMatches({ mode, allowDemoFallback });
    const syncedProfile = getActiveProfile();
    if (syncedProfile) {
      syncedProfile.lastSyncAt = result?.syncedAt || nowISO();
      saveProfiles();
    }

    if (!silent) {
      if (result?.source === "demo-fixture") {
        alert(`Riot access is still restricted, so ${result.count} demo matches were loaded from the example dataset.`);
      } else {
        alert(`${mode === "refresh" ? "Synced" : "Imported"} ${result.count} recent matches from Riot.`);
      }
    }

    return result;
  } catch (err) {
    console.error("RIOT SYNC ERROR", err);
    if (!silent) {
      alert(err?.message || "Failed to sync Riot matches");
    }
    return null;
  } finally {
    riotSyncInFlight = false;
    if (profileSyncBtn) profileSyncBtn.disabled = false;
    scheduleRiotAutoSync();
  }
}

function scheduleRiotAutoSync() {
  clearRiotAutoSyncTimer();

  riotAutoSyncDeadline = Date.now() + RIOT_AUTO_SYNC_MS;
  startRiotAutoSyncCountdown();

  if (!hasSyncableRiotProfile()) {
    return;
  }

  riotAutoSyncTimer = setTimeout(() => {
    performRiotSync({
      silent: true,
      mode: "refresh",
      allowDemoFallback: false
    });
  }, RIOT_AUTO_SYNC_MS);
}

