function updateWeeklyFocusDetailsModel(topInsights = []) {
  updateWeeklyFocusDateLabel();
  const whyEl = document.getElementById("insightFocusWhy");
  const howEl = document.getElementById("insightFocusHow");
  const sourceEl = document.getElementById("insightFocusSource");
  const priorityEl = document.getElementById("insightPriorityPill");
  const confidenceEl = document.getElementById("insightConfidencePill");
  const summaryEl = document.getElementById("weeklyFocusSummary");
  const model = getPlayerModel();
  const weekly = model?.weekly || {};
  const weeklyCards = weekly.cards || {};
  const weeklyCandidates = model?.scoring?.weeklyCandidates || [];
  const primaryCandidate = weeklyCandidates[0] || null;
  const leadInsight = topInsights[0] || cachedInsights[0] || null;

  const applyConfidencePillClass = (el, confidence = {}) => {
    const label = confidence.label || "Low";
    el.classList.remove("confidence-high", "confidence-medium", "confidence-low");
    el.classList.add(
      label === "High" ? "confidence-high" :
      label === "Medium" ? "confidence-medium" :
      "confidence-low"
    );
    return label;
  };

  const weeklyPillMeta = {
    tilt: { title: "Tilt Pattern", fallback: weekly.topMood || "No mood trend yet", confidence: weeklyCards.primary },
    ratings: { title: "Self-Rating Pattern", fallback: weekly.weakestTheme || "No low-rating pattern yet", confidence: weeklyCards.secondary },
    losses: { title: "Loss Pattern", fallback: "No repeated loss context yet", confidence: { label: "Low", detail: "Waiting for loss-pattern confidence data." } },
    impactful: { title: "Biggest Focus Gap", fallback: "No clear focus gap yet", confidence: weeklyCards.tertiary }
  };

  if (summaryEl) {
    const renderedCandidates = weeklyCandidates.length
      ? weeklyCandidates.slice(0, 4)
      : [
          { key: "tilt", label: weekly.topMood || "No mood trend yet", confidence: weeklyCards.primary?.label || "Low", detail: weeklyCards.primary?.detail || "Waiting for confidence data." },
          { key: "ratings", label: weekly.weakestTheme || "No low-rating pattern yet", confidence: weeklyCards.secondary?.label || "Low", detail: weeklyCards.secondary?.detail || "Waiting for confidence data." },
          { key: "losses", label: "No repeated loss context yet", confidence: "Low", detail: "Waiting for confidence data." },
          { key: "impactful", label: weekly.mostPracticed || activeInsightFocus || "No repeated focus category yet", confidence: weeklyCards.tertiary?.label || "Low", detail: weeklyCards.tertiary?.detail || "Waiting for confidence data." }
        ];

    summaryEl.innerHTML = renderedCandidates.map((candidate, index) => {
      const meta = weeklyPillMeta[candidate?.key] || { title: `Weekly Read ${index + 1}`, fallback: "Waiting for weekly read", confidence: { label: candidate?.confidence || "Low", detail: candidate?.detail || "Waiting for confidence data." } };
      const confidenceConfig = {
        label: candidate?.confidence || meta?.confidence?.label || "Low",
        detail: candidate?.detail || meta?.confidence?.detail || "Waiting for confidence data."
      };
      const confidenceClassName = confidenceConfig.label === "High"
        ? "confidence-high"
        : confidenceConfig.label === "Medium"
          ? "confidence-medium"
          : "confidence-low";
      const pillBody = candidate?.summary || candidate?.label || meta.fallback;

      return `
        <button class="weekly-focus-pill" type="button" data-weekly-key="${escapeHtml(candidate?.key || "")}" title="${escapeHtml(candidate?.sourceLabel || confidenceConfig.detail)}">
          <div class="weekly-focus-pill-head">
            <span class="weekly-focus-key">${escapeHtml(meta.title)}</span>
            <span class="weekly-focus-confidence ${confidenceClassName}" title="${escapeHtml(confidenceConfig.detail)}">Confidence: ${escapeHtml(confidenceConfig.label)}</span>
          </div>
          <span class="weekly-focus-text">${escapeHtml(pillBody)}</span>
        </button>
      `;
    }).join("");
  }

  if (whyEl) {
    whyEl.textContent = primaryCandidate?.summary
      || primaryCandidate?.read
      || leadInsight?.preview
      || weekly.why
      || "Add more matches and logs to sharpen the weekly focus category.";
  }
  if (howEl) {
    howEl.textContent = model?.coachRecommendation
      || primaryCandidate?.read
      || leadInsight?.action
      || weekly.how
      || "Use one coaching focus category for the week and review whether the next match block improved it.";
  }
  if (sourceEl) {
    sourceEl.textContent = primaryCandidate?.sourceLabel
      || weekly.source
      || "Waiting for profile data";
  }
  if (priorityEl) {
    priorityEl.textContent = `Priority: ${model?.priorityLabel || "Watch"}`;
    applyInsightMetaPillTone(priorityEl, getInsightMetaToneClass("priority", model?.priorityLabel || "Watch"));
  }
  if (confidenceEl) {
    confidenceEl.textContent = `Confidence: ${model?.confidenceLabel || "Low Confidence"}`;
    applyInsightMetaPillTone(confidenceEl, getInsightMetaToneClass("confidence", model?.confidenceLabel || "Low Confidence"));
  }
}

