function renderStatsWeaponsModel() {
  const container = document.getElementById("statsWeaponsList");
  if (!container) return;

  const weaponSummaries = summarizeSpecificWeaponRounds(matches);
  const summaryMap = new Map(weaponSummaries.map(weapon => [weapon.weaponKey, weapon]));

  container.innerHTML = STATS_WEAPON_FAMILIES.map((family) => {
    const familySummary = getWeaponFamilySummary(family, summaryMap);
    const hasFamilyData = safeNumber(familySummary.rounds) > 0;
    const toneClass = hasFamilyData
      ? (safeNumber(familySummary.winrate) >= 50 ? "is-positive" : "is-negative")
      : "is-empty is-locked";
    const weaponTiles = family.weapons.map((weaponName) => {
      const weaponKey = normalizeStatsWeaponKey(weaponName);
      const weapon = summaryMap.get(weaponKey);
      const hasWeaponData = safeNumber(weapon?.rounds) > 0;
      const assetPath = getStatsWeaponAssetPath(weaponName);
      const weaponWinrate = safeNumber(weapon?.winrate);
      const winrateLabel = hasWeaponData ? `${Math.round(weaponWinrate)}% WR` : "No Data";
      const weaponWinrateTone = hasWeaponData ? (weaponWinrate >= 50 ? "stats-value-positive" : "stats-value-negative") : "";
      const tileTone = hasWeaponData
        ? (weaponWinrate >= 50 ? "is-positive" : "is-negative")
        : "is-empty is-locked";

      return `
        <button type="button" class="stats-weapon-tile ${hasWeaponData ? "has-data" : "is-empty"} ${tileTone}" data-weapon-key="${escapeHtml(weaponKey)}" aria-label="Open ${escapeHtml(weaponName)} weapon insights" ${hasWeaponData ? "" : "disabled aria-disabled=\"true\""}>
          <span class="stats-weapon-art-wrap">
            <img class="stats-weapon-art" src="${escapeHtml(assetPath)}" alt="${escapeHtml(weaponName)} weapon">
          </span>
          <span class="stats-weapon-label-row">
            <span class="stats-weapon-name">${escapeHtml(weaponName)}</span>
            <span class="stats-weapon-mini"><span class="${weaponWinrateTone}">${escapeHtml(winrateLabel)}</span></span>
          </span>
        </button>
      `;
    }).join("");

    return `
      <section class="stats-weapon-family-row ${hasFamilyData ? "has-data" : "is-empty"} ${toneClass}" style="--weapon-count:${family.weapons.length}">
        <div class="stats-weapon-family-head">
          <span class="stats-weapon-family-title">${escapeHtml(family.label)}</span>
        </div>
        <div class="stats-weapon-image-row">
          ${weaponTiles}
        </div>
      </section>
    `;
  }).join("");

  container.querySelectorAll(".stats-weapon-tile").forEach((button) => {
    if (button.disabled || button.classList.contains("is-empty")) return;
    button.addEventListener("click", () => openStatsDetailModal("weapon", button.dataset.weaponKey || ""));
  });
}

function renderStatsSummaryMetaModel() {
  const selector = document.getElementById("statsActSelector");
  if (!selector) return;

  const model = getPlayerModel();
  const currentLabel = model?.currentAct || "Current Window";
  const options = model?.acts?.length ? model.acts : [currentLabel];

  selector.innerHTML = "";
  options.forEach((label) => {
    const option = document.createElement("option");
    option.value = label;
    option.textContent = label;
    selector.appendChild(option);
  });

  selector.disabled = false;
}

function renderStatsPeakProgress() {
  const profile = getActiveProfile();
  const peak = computePeakProfileProgress(profile);
  const icon = document.getElementById("statsPeakRankIcon");
  const rankText = document.getElementById("statsPeakRankText");
  const rrText = document.getElementById("statsPeakRRText");
  const note = document.getElementById("statsPeakProofNote");

  if (icon) {
    icon.src = peak.rankIconUrl;
    icon.alt = peak.tierLabel;
  }
  if (rankText) rankText.textContent = peak.tierLabel;
  if (rrText) rrText.textContent = `${Math.round(peak.peakRR)} RR peak`;
  if (note) {
    note.textContent = peak.gainFromStart > 0
      ? `Visual proof of progress: +${Math.round(peak.gainFromStart)} RR above your starting point.`
      : "Highest point reached in this profile timeline so far.";
  }
}

function renderStatsRoleProgress() {
  const container = document.getElementById("statsRoleProgressRow");
  if (!container) return;

  const model = getPlayerModel();
  const roles = (model?.roles || []).slice().sort((a, b) => b.matchesPlayed - a.matchesPlayed);
  const importedRoles = getActiveProfile()?.trackerAnalytics?.roles || [];

  if (!roles.length && !importedRoles.length) {
    container.innerHTML = `<div class="stats-empty">Import matches to compare roles</div>`;
    return;
  }

  container.innerHTML = "";

  (roles.length ? roles : importedRoles).slice(0, 4).forEach((role) => {
    const currentWinRate = safeNumber(role?.winrate, safeDivide(safeNumber(role?.matchesWon) * 100, safeNumber(role?.matchesPlayed)));
    const importedRole = importedRoles.find(entry => String(entry?.role || "").toLowerCase() === String(role?.role || "").toLowerCase());
    const baselineWinRate = (safeNumber(importedRole?.matchesWon) || safeNumber(importedRole?.matchesPlayed))
      ? safeDivide(safeNumber(importedRole?.matchesWon) * 100, safeNumber(importedRole?.matchesPlayed))
      : currentWinRate;
    const delta = currentWinRate - baselineWinRate;
    const deltaClass = delta > 1 ? "is-up" : delta < -1 ? "is-down" : "";

    const pill = document.createElement("div");
    pill.className = "stats-role-pill";
    pill.innerHTML = `
      <span class="stats-role-pill-label">${escapeHtml(role.role || "Role")}</span>
      <div class="stats-role-pill-value">
        <span>${Math.round(currentWinRate)}% WR</span>
        <span class="stats-role-pill-delta ${deltaClass}">${delta > 0 ? "+" : ""}${Math.round(delta)}%</span>
      </div>
    `;
    container.appendChild(pill);
  });
}

function renderInsightCardsModel() {
  const container = document.getElementById("insightsList");
  if (!container) return;

  const model = getPlayerModel();
  let list = (model?.insights || []).slice();

  if (activeInsightFilter !== "all") {
    list = list.filter(insight => insight.type === activeInsightFilter);
  }

  if (!list.length) {
    list = (model?.insights || []).slice();
  }

  container.innerHTML = "";

  if (!list.length) {
    const emptyCard = document.createElement("div");
    emptyCard.className = "insight-card insight-empty";
    emptyCard.innerHTML = `
      <div class="insight-header">
        <div class="insight-header-main">
          <div class="insight-title">Insights Waiting On More Data</div>
          <div class="insight-tag">INFO</div>
        </div>
      </div>
      <div class="insight-preview">This panel fills with ranked coaching reads after you import a few matches or save a few reflections.</div>
      <div class="insight-block">
        <div class="insight-label">NEXT STEP</div>
        Play or import another short block, then reopen Insights to surface the strongest trends.
      </div>
    `;
    container.appendChild(emptyCard);
    scheduleInsightListOverflowSync(container);
    return;
  }

  list.forEach((insight, index) => {
    const el = document.createElement("div");
    el.className = `insight-card insight-${insight.type}`;
    el.style.position = "relative";
    el.dataset.insightIndex = String(index);
    const signature = getInsightSignature(insight);
    const latestFeedback = getLatestInsightFeedback(signature);
    const priority = getPriorityLabel(insight.priority);
    const confidence = getConfidenceLabel((safeNumber(insight.priority) * 0.65) + (safeNumber(model?.confidenceScore) * 0.35));
    const priorityTone = getInsightMetaToneClass("priority", priority);
    const confidenceTone = getInsightMetaToneClass("confidence", confidence);
    const focusTone = getInsightMetaToneClass("focus", insight.focus || model?.focus || "Build Sample", insight.type || "neutral");
    const showPriorityMeta = String(insight.type || "").toLowerCase() !== "good";
    el.innerHTML = `
      <div class="insight-header">
        <div class="insight-header-main">
          <div class="insight-title">${escapeHtml(insight.title)}</div>
          <div class="insight-tag">${escapeHtml(String(insight.type || "").toUpperCase())}</div>
        </div>
      </div>
      <div class="insight-preview">${escapeHtml(insight.preview || "")}</div>
      <div class="insight-meta-row">
        ${showPriorityMeta ? `<span class="insight-meta-pill ${priorityTone}">${escapeHtml(priority)} Priority</span>` : ""}
        <span class="insight-meta-pill ${confidenceTone}">${escapeHtml(confidence)}</span>
        <span class="insight-meta-pill ${focusTone}">Focus Category: ${escapeHtml(insight.focus || model?.focus || "Build Sample")}</span>
      </div>
      <div class="insight-expand">
        <div class="insight-block">
          <div class="insight-label">WHAT</div>
          ${escapeHtml(insight.what || "")}
        </div>
        <div class="insight-block">
          <div class="insight-label">WHY</div>
          ${escapeHtml(insight.why || "")}
        </div>
        <div class="insight-block">
          <div class="insight-label">ACTION</div>
          ${escapeHtml(insight.action || "")}
        </div>
        <div class="insight-sources">
          ${(insight.sources || []).map((source) => `<span class="insight-source">${escapeHtml(source)}</span>`).join("")}
        </div>
        <div class="insight-feedback-row" aria-label="Insight feedback">
          <span class="insight-feedback-label">Was this read useful?</span>
          <button type="button" class="insight-feedback-btn ${latestFeedback?.rating === "helpful" ? "is-active" : ""}" data-feedback-rating="helpful">Yes</button>
          <button type="button" class="insight-feedback-btn ${latestFeedback?.rating === "inaccurate" ? "is-active" : ""}" data-feedback-rating="inaccurate">Not really</button>
        </div>
      </div>
    `;
    container.appendChild(el);
  });

  bindInsightCards();
  scheduleInsightListOverflowSync(container);
}

function renderStatsPerformanceClean() {
  const container = document.getElementById("statsPerformanceChart");
  if (!container) return;

  const model = getPlayerModel();
  container.className = "stats-chart-wrap stats-trends-list stats-trends-grid";

  if (!(model?.trends || []).length) {
    container.innerHTML = `<div class="stats-empty">Import matches to view performance trends</div>`;
    return;
  }

  container.innerHTML = model.trends.map((trend) => {
    const toneMeta = getSignalToneMeta(trend?.tone);
    return `
      <button type="button" class="stats-trend-row stats-trend-card stats-trend-${toneMeta.tone} stats-select-card" data-trend-id="${escapeHtml(trend?.id || "")}">
        <div class="stats-trend-head">
          <span class="stats-trend-tone">${escapeHtml(toneMeta.label)}</span>
          <span class="stats-trend-kicker">${escapeHtml(trend?.kicker || "Current Window")}</span>
        </div>
        <div class="stats-trend-copy">
          <div class="stats-main-text">${escapeHtml(trend?.label || "Read")}</div>
          <div class="stats-sub-text">${escapeHtml(trend?.value || "--")}</div>
        </div>
        <div class="stats-trend-detail">${escapeHtml(trend?.detail || "No detail available yet.")}</div>
      </button>
    `;
  }).join("");

  container.querySelectorAll(".stats-trend-card").forEach((button) => {
    button.addEventListener("click", () => {
      openStatsDetailModal("trend", button.dataset.trendId || "");
    });
  });
}

renderStatsAgents = renderStatsAgentsModel;
renderStatsMaps = renderStatsMapsModel;
renderStatsWeapons = renderStatsWeaponsModel;
renderStatsSummaryMeta = renderStatsSummaryMetaModel;
renderInsightCards = renderInsightCardsModel;
renderStatsPerformance = renderStatsPerformanceClean;

